#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct NativeVulkanVideoImportSnapshot {
    texture_import_status: &'static str,
    frames_imported: u64,
    last_import_size: Option<(u32, u32)>,
    last_import_memory_path: Option<String>,
    last_import_error: Option<String>,
    last_import_elapsed_us: Option<u64>,
    max_import_elapsed_us: Option<u64>,
}

#[cfg(not(feature = "native-vulkan-gst-video"))]
#[derive(Debug, Clone, PartialEq, Eq)]
struct NativeVulkanVideoImportSnapshot {
    texture_import_status: &'static str,
    frames_imported: u64,
    last_import_size: Option<(u32, u32)>,
    last_import_memory_path: Option<String>,
    last_import_error: Option<String>,
    last_import_elapsed_us: Option<u64>,
    max_import_elapsed_us: Option<u64>,
}

pub struct NativeVulkanSession {
    host: NativeWaylandHost,
    _entry: ash::Entry,
    instance: ash::Instance,
    surface_loader: ash::khr::surface::Instance,
    _wayland_surface_loader: ash::khr::wayland_surface::Instance,
    surface: vk::SurfaceKHR,
    physical_device: vk::PhysicalDevice,
    selected_physical_device_name: String,
    selected_physical_device_type: &'static str,
    queue_family_index: u32,
    device: ash::Device,
    queue: vk::Queue,
    swapchain_loader: ash::khr::swapchain::Device,
    swapchain: vk::SwapchainKHR,
    swapchain_format: vk::Format,
    present_mode: vk::PresentModeKHR,
    swapchain_extent: vk::Extent2D,
    swapchain_images: Vec<vk::Image>,
    swapchain_image_views: Vec<vk::ImageView>,
    swapchain_image_layouts: Vec<vk::ImageLayout>,
    command_pool: vk::CommandPool,
    command_buffers: Vec<vk::CommandBuffer>,
    image_available: vk::Semaphore,
    render_finished: vk::Semaphore,
    in_flight: vk::Fence,
    static_upload: Option<NativeVulkanStaticImageUpload>,
    #[cfg(feature = "native-vulkan-gst-video")]
    video_frontend: Option<NativeVulkanGstVideoFrontend>,
    #[cfg(feature = "native-vulkan-gst-video")]
    video_renderer: Option<NativeVulkanVideoRenderer>,
    #[cfg(feature = "native-vulkan-gst-video")]
    video_texture: Option<NativeVulkanVideoTexture>,
    #[cfg(feature = "native-vulkan-gst-video")]
    video_import_status: NativeVulkanVideoImportStatus,
    clear_color: NativeVulkanClearColor,
    render_item: NativeVulkanRenderItem,
    started_at: Instant,
    frames_rendered: u64,
    last_render_error: Option<String>,
}

impl NativeVulkanSession {
    pub fn connect(options: NativeVulkanOptions) -> Result<Self, NativeVulkanError> {
        Self::connect_with_render_item(
            options,
            NativeVulkanRenderItem::Clear {
                output_name: "native-vulkan".to_owned(),
            },
        )
    }

    pub fn connect_with_render_item(
        options: NativeVulkanOptions,
        render_item: NativeVulkanRenderItem,
    ) -> Result<Self, NativeVulkanError> {
        let mut host = NativeWaylandHost::connect(options.host)?;
        host.wait_until_configured(options.wait_configure_roundtrips)?;
        let handles = host.surface_handles()?;

        let (entry, instance) = create_native_vulkan_instance()?;
        let surface_loader = ash::khr::surface::Instance::new(&entry, &instance);
        let wayland_surface_loader = ash::khr::wayland_surface::Instance::new(&entry, &instance);
        let surface_create_info = vk::WaylandSurfaceCreateInfoKHR::default()
            .display(handles.display.as_ptr().cast::<vk::wl_display>())
            .surface(handles.surface.as_ptr().cast::<vk::wl_surface>());
        let surface = match unsafe {
            wayland_surface_loader.create_wayland_surface(&surface_create_info, None)
        } {
            Ok(surface) => surface,
            Err(result) => {
                unsafe {
                    instance.destroy_instance(None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateWaylandSurfaceKHR",
                    result,
                });
            }
        };

        let selection =
            select_native_vulkan_present_queue(&instance, &surface_loader, surface)?.selection;
        ensure_native_vulkan_device_extension(
            &instance,
            selection.physical_device,
            ash::khr::swapchain::NAME,
        )?;
        #[cfg(feature = "native-vulkan-gst-video")]
        let video_enabled = matches!(&render_item, NativeVulkanRenderItem::Video { .. });
        #[cfg(feature = "native-vulkan-gst-video")]
        if video_enabled {
            ensure_native_vulkan_device_extension(
                &instance,
                selection.physical_device,
                ash::khr::external_memory_fd::NAME,
            )?;
        }
        let priorities = [1.0_f32];
        let queue_create_info = vk::DeviceQueueCreateInfo::default()
            .queue_family_index(selection.queue_family_index)
            .queue_priorities(&priorities);
        let queue_create_infos = [queue_create_info];
        #[cfg(feature = "native-vulkan-gst-video")]
        let device_extensions = {
            let mut extensions = vec![ash::khr::swapchain::NAME.as_ptr()];
            if video_enabled {
                extensions.push(ash::khr::external_memory_fd::NAME.as_ptr());
            }
            extensions
        };
        #[cfg(not(feature = "native-vulkan-gst-video"))]
        let device_extensions = vec![ash::khr::swapchain::NAME.as_ptr()];
        let device_create_info = vk::DeviceCreateInfo::default()
            .queue_create_infos(&queue_create_infos)
            .enabled_extension_names(&device_extensions);
        let device =
            unsafe { instance.create_device(selection.physical_device, &device_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateDevice",
                    result,
                })?;
        let queue = unsafe { device.get_device_queue(selection.queue_family_index, 0) };
        let swapchain_loader = ash::khr::swapchain::Device::new(&instance, &device);
        let swapchain_plan = create_native_vulkan_swapchain_plan(
            &surface_loader,
            selection.physical_device,
            surface,
            handles.logical_size,
            handles.buffer_size,
        )?;
        let swapchain =
            unsafe { swapchain_loader.create_swapchain(&swapchain_plan.create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSwapchainKHR",
                    result,
                })?;
        let swapchain_images = unsafe { swapchain_loader.get_swapchain_images(swapchain) }
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkGetSwapchainImagesKHR",
                result,
            })?;
        let swapchain_image_views = create_native_vulkan_swapchain_image_views(
            &device,
            &swapchain_images,
            swapchain_plan.format.format,
        )?;
        let command_pool_create_info = vk::CommandPoolCreateInfo::default()
            .flags(vk::CommandPoolCreateFlags::RESET_COMMAND_BUFFER)
            .queue_family_index(selection.queue_family_index);
        let command_pool = unsafe { device.create_command_pool(&command_pool_create_info, None) }
            .map_err(|result| NativeVulkanError::Vulkan {
            operation: "vkCreateCommandPool",
            result,
        })?;
        let command_buffer_allocate_info = vk::CommandBufferAllocateInfo::default()
            .command_pool(command_pool)
            .level(vk::CommandBufferLevel::PRIMARY)
            .command_buffer_count(swapchain_images.len() as u32);
        let command_buffers =
            unsafe { device.allocate_command_buffers(&command_buffer_allocate_info) }.map_err(
                |result| NativeVulkanError::Vulkan {
                    operation: "vkAllocateCommandBuffers",
                    result,
                },
            )?;
        let semaphore_create_info = vk::SemaphoreCreateInfo::default();
        let image_available = unsafe { device.create_semaphore(&semaphore_create_info, None) }
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkCreateSemaphore(image_available)",
                result,
            })?;
        let render_finished = unsafe { device.create_semaphore(&semaphore_create_info, None) }
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkCreateSemaphore(render_finished)",
                result,
            })?;
        let fence_create_info =
            vk::FenceCreateInfo::default().flags(vk::FenceCreateFlags::SIGNALED);
        let in_flight =
            unsafe { device.create_fence(&fence_create_info, None) }.map_err(|result| {
                NativeVulkanError::Vulkan {
                    operation: "vkCreateFence",
                    result,
                }
            })?;
        let static_upload = match &render_item {
            NativeVulkanRenderItem::StaticImage {
                source,
                fit,
                background,
                ..
            } => Some(NativeVulkanStaticImageUpload::new(
                &instance,
                selection.physical_device,
                &device,
                source,
                *fit,
                background.as_deref(),
                swapchain_plan.format.format,
                swapchain_plan.extent,
            )?),
            NativeVulkanRenderItem::Video {
                poster: Some(poster),
                fit,
                ..
            } => Some(NativeVulkanStaticImageUpload::new(
                &instance,
                selection.physical_device,
                &device,
                poster,
                *fit,
                None,
                swapchain_plan.format.format,
                swapchain_plan.extent,
            )?),
            _ => None,
        };
        #[cfg(feature = "native-vulkan-gst-video")]
        let video_frontend = match &render_item {
            NativeVulkanRenderItem::Video { .. } => {
                Some(NativeVulkanGstVideoFrontend::new(&render_item)?)
            }
            _ => None,
        };
        #[cfg(feature = "native-vulkan-gst-video")]
        let video_renderer = match &render_item {
            NativeVulkanRenderItem::Video { .. } => Some(NativeVulkanVideoRenderer::new(
                &device,
                swapchain_plan.format.format,
                swapchain_plan.extent,
                &swapchain_image_views,
            )?),
            _ => None,
        };

        Ok(Self {
            host,
            _entry: entry,
            instance,
            surface_loader,
            _wayland_surface_loader: wayland_surface_loader,
            surface,
            physical_device: selection.physical_device,
            selected_physical_device_name: selection.physical_device_name,
            selected_physical_device_type: selection.physical_device_type,
            queue_family_index: selection.queue_family_index,
            device,
            queue,
            swapchain_loader,
            swapchain,
            swapchain_format: swapchain_plan.format.format,
            present_mode: swapchain_plan.present_mode,
            swapchain_extent: swapchain_plan.extent,
            swapchain_image_layouts: vec![vk::ImageLayout::UNDEFINED; swapchain_images.len()],
            swapchain_image_views,
            swapchain_images,
            command_pool,
            command_buffers,
            image_available,
            render_finished,
            in_flight,
            static_upload,
            #[cfg(feature = "native-vulkan-gst-video")]
            video_frontend,
            #[cfg(feature = "native-vulkan-gst-video")]
            video_renderer,
            #[cfg(feature = "native-vulkan-gst-video")]
            video_texture: None,
            #[cfg(feature = "native-vulkan-gst-video")]
            video_import_status: NativeVulkanVideoImportStatus::default(),
            clear_color: options.clear_color,
            render_item,
            started_at: Instant::now(),
            frames_rendered: 0,
            last_render_error: None,
        })
    }

    pub fn run_for(
        &mut self,
        duration: Duration,
        target_max_fps: Option<u32>,
    ) -> Result<NativeVulkanRuntimeSnapshot, NativeVulkanError> {
        let deadline = Instant::now() + duration;
        let frame_interval = target_max_fps
            .filter(|fps| *fps > 0)
            .map(|fps| Duration::from_secs_f64(1.0 / fps as f64));
        let mut next_frame = Instant::now();

        while Instant::now() < deadline && !self.host.is_closed() {
            self.host.pump_events()?;
            self.wait_for_in_flight()?;
            self.poll_video_frontend()?;
            match self.render_frame() {
                Ok(()) => {}
                Err(err) => {
                    self.last_render_error = Some(err.to_string());
                    return Err(err);
                }
            }
            self.trim_allocator_after_frame();

            if let Some(interval) = frame_interval {
                next_frame += interval;
                let now = Instant::now();
                if next_frame > now {
                    thread::sleep(next_frame - now);
                } else {
                    next_frame = now;
                }
            }
        }

        Ok(self.snapshot())
    }

    pub fn snapshot(&self) -> NativeVulkanRuntimeSnapshot {
        let elapsed = self.started_at.elapsed();
        NativeVulkanRuntimeSnapshot {
            runtime_elapsed_ms: elapsed.as_millis().min(u64::MAX as u128) as u64,
            frames_rendered: self.frames_rendered,
            average_render_fps: if elapsed.is_zero() {
                0.0
            } else {
                self.frames_rendered as f64 / elapsed.as_secs_f64()
            },
            configured: self.host.snapshot().configured,
            wayland_surface_logical_size: self
                .host
                .logical_size()
                .unwrap_or((self.swapchain_extent.width, self.swapchain_extent.height)),
            wayland_surface_buffer_size: (
                self.swapchain_extent.width,
                self.swapchain_extent.height,
            ),
            selected_physical_device_name: self.selected_physical_device_name.clone(),
            selected_physical_device_type: self.selected_physical_device_type,
            selected_queue_family_index: self.queue_family_index,
            swapchain_extent: (self.swapchain_extent.width, self.swapchain_extent.height),
            swapchain_image_count: self.swapchain_images.len(),
            swapchain_format: format!("{:?}", self.swapchain_format),
            present_mode: native_vulkan_present_mode_label(self.present_mode),
            clear_color: self.clear_color,
            static_upload_bytes: self
                .static_upload
                .as_ref()
                .map(|upload| upload.size_bytes.min(u64::MAX as vk::DeviceSize) as u64),
            video_runtime: native_vulkan_video_runtime_snapshot(
                &self.render_item,
                self.video_frontend_snapshot(),
                self.video_import_snapshot(),
                self.frames_rendered,
                self.static_upload
                    .as_ref()
                    .map(|upload| upload.size_bytes.min(u64::MAX as vk::DeviceSize) as u64),
            ),
            render_item: self.render_item.clone(),
            last_render_error: self.last_render_error.clone(),
        }
    }

    fn render_frame(&mut self) -> Result<(), NativeVulkanError> {
        self.wait_for_in_flight()?;
        let fences = [self.in_flight];
        unsafe {
            self.device
                .reset_fences(&fences)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkResetFences",
                    result,
                })?;
        }

        let (image_index, _) = unsafe {
            self.swapchain_loader.acquire_next_image(
                self.swapchain,
                u64::MAX,
                self.image_available,
                vk::Fence::null(),
            )
        }
        .map_err(|result| NativeVulkanError::Vulkan {
            operation: "vkAcquireNextImageKHR",
            result,
        })?;
        let image_index = image_index as usize;
        let command_buffer = self.command_buffers[image_index];
        self.record_frame_command(command_buffer, image_index)?;

        let wait_semaphores = [self.image_available];
        let wait_stages = [self.current_render_wait_stage()];
        let command_buffers = [command_buffer];
        let signal_semaphores = [self.render_finished];
        let submit_info = vk::SubmitInfo::default()
            .wait_semaphores(&wait_semaphores)
            .wait_dst_stage_mask(&wait_stages)
            .command_buffers(&command_buffers)
            .signal_semaphores(&signal_semaphores);
        let submit_infos = [submit_info];
        unsafe {
            self.device
                .queue_submit(self.queue, &submit_infos, self.in_flight)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkQueueSubmit",
                    result,
                })?;
        }

        let swapchains = [self.swapchain];
        let image_indices = [image_index as u32];
        let present_info = vk::PresentInfoKHR::default()
            .wait_semaphores(&signal_semaphores)
            .swapchains(&swapchains)
            .image_indices(&image_indices);
        unsafe {
            self.swapchain_loader
                .queue_present(self.queue, &present_info)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkQueuePresentKHR",
                    result,
                })?;
        }
        self.frames_rendered += 1;
        Ok(())
    }

    fn wait_for_in_flight(&self) -> Result<(), NativeVulkanError> {
        let fences = [self.in_flight];
        unsafe {
            self.device
                .wait_for_fences(&fences, true, u64::MAX)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkWaitForFences",
                    result,
                })
        }
    }

    fn trim_allocator_after_frame(&self) {
        #[cfg(feature = "native-vulkan-gst-video")]
        if matches!(self.render_item, NativeVulkanRenderItem::Video { .. })
            && self.frames_rendered > 0
            && self.frames_rendered % 240 == 0
        {
            native_vulkan_trim_process_heap();
        }
    }

    fn record_frame_command(
        &mut self,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
    ) -> Result<(), NativeVulkanError> {
        #[cfg(feature = "native-vulkan-gst-video")]
        if self.video_texture.is_some() && self.video_renderer.is_some() {
            return self.record_video_frame_command(command_buffer, image_index);
        }
        unsafe {
            self.device
                .reset_command_buffer(command_buffer, vk::CommandBufferResetFlags::empty())
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkResetCommandBuffer",
                    result,
                })?;
            let begin_info = vk::CommandBufferBeginInfo::default()
                .flags(vk::CommandBufferUsageFlags::ONE_TIME_SUBMIT);
            self.device
                .begin_command_buffer(command_buffer, &begin_info)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkBeginCommandBuffer",
                    result,
                })?;

            let image = self.swapchain_images[image_index];
            let old_layout = self.swapchain_image_layouts[image_index];
            let range = native_vulkan_color_subresource_range();
            let to_transfer = vk::ImageMemoryBarrier::default()
                .old_layout(old_layout)
                .new_layout(vk::ImageLayout::TRANSFER_DST_OPTIMAL)
                .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .image(image)
                .subresource_range(range)
                .src_access_mask(vk::AccessFlags::empty())
                .dst_access_mask(vk::AccessFlags::TRANSFER_WRITE);
            self.device.cmd_pipeline_barrier(
                command_buffer,
                vk::PipelineStageFlags::TOP_OF_PIPE,
                vk::PipelineStageFlags::TRANSFER,
                vk::DependencyFlags::empty(),
                &[],
                &[],
                &[to_transfer],
            );

            if let Some(static_upload) = &self.static_upload {
                let copy = static_upload.buffer_image_copy;
                self.device.cmd_copy_buffer_to_image(
                    command_buffer,
                    static_upload.buffer,
                    image,
                    vk::ImageLayout::TRANSFER_DST_OPTIMAL,
                    &[copy],
                );
            } else {
                let clear_color = vk::ClearColorValue::from(self.clear_color);
                self.device.cmd_clear_color_image(
                    command_buffer,
                    image,
                    vk::ImageLayout::TRANSFER_DST_OPTIMAL,
                    &clear_color,
                    &[range],
                );
            }

            let to_present = vk::ImageMemoryBarrier::default()
                .old_layout(vk::ImageLayout::TRANSFER_DST_OPTIMAL)
                .new_layout(vk::ImageLayout::PRESENT_SRC_KHR)
                .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .image(image)
                .subresource_range(range)
                .src_access_mask(vk::AccessFlags::TRANSFER_WRITE)
                .dst_access_mask(vk::AccessFlags::empty());
            self.device.cmd_pipeline_barrier(
                command_buffer,
                vk::PipelineStageFlags::TRANSFER,
                vk::PipelineStageFlags::BOTTOM_OF_PIPE,
                vk::DependencyFlags::empty(),
                &[],
                &[],
                &[to_present],
            );

            self.device
                .end_command_buffer(command_buffer)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkEndCommandBuffer",
                    result,
                })?;
            self.swapchain_image_layouts[image_index] = vk::ImageLayout::PRESENT_SRC_KHR;
        }
        Ok(())
    }

    fn current_render_wait_stage(&self) -> vk::PipelineStageFlags {
        #[cfg(feature = "native-vulkan-gst-video")]
        if self.video_texture.is_some() && self.video_renderer.is_some() {
            return vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT;
        }
        vk::PipelineStageFlags::TRANSFER
    }

    #[cfg(feature = "native-vulkan-gst-video")]
    fn record_video_frame_command(
        &mut self,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
    ) -> Result<(), NativeVulkanError> {
        let texture = self
            .video_texture
            .as_ref()
            .ok_or_else(|| NativeVulkanError::Video("video texture is not ready".to_owned()))?;
        let renderer = self
            .video_renderer
            .as_ref()
            .ok_or_else(|| NativeVulkanError::Video("video renderer is not ready".to_owned()))?;
        let fit = match &self.render_item {
            NativeVulkanRenderItem::Video { fit, .. } => *fit,
            _ => FitMode::Cover,
        };
        renderer.record_frame(
            &self.device,
            command_buffer,
            image_index,
            self.swapchain_images[image_index],
            self.swapchain_image_layouts[image_index],
            texture,
            fit,
        )?;
        self.swapchain_image_layouts[image_index] = renderer.target_final_layout();
        Ok(())
    }

    fn poll_video_frontend(&mut self) -> Result<(), NativeVulkanError> {
        #[cfg(feature = "native-vulkan-gst-video")]
        if let Some(frontend) = self.video_frontend.as_mut() {
            frontend.poll()?;
            if let Some(sample) = frontend.take_latest_sample() {
                self.import_video_sample(sample);
            }
        }
        Ok(())
    }

    #[cfg(feature = "native-vulkan-gst-video")]
    fn video_frontend_snapshot(&self) -> Option<NativeVulkanGstVideoFrontendSnapshot> {
        self.video_frontend
            .as_ref()
            .map(NativeVulkanGstVideoFrontend::snapshot)
    }

    #[cfg(feature = "native-vulkan-gst-video")]
    fn video_import_snapshot(&self) -> Option<NativeVulkanVideoImportSnapshot> {
        matches!(self.render_item, NativeVulkanRenderItem::Video { .. })
            .then(|| self.video_import_status.snapshot())
    }

    #[cfg(feature = "native-vulkan-gst-video")]
    fn import_video_sample(&mut self, sample: gst::Sample) {
        let started_at = Instant::now();
        let import_result = self.import_video_sample_inner(&sample);
        match import_result {
            Ok(mut report) => {
                report.elapsed_us = native_vulkan_elapsed_us(started_at.elapsed());
                self.video_import_status.record_import(report);
            }
            Err(err) => self.video_import_status.record_error(err.to_string()),
        }
    }

    #[cfg(feature = "native-vulkan-gst-video")]
    fn import_video_sample_inner(
        &mut self,
        sample: &gst::Sample,
    ) -> Result<NativeVulkanVideoImportReport, NativeVulkanError> {
        self.video_renderer.as_ref().ok_or_else(|| {
            NativeVulkanError::Video("native Vulkan video renderer is not initialized".to_owned())
        })?;
        let buffer = sample
            .buffer()
            .ok_or_else(|| NativeVulkanError::Video("appsink sample has no buffer".to_owned()))?;
        let meta = native_vulkan_gst_system_yuv420_meta(sample, buffer)?;
        if native_vulkan_gst_buffer_has_dmabuf_memory(buffer) {
            let frame = native_vulkan_gst_dmabuf_frame(sample, buffer, &meta)?;
            return self.import_dmabuf_video_frame(
                &frame,
                "GstDmaBufMemory->Vulkan external DRM modifier image planes",
            );
        }
        let memory_types = native_vulkan_gst_memory_types(buffer);
        #[cfg(not(feature = "native-vulkan-gst-va"))]
        if memory_types
            .iter()
            .any(|memory_type| memory_type == "VAMemory" || memory_type.contains("VAMemory"))
        {
            return Err(NativeVulkanError::Video(
                "native Vulkan VAMemory importer requires the native-vulkan-gst-va feature"
                    .to_owned(),
            ));
        }
        if native_vulkan_gst_buffer_has_va_memory(buffer) {
            let frame = native_vulkan_gst_va_dmabuf_frame(buffer, &meta)?;
            return self.import_dmabuf_video_frame(
                &frame,
                "GstVAMemory->vaExportSurfaceHandle(DRM PRIME)->Vulkan external DRM modifier image planes",
            );
        }
        #[cfg(not(feature = "native-vulkan-gst-cuda"))]
        if memory_types
            .iter()
            .any(|memory_type| memory_type == "CUDAMemory" || memory_type.contains("CUDAMemory"))
        {
            return Err(NativeVulkanError::Video(
                "native Vulkan CUDAMemory importer requires the native-vulkan-gst-cuda feature"
                    .to_owned(),
            ));
        }
        if !native_vulkan_gst_buffer_has_cuda_memory(buffer) {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan import expected DMABuf, VAMemory, or CUDAMemory, got {}",
                memory_types.join("|")
            )));
        }
        let cuda_context = native_vulkan_gst_cuda_context_from_buffer(buffer)?;
        let recreate = match self.video_texture.as_ref() {
            Some(NativeVulkanVideoTexture::Cuda(texture)) => {
                !texture.matches(cuda_context, meta.width, meta.height, meta.format)
            }
            _ => true,
        };
        if recreate {
            let texture = NativeVulkanCudaVideoTexture::new(
                &self.instance,
                self.physical_device,
                self.queue,
                self.command_pool,
                &self.device,
                self.queue_family_index,
                cuda_context,
                meta.width,
                meta.height,
                meta.format,
            )?;
            if let Some(old_texture) = self.video_texture.take() {
                old_texture.destroy(&self.device);
            }
            self.video_texture = Some(NativeVulkanVideoTexture::Cuda(texture));
            let renderer = self.video_renderer.as_mut().ok_or_else(|| {
                NativeVulkanError::Video(
                    "native Vulkan video renderer is not initialized".to_owned(),
                )
            })?;
            renderer.update_descriptors(
                &self.device,
                self.video_texture
                    .as_ref()
                    .expect("video texture must exist after create"),
            );
        }
        let Some(NativeVulkanVideoTexture::Cuda(texture)) = self.video_texture.as_mut() else {
            return Err(NativeVulkanError::Video(
                "native Vulkan CUDA texture was not initialized".to_owned(),
            ));
        };
        texture.copy_sample(buffer, &meta)?;
        Ok(NativeVulkanVideoImportReport {
            width: meta.width,
            height: meta.height,
            memory_path: "CUDAMemory->CUDA->Vulkan external image planes".to_owned(),
            elapsed_us: 0,
        })
    }

    #[cfg(feature = "native-vulkan-gst-video")]
    fn import_dmabuf_video_frame(
        &mut self,
        frame: &NativeVulkanDmabufVideoFrame,
        memory_path: &'static str,
    ) -> Result<NativeVulkanVideoImportReport, NativeVulkanError> {
        let texture = NativeVulkanDmabufVideoTexture::new(
            &self.instance,
            self.physical_device,
            self.queue,
            self.command_pool,
            &self.device,
            self.queue_family_index,
            frame,
        )?;
        if let Some(old_texture) = self.video_texture.take() {
            old_texture.destroy(&self.device);
        }
        self.video_texture = Some(NativeVulkanVideoTexture::Dmabuf(texture));
        let renderer = self.video_renderer.as_mut().ok_or_else(|| {
            NativeVulkanError::Video("native Vulkan video renderer is not initialized".to_owned())
        })?;
        renderer.update_descriptors(
            &self.device,
            self.video_texture
                .as_ref()
                .expect("video texture must exist after DMABuf import"),
        );
        Ok(NativeVulkanVideoImportReport {
            width: frame.width,
            height: frame.height,
            memory_path: memory_path.to_owned(),
            elapsed_us: 0,
        })
    }

    #[cfg(not(feature = "native-vulkan-gst-video"))]
    fn video_frontend_snapshot(&self) -> Option<NativeVulkanGstVideoFrontendSnapshot> {
        None
    }

    #[cfg(not(feature = "native-vulkan-gst-video"))]
    fn video_import_snapshot(&self) -> Option<NativeVulkanVideoImportSnapshot> {
        None
    }
}

impl Drop for NativeVulkanSession {
    fn drop(&mut self) {
        unsafe {
            let _ = self.device.device_wait_idle();
            #[cfg(feature = "native-vulkan-gst-video")]
            if let Some(texture) = self.video_texture.take() {
                texture.destroy(&self.device);
            }
            #[cfg(feature = "native-vulkan-gst-video")]
            if let Some(renderer) = self.video_renderer.take() {
                renderer.destroy(&self.device);
            }
            if let Some(static_upload) = self.static_upload.take() {
                static_upload.destroy(&self.device);
            }
            self.device.destroy_fence(self.in_flight, None);
            self.device.destroy_semaphore(self.render_finished, None);
            self.device.destroy_semaphore(self.image_available, None);
            self.device.destroy_command_pool(self.command_pool, None);
            for view in self.swapchain_image_views.drain(..) {
                self.device.destroy_image_view(view, None);
            }
            self.swapchain_loader
                .destroy_swapchain(self.swapchain, None);
            self.device.destroy_device(None);
            self.surface_loader.destroy_surface(self.surface, None);
            self.instance.destroy_instance(None);
        }
    }
}

pub fn run_clear(
    options: NativeVulkanOptions,
    duration: Duration,
) -> Result<NativeVulkanRuntimeSnapshot, NativeVulkanError> {
    let target_max_fps = options.target_max_fps;
    let mut session = NativeVulkanSession::connect(options)?;
    session.run_for(duration, target_max_fps)
}

pub fn run_static_image(
    options: NativeVulkanOptions,
    duration: Duration,
    plan: StaticWallpaperPlan,
) -> Result<NativeVulkanRuntimeSnapshot, NativeVulkanError> {
    let target_max_fps = options.target_max_fps;
    let item = native_vulkan_static_item(&plan);
    let mut session = NativeVulkanSession::connect_with_render_item(options, item)?;
    session.run_for(duration, target_max_fps)
}

pub fn run_video(
    options: NativeVulkanOptions,
    duration: Duration,
    plan: VideoWallpaperPlan,
) -> Result<NativeVulkanRuntimeSnapshot, NativeVulkanError> {
    let target_max_fps = options.target_max_fps;
    let item = native_vulkan_video_item(&plan);
    let mut session = NativeVulkanSession::connect_with_render_item(options, item)?;
    session.run_for(duration, target_max_fps)
}

#[cfg(feature = "native-vulkan-gst-video")]
pub fn run_h265_first_frame_video(
    options: NativeVulkanOptions,
    duration: Duration,
    source: PathBuf,
    width: u32,
    height: u32,
    fit: FitMode,
    bitstream_samples: u32,
) -> Result<NativeVulkanDirectH265FirstFrameRuntimeSnapshot, NativeVulkanError> {
    if width == 0 || height == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.265 first-frame video requires a non-zero source extent".to_owned(),
        ));
    }
    let target_max_fps = options.target_max_fps;
    let mut probe = NativeVulkanSurfaceProbe::connect(NativeVulkanSurfaceProbeOptions {
        host: options.host,
        wait_configure_roundtrips: options.wait_configure_roundtrips,
    })?;
    probe.pump_events()?;
    let surface_snapshot = probe.snapshot();
    let present_query =
        select_native_vulkan_present_queue(&probe.instance, &probe.surface_loader, probe.surface)?;
    let present_selection = present_query.selection;
    let present_queue_family_index = present_selection.queue_family_index;
    let present_queue_families = unsafe {
        probe
            .instance
            .get_physical_device_queue_family_properties(present_selection.physical_device)
    };
    let present_queue_flags = present_queue_families
        .get(present_queue_family_index as usize)
        .map(|queue| queue.queue_flags)
        .unwrap_or_default();
    let video_queue_family = native_vulkan_video_decode_queue_family_infos(
        &probe.instance,
        present_selection.physical_device,
    )
    .into_iter()
    .find(|queue_family| {
        queue_family.queue_count > 0
            && queue_family
                .queue_flags
                .contains(vk::QueueFlags::VIDEO_DECODE_KHR)
            && queue_family
                .video_codec_operations
                .contains(vk::VideoCodecOperationFlagsKHR::DECODE_H265)
    })
    .ok_or_else(|| {
        NativeVulkanError::Video(format!(
            "selected present device {} has no same-device H.265 Vulkan Video decode queue",
            present_selection.physical_device_name
        ))
    })?;

    ensure_native_vulkan_device_extension(
        &probe.instance,
        present_selection.physical_device,
        ash::khr::swapchain::NAME,
    )?;
    for extension in native_vulkan_video_session_required_device_extensions(
        NativeVulkanVideoSessionCodec::H265Main8,
    ) {
        ensure_native_vulkan_device_extension(
            &probe.instance,
            present_selection.physical_device,
            extension,
        )?;
    }

    let mut h265_profile_info = vk::VideoDecodeH265ProfileInfoKHR::default()
        .std_profile_idc(vk::native::StdVideoH265ProfileIdc_STD_VIDEO_H265_PROFILE_IDC_MAIN);
    let profile_info = vk::VideoProfileInfoKHR::default()
        .video_codec_operation(vk::VideoCodecOperationFlagsKHR::DECODE_H265)
        .chroma_subsampling(vk::VideoChromaSubsamplingFlagsKHR::TYPE_420)
        .luma_bit_depth(vk::VideoComponentBitDepthFlagsKHR::TYPE_8)
        .chroma_bit_depth(vk::VideoComponentBitDepthFlagsKHR::TYPE_8)
        .push_next(&mut h265_profile_info);
    let video_queue_loader = ash::khr::video_queue::Instance::new(&probe._entry, &probe.instance);
    let capabilities = native_vulkan_video_session_h265_capabilities(
        &video_queue_loader,
        present_selection.physical_device,
        &profile_info,
    )?;
    let source_extent = vk::Extent2D { width, height };
    if !native_vulkan_video_session_extent_supported(source_extent, &capabilities) {
        return Err(NativeVulkanError::Video(format!(
            "direct H.265 source extent {width}x{height} is outside {:?}..{:?} or not aligned to {:?}",
            (
                capabilities.min_coded_extent.width,
                capabilities.min_coded_extent.height
            ),
            (
                capabilities.max_coded_extent.width,
                capabilities.max_coded_extent.height
            ),
            (
                capabilities.picture_access_granularity.width,
                capabilities.picture_access_granularity.height
            )
        )));
    }
    let format_probe = native_vulkan_video_decode_format_probe(
        &video_queue_loader,
        present_selection.physical_device,
        &profile_info,
        capabilities.decode_capability_flags,
    );
    if !format_probe.nv12_dpb_supported
        || !format_probe.nv12_output_supported
        || !format_probe.nv12_sampled_output_supported
    {
        return Err(NativeVulkanError::Video(format!(
            "direct H.265 first-frame video requires NV12 decode+sampled support{}",
            format_probe
                .query_error
                .as_ref()
                .map(|err| format!(": {err}"))
                .unwrap_or_default()
        )));
    }

    let mut device_queue_family_indices = vec![present_queue_family_index];
    if !device_queue_family_indices.contains(&video_queue_family.queue_family_index) {
        device_queue_family_indices.push(video_queue_family.queue_family_index);
    }
    let priorities = [1.0_f32];
    let queue_create_infos = device_queue_family_indices
        .iter()
        .copied()
        .map(|queue_family_index| {
            vk::DeviceQueueCreateInfo::default()
                .queue_family_index(queue_family_index)
                .queue_priorities(&priorities)
        })
        .collect::<Vec<_>>();
    let mut enabled_extensions = vec![ash::khr::swapchain::NAME.as_ptr()];
    enabled_extensions.extend(
        native_vulkan_video_session_required_device_extensions(
            NativeVulkanVideoSessionCodec::H265Main8,
        )
        .iter()
        .map(|extension| extension.as_ptr()),
    );
    let mut synchronization2_features =
        vk::PhysicalDeviceSynchronization2Features::default().synchronization2(true);
    let device_create_info = vk::DeviceCreateInfo::default()
        .queue_create_infos(&queue_create_infos)
        .enabled_extension_names(&enabled_extensions)
        .push_next(&mut synchronization2_features);
    let device = unsafe {
        probe
            .instance
            .create_device(present_selection.physical_device, &device_create_info, None)
    }
    .map_err(|result| NativeVulkanError::Vulkan {
        operation: "vkCreateDevice(direct h265 first-frame video)",
        result,
    })?;

    let mut swapchain_loader = None::<ash::khr::swapchain::Device>;
    let mut swapchain = vk::SwapchainKHR::null();
    let mut swapchain_image_views = Vec::<vk::ImageView>::new();
    let mut command_pool = vk::CommandPool::null();
    let mut command_buffers = Vec::<vk::CommandBuffer>::new();
    let mut image_available = vk::Semaphore::null();
    let mut render_finished = vk::Semaphore::null();
    let mut in_flight = vk::Fence::null();
    let mut renderer = None::<NativeVulkanVideoRenderer>;
    let mut texture = None::<NativeVulkanVideoTexture>;
    let mut video_session = vk::VideoSessionKHR::null();
    let mut video_session_parameters = vk::VideoSessionParametersKHR::null();
    let mut session_memories = Vec::<vk::DeviceMemory>::new();
    let mut resource_image = None::<NativeVulkanVideoResourceImage>;
    let mut bitstream_buffer = None::<NativeVulkanVideoBitstreamBuffer>;

    let result =
        (|| -> Result<NativeVulkanDirectH265FirstFrameRuntimeSnapshot, NativeVulkanError> {
            let present_queue = unsafe { device.get_device_queue(present_queue_family_index, 0) };
            let video_queue_device = ash::khr::video_queue::Device::new(&probe.instance, &device);
            let video_decode_queue_device =
                ash::khr::video_decode_queue::Device::new(&probe.instance, &device);
            let memory_properties = unsafe {
                probe
                    .instance
                    .get_physical_device_memory_properties(present_selection.physical_device)
            };

            swapchain_loader = Some(ash::khr::swapchain::Device::new(&probe.instance, &device));
            let swapchain_loader_ref = swapchain_loader
                .as_ref()
                .expect("swapchain loader was just created");
            let swapchain_plan = create_native_vulkan_swapchain_plan(
                &probe.surface_loader,
                present_selection.physical_device,
                probe.surface,
                surface_snapshot.wayland_surface_logical_size,
                surface_snapshot.wayland_surface_buffer_size,
            )?;
            swapchain =
                unsafe { swapchain_loader_ref.create_swapchain(&swapchain_plan.create_info, None) }
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkCreateSwapchainKHR(direct h265 first-frame video)",
                        result,
                    })?;
            let swapchain_images = unsafe { swapchain_loader_ref.get_swapchain_images(swapchain) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkGetSwapchainImagesKHR(direct h265 first-frame video)",
                    result,
                })?;
            swapchain_image_views = create_native_vulkan_swapchain_image_views(
                &device,
                &swapchain_images,
                swapchain_plan.format.format,
            )?;
            let command_pool_info = vk::CommandPoolCreateInfo::default()
                .flags(vk::CommandPoolCreateFlags::RESET_COMMAND_BUFFER)
                .queue_family_index(present_queue_family_index);
            command_pool = unsafe { device.create_command_pool(&command_pool_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateCommandPool(direct h265 first-frame present)",
                    result,
                })?;
            let command_buffer_info = vk::CommandBufferAllocateInfo::default()
                .command_pool(command_pool)
                .level(vk::CommandBufferLevel::PRIMARY)
                .command_buffer_count(swapchain_images.len() as u32);
            command_buffers = unsafe { device.allocate_command_buffers(&command_buffer_info) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkAllocateCommandBuffers(direct h265 first-frame present)",
                    result,
                })?;
            let semaphore_create_info = vk::SemaphoreCreateInfo::default();
            image_available = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h265 image_available)",
                    result,
                })?;
            render_finished = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h265 render_finished)",
                    result,
                })?;
            let fence_create_info =
                vk::FenceCreateInfo::default().flags(vk::FenceCreateFlags::SIGNALED);
            in_flight =
                unsafe { device.create_fence(&fence_create_info, None) }.map_err(|result| {
                    NativeVulkanError::Vulkan {
                        operation: "vkCreateFence(direct h265 first-frame)",
                        result,
                    }
                })?;

            let session_max_dpb_slots =
                native_vulkan_video_session_max_dpb_slots(capabilities.max_dpb_slots);
            let session_max_active_reference_pictures =
                native_vulkan_video_session_max_active_reference_pictures(
                    capabilities.max_active_reference_pictures,
                    session_max_dpb_slots,
                );
            let picture_format = vk::Format::G8_B8R8_2PLANE_420_UNORM;
            let create_info = vk::VideoSessionCreateInfoKHR::default()
                .queue_family_index(video_queue_family.queue_family_index)
                .video_profile(&profile_info)
                .picture_format(picture_format)
                .reference_picture_format(picture_format)
                .max_coded_extent(source_extent)
                .max_dpb_slots(session_max_dpb_slots)
                .max_active_reference_pictures(session_max_active_reference_pictures)
                .std_header_version(&capabilities.std_header_version);
            video_session = native_vulkan_create_video_session(&video_queue_device, &create_info)?;

            let memory_requirements = native_vulkan_video_session_memory_requirements(
                &video_queue_device,
                video_session,
            )?;
            let mut bind_infos = Vec::with_capacity(memory_requirements.len());
            let mut session_memory_bytes = 0u64;
            for requirement in memory_requirements.iter() {
                if requirement.memory_requirements.size == 0 {
                    return Err(NativeVulkanError::Video(format!(
                        "direct H.265 session memory bind {} reported zero size",
                        requirement.memory_bind_index
                    )));
                }
                let memory_type_index = native_vulkan_memory_type_index(
                    &memory_properties,
                    requirement.memory_requirements.memory_type_bits,
                    vk::MemoryPropertyFlags::DEVICE_LOCAL,
                )
                .or_else(|| {
                    native_vulkan_memory_type_index(
                        &memory_properties,
                        requirement.memory_requirements.memory_type_bits,
                        vk::MemoryPropertyFlags::empty(),
                    )
                })
                .ok_or(NativeVulkanError::MissingMemoryType(
                    "direct H.265 video session memory",
                ))?;
                let allocation_info = vk::MemoryAllocateInfo::default()
                    .allocation_size(requirement.memory_requirements.size)
                    .memory_type_index(memory_type_index);
                let memory = unsafe { device.allocate_memory(&allocation_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateMemory(direct h265 video session)",
                        result,
                    },
                )?;
                session_memories.push(memory);
                bind_infos.push(
                    vk::BindVideoSessionMemoryInfoKHR::default()
                        .memory_bind_index(requirement.memory_bind_index)
                        .memory(memory)
                        .memory_offset(0)
                        .memory_size(requirement.memory_requirements.size),
                );
                session_memory_bytes =
                    session_memory_bytes.saturating_add(requirement.memory_requirements.size);
            }
            native_vulkan_bind_video_session_memory(
                &video_queue_device,
                video_session,
                &bind_infos,
            )?;

            resource_image = Some(native_vulkan_create_video_session_resource_image(
                &video_queue_loader,
                &device,
                &memory_properties,
                present_selection.physical_device,
                &profile_info,
                source_extent,
                session_max_dpb_slots.max(1),
                picture_format,
                capabilities.decode_capability_flags,
                vk::ImageUsageFlags::empty(),
                &device_queue_family_indices,
                false,
            )?);

            let mut extract_options = NativeVulkanVideoSessionSmokeOptions::default();
            extract_options.codec = NativeVulkanVideoSessionCodec::H265Main8;
            extract_options.width = width;
            extract_options.height = height;
            extract_options.extract_bitstream = true;
            extract_options.bitstream_source = Some(source.clone());
            extract_options.bitstream_extract_max_samples = bitstream_samples.max(1);
            let extract = native_vulkan_extract_video_bitstream(&extract_options)?;
            let parameter_sets =
                extract
                    .snapshot
                    .h265_parameter_sets
                    .as_ref()
                    .ok_or_else(|| {
                        NativeVulkanError::Video(
                            "direct H.265 first-frame video requires parsed H.265 parameter sets"
                                .to_owned(),
                        )
                    })?;
            let bitstream_payload = extract.selected_access_unit.as_slice();
            let requested_bitstream_size = native_vulkan_align_up(
                bitstream_payload.len() as u64,
                capabilities.min_bitstream_buffer_size_alignment.max(1),
            );
            bitstream_buffer = Some(native_vulkan_create_video_session_bitstream_buffer(
                &device,
                &memory_properties,
                &profile_info,
                requested_bitstream_size,
                capabilities.min_bitstream_buffer_size_alignment,
                Some(bitstream_payload),
            )?);
            let parameters = native_vulkan_create_h265_video_session_parameters(
                &video_queue_device,
                video_session,
                parameter_sets,
            )?;
            video_session_parameters = parameters.parameters;
            let image = resource_image
                .as_ref()
                .expect("video resource image was just created");
            let buffer = bitstream_buffer
                .as_ref()
                .expect("bitstream buffer was just created");
            let decode = native_vulkan_decode_h265_first_frame_to_image(
                &device,
                &video_queue_device,
                &video_decode_queue_device,
                video_queue_family.queue_family_index,
                video_session,
                video_session_parameters,
                source_extent,
                capabilities.min_bitstream_buffer_size_alignment,
                image,
                buffer,
                &extract,
                parameter_sets,
            )?;

            renderer = Some(NativeVulkanVideoRenderer::new(
                &device,
                swapchain_plan.format.format,
                swapchain_plan.extent,
                &swapchain_image_views,
            )?);
            texture = Some(NativeVulkanVideoTexture::Decoded(
                NativeVulkanDecodedVideoTexture::new(
                    &device,
                    image.image,
                    width,
                    height,
                    0,
                    vk::ImageLayout::VIDEO_DECODE_DPB_KHR,
                    vk::AccessFlags::MEMORY_WRITE,
                )?,
            ));
            let renderer_ref = renderer.as_mut().expect("video renderer was just created");
            renderer_ref.update_descriptors(
                &device,
                texture.as_ref().expect("decoded texture was just created"),
            );

            let started_at = Instant::now();
            let deadline = started_at + duration;
            let fifo_present_paced = swapchain_plan.present_mode == vk::PresentModeKHR::FIFO;
            let pacing_strategy = if fifo_present_paced {
                "fifo-present-blocking-no-cpu-sleep"
            } else if target_max_fps.is_some_and(|fps| fps > 0) {
                "target-fps-cpu-sleep"
            } else {
                "unlimited"
            };
            let frame_interval = if fifo_present_paced {
                None
            } else {
                target_max_fps
                    .filter(|fps| *fps > 0)
                    .map(|fps| Duration::from_secs_f64(1.0 / fps as f64))
            };
            let mut next_frame = Instant::now();
            let mut frames_rendered = 0u64;
            let mut swapchain_image_layouts =
                vec![vk::ImageLayout::UNDEFINED; swapchain_images.len()];

            while Instant::now() < deadline && !probe.host.is_closed() {
                probe.host.pump_events()?;
                let fences = [in_flight];
                unsafe {
                    device
                        .wait_for_fences(&fences, true, u64::MAX)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkWaitForFences(direct h265 first-frame)",
                            result,
                        })?;
                    device
                        .reset_fences(&fences)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkResetFences(direct h265 first-frame)",
                            result,
                        })?;
                }
                let (image_index, _) = unsafe {
                    swapchain_loader_ref.acquire_next_image(
                        swapchain,
                        u64::MAX,
                        image_available,
                        vk::Fence::null(),
                    )
                }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkAcquireNextImageKHR(direct h265 first-frame)",
                    result,
                })?;
                let image_index = image_index as usize;
                renderer_ref.record_frame(
                    &device,
                    command_buffers[image_index],
                    image_index,
                    swapchain_images[image_index],
                    swapchain_image_layouts[image_index],
                    texture
                        .as_ref()
                        .expect("decoded texture exists during render"),
                    fit,
                )?;
                swapchain_image_layouts[image_index] = renderer_ref.target_final_layout();
                let wait_semaphores = [image_available];
                let wait_stages = [vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT];
                let command_buffers_for_submit = [command_buffers[image_index]];
                let signal_semaphores = [render_finished];
                let submit_info = vk::SubmitInfo::default()
                    .wait_semaphores(&wait_semaphores)
                    .wait_dst_stage_mask(&wait_stages)
                    .command_buffers(&command_buffers_for_submit)
                    .signal_semaphores(&signal_semaphores);
                unsafe {
                    device
                        .queue_submit(present_queue, &[submit_info], in_flight)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkQueueSubmit(direct h265 first-frame present)",
                            result,
                        })?;
                }
                let swapchains = [swapchain];
                let image_indices = [image_index as u32];
                let present_info = vk::PresentInfoKHR::default()
                    .wait_semaphores(&signal_semaphores)
                    .swapchains(&swapchains)
                    .image_indices(&image_indices);
                unsafe {
                    swapchain_loader_ref
                        .queue_present(present_queue, &present_info)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkQueuePresentKHR(direct h265 first-frame)",
                            result,
                        })?;
                }
                frames_rendered = frames_rendered.saturating_add(1);
                if let Some(NativeVulkanVideoTexture::Decoded(texture)) = texture.as_mut() {
                    texture.source_layout = vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL;
                    texture.source_access = vk::AccessFlags::SHADER_READ;
                }

                if let Some(interval) = frame_interval {
                    next_frame += interval;
                    let now = Instant::now();
                    if next_frame > now {
                        thread::sleep(next_frame - now);
                    } else {
                        next_frame = now;
                    }
                }
            }
            unsafe {
                device
                    .wait_for_fences(&[in_flight], true, u64::MAX)
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkWaitForFences(direct h265 first-frame final)",
                        result,
                    })?;
            }

            let elapsed = started_at.elapsed();
            Ok(NativeVulkanDirectH265FirstFrameRuntimeSnapshot {
                runtime_elapsed_ms: elapsed.as_millis().min(u64::MAX as u128) as u64,
                frames_rendered,
                average_render_fps: if elapsed.is_zero() {
                    0.0
                } else {
                    frames_rendered as f64 / elapsed.as_secs_f64()
                },
                configured: probe.host.snapshot().configured,
                source,
                source_extent: (width, height),
                fit,
                target_max_fps,
                wayland_surface_logical_size: surface_snapshot.wayland_surface_logical_size,
                wayland_surface_buffer_size: surface_snapshot.wayland_surface_buffer_size,
                selected_physical_device_name: present_selection.physical_device_name,
                selected_physical_device_type: present_selection.physical_device_type,
                present_queue_family_index,
                present_queue_flags: native_vulkan_queue_flag_labels(present_queue_flags),
                video_decode_queue_family_index: video_queue_family.queue_family_index,
                video_decode_queue_flags: native_vulkan_queue_flag_labels(
                    video_queue_family.queue_flags,
                ),
                video_decode_queue_codec_operations: native_vulkan_video_codec_operation_labels(
                    video_queue_family.video_codec_operations,
                ),
                cross_queue_sync_strategy: "decode-queue-wait-idle-then-present-queue-sampled-render",
                swapchain_extent: (swapchain_plan.extent.width, swapchain_plan.extent.height),
                swapchain_image_count: swapchain_images.len(),
                swapchain_format: native_vulkan_format_label(swapchain_plan.format.format)
                    .to_owned(),
                present_mode: native_vulkan_present_mode_label(swapchain_plan.present_mode),
                pacing_strategy,
                video_resource_memory_bytes: image.snapshot.memory_size,
                session_memory_bytes,
                bitstream_buffer_bytes: buffer.snapshot.size,
                decode,
                last_render_error: None,
            })
        })();

    unsafe {
        let _ = device.device_wait_idle();
        if let Some(texture) = texture.take() {
            texture.destroy(&device);
        }
        if let Some(renderer) = renderer.take() {
            renderer.destroy(&device);
        }
        if image_available != vk::Semaphore::null() {
            device.destroy_semaphore(image_available, None);
        }
        if render_finished != vk::Semaphore::null() {
            device.destroy_semaphore(render_finished, None);
        }
        if in_flight != vk::Fence::null() {
            device.destroy_fence(in_flight, None);
        }
        if command_pool != vk::CommandPool::null() {
            device.destroy_command_pool(command_pool, None);
        }
        if let Some(buffer) = bitstream_buffer.take() {
            native_vulkan_destroy_video_session_bitstream_buffer(&device, buffer);
        }
        let video_queue_device = ash::khr::video_queue::Device::new(&probe.instance, &device);
        if video_session_parameters != vk::VideoSessionParametersKHR::null() {
            (video_queue_device.fp().destroy_video_session_parameters_khr)(
                video_queue_device.device(),
                video_session_parameters,
                ptr::null(),
            );
        }
        if let Some(image) = resource_image.take() {
            native_vulkan_destroy_video_session_resource_image(&device, image);
        }
        if video_session != vk::VideoSessionKHR::null() {
            (video_queue_device.fp().destroy_video_session_khr)(
                video_queue_device.device(),
                video_session,
                ptr::null(),
            );
        }
        for memory in session_memories {
            device.free_memory(memory, None);
        }
        for view in swapchain_image_views {
            device.destroy_image_view(view, None);
        }
        if swapchain != vk::SwapchainKHR::null()
            && let Some(loader) = swapchain_loader.as_ref()
        {
            loader.destroy_swapchain(swapchain, None);
        }
        device.destroy_device(None);
    }

    result
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(clippy::too_many_arguments)]
pub fn run_h264_ready_prefix_video(
    options: NativeVulkanOptions,
    source: PathBuf,
    width: u32,
    height: u32,
    fit: FitMode,
    _bitstream_samples: u32,
    ready_prefix_frame_count: u32,
    input_mode: NativeVulkanH264VideoInputMode,
    playback_frame_count: u32,
) -> Result<NativeVulkanDirectH264ReadyPrefixRuntimeSnapshot, NativeVulkanError> {
    if width == 0 || height == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.264 ready-prefix video requires a non-zero source extent".to_owned(),
        ));
    }
    if ready_prefix_frame_count == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.264 ready-prefix video requires at least one ready-prefix frame".to_owned(),
        ));
    }
    if playback_frame_count == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.264 ready-prefix video requires at least one playback frame".to_owned(),
        ));
    }
    let target_max_fps = options.target_max_fps;
    let queue_capacity =
        native_vulkan_h264_streaming_packet_queue_capacity(ready_prefix_frame_count);
    let mut streaming_queue =
        native_vulkan_start_h264_streaming_packet_queue(&source, queue_capacity)?;
    let parameter_sets = streaming_queue.parameter_sets.clone();
    let streaming_bootstrap =
        native_vulkan_h264_align_streaming_bootstrap(&mut streaming_queue, &parameter_sets)?;
    native_vulkan_require_streaming_bootstrap_window(&streaming_queue, ready_prefix_frame_count)?;
    let stream_sps_dpb_slots = streaming_bootstrap.stream_sps_dpb_slots;
    let stream_dpb_slots = streaming_bootstrap.stream_dpb_slots;
    let stream_max_active_reference_pictures =
        streaming_bootstrap.stream_max_active_reference_pictures;
    let stream_max_frame_num = streaming_bootstrap.max_frame_num;
    let mut probe = NativeVulkanSurfaceProbe::connect(NativeVulkanSurfaceProbeOptions {
        host: options.host,
        wait_configure_roundtrips: options.wait_configure_roundtrips,
    })?;
    probe.pump_events()?;
    let surface_snapshot = probe.snapshot();
    let present_query =
        select_native_vulkan_present_queue(&probe.instance, &probe.surface_loader, probe.surface)?;
    let present_selection = present_query.selection;
    let present_queue_family_index = present_selection.queue_family_index;
    let present_queue_families = unsafe {
        probe
            .instance
            .get_physical_device_queue_family_properties(present_selection.physical_device)
    };
    let present_queue_flags = present_queue_families
        .get(present_queue_family_index as usize)
        .map(|queue| queue.queue_flags)
        .unwrap_or_default();
    let video_queue_family = native_vulkan_video_decode_queue_family_infos(
        &probe.instance,
        present_selection.physical_device,
    )
    .into_iter()
    .find(|queue_family| {
        queue_family.queue_count > 0
            && queue_family
                .queue_flags
                .contains(vk::QueueFlags::VIDEO_DECODE_KHR)
            && queue_family
                .video_codec_operations
                .contains(vk::VideoCodecOperationFlagsKHR::DECODE_H264)
    })
    .ok_or_else(|| {
        NativeVulkanError::Video(format!(
            "selected present device {} has no same-device H.264 Vulkan Video decode queue",
            present_selection.physical_device_name
        ))
    })?;

    ensure_native_vulkan_device_extension(
        &probe.instance,
        present_selection.physical_device,
        ash::khr::swapchain::NAME,
    )?;
    for extension in native_vulkan_video_session_required_device_extensions(
        NativeVulkanVideoSessionCodec::H264High8,
    ) {
        ensure_native_vulkan_device_extension(
            &probe.instance,
            present_selection.physical_device,
            extension,
        )?;
    }

    let mut h264_profile_info = vk::VideoDecodeH264ProfileInfoKHR::default()
        .std_profile_idc(vk::native::StdVideoH264ProfileIdc_STD_VIDEO_H264_PROFILE_IDC_HIGH)
        .picture_layout(vk::VideoDecodeH264PictureLayoutFlagsKHR::PROGRESSIVE);
    let profile_info = vk::VideoProfileInfoKHR::default()
        .video_codec_operation(vk::VideoCodecOperationFlagsKHR::DECODE_H264)
        .chroma_subsampling(vk::VideoChromaSubsamplingFlagsKHR::TYPE_420)
        .luma_bit_depth(vk::VideoComponentBitDepthFlagsKHR::TYPE_8)
        .chroma_bit_depth(vk::VideoComponentBitDepthFlagsKHR::TYPE_8)
        .push_next(&mut h264_profile_info);
    let video_queue_loader = ash::khr::video_queue::Instance::new(&probe._entry, &probe.instance);
    let capabilities = native_vulkan_video_session_h264_capabilities(
        &video_queue_loader,
        present_selection.physical_device,
        &profile_info,
    )?;
    let source_extent = vk::Extent2D { width, height };
    if !native_vulkan_video_session_extent_supported(source_extent, &capabilities) {
        return Err(NativeVulkanError::Video(format!(
            "direct H.264 ready-prefix source extent {width}x{height} is outside {:?}..{:?} or not aligned to {:?}",
            (
                capabilities.min_coded_extent.width,
                capabilities.min_coded_extent.height
            ),
            (
                capabilities.max_coded_extent.width,
                capabilities.max_coded_extent.height
            ),
            (
                capabilities.picture_access_granularity.width,
                capabilities.picture_access_granularity.height
            )
        )));
    }
    let format_probe = native_vulkan_video_decode_format_probe(
        &video_queue_loader,
        present_selection.physical_device,
        &profile_info,
        capabilities.decode_capability_flags,
    );
    if !format_probe.nv12_dpb_supported
        || !format_probe.nv12_output_supported
        || !format_probe.nv12_sampled_output_supported
    {
        return Err(NativeVulkanError::Video(format!(
            "direct H.264 ready-prefix video requires NV12 decode+sampled support{}",
            format_probe
                .query_error
                .as_ref()
                .map(|err| format!(": {err}"))
                .unwrap_or_default()
        )));
    }

    let mut device_queue_family_indices = vec![present_queue_family_index];
    if !device_queue_family_indices.contains(&video_queue_family.queue_family_index) {
        device_queue_family_indices.push(video_queue_family.queue_family_index);
    }
    let priorities = [1.0_f32];
    let queue_create_infos = device_queue_family_indices
        .iter()
        .copied()
        .map(|queue_family_index| {
            vk::DeviceQueueCreateInfo::default()
                .queue_family_index(queue_family_index)
                .queue_priorities(&priorities)
        })
        .collect::<Vec<_>>();
    let mut enabled_extensions = vec![ash::khr::swapchain::NAME.as_ptr()];
    enabled_extensions.extend(
        native_vulkan_video_session_required_device_extensions(
            NativeVulkanVideoSessionCodec::H264High8,
        )
        .iter()
        .map(|extension| extension.as_ptr()),
    );
    let mut synchronization2_features =
        vk::PhysicalDeviceSynchronization2Features::default().synchronization2(true);
    let device_create_info = vk::DeviceCreateInfo::default()
        .queue_create_infos(&queue_create_infos)
        .enabled_extension_names(&enabled_extensions)
        .push_next(&mut synchronization2_features);
    let device = unsafe {
        probe
            .instance
            .create_device(present_selection.physical_device, &device_create_info, None)
    }
    .map_err(|result| NativeVulkanError::Vulkan {
        operation: "vkCreateDevice(direct h264 ready-prefix video)",
        result,
    })?;

    let mut swapchain_loader = None::<ash::khr::swapchain::Device>;
    let mut swapchain = vk::SwapchainKHR::null();
    let mut swapchain_image_views = Vec::<vk::ImageView>::new();
    let mut present_command_pool = vk::CommandPool::null();
    let mut present_command_buffers = Vec::<vk::CommandBuffer>::new();
    let mut video_command_pool = vk::CommandPool::null();
    let mut image_available = vk::Semaphore::null();
    let mut decode_finished = vk::Semaphore::null();
    let mut render_finished = vk::Semaphore::null();
    let mut in_flight = vk::Fence::null();
    let mut renderer = None::<NativeVulkanVideoRenderer>;
    let mut retired_textures = Vec::<NativeVulkanVideoTexture>::new();
    let mut decoded_plane_view_cache = Vec::<NativeVulkanDecodedVideoPlaneViews>::new();
    let mut video_session = vk::VideoSessionKHR::null();
    let mut video_session_parameters = vk::VideoSessionParametersKHR::null();
    let mut session_memories = Vec::<vk::DeviceMemory>::new();
    let mut resource_image = None::<NativeVulkanVideoResourceImage>;
    let mut bitstream_buffer = None::<NativeVulkanVideoBitstreamBuffer>;

    let result =
        (|| -> Result<NativeVulkanDirectH264ReadyPrefixRuntimeSnapshot, NativeVulkanError> {
            let present_queue = unsafe { device.get_device_queue(present_queue_family_index, 0) };
            let video_queue =
                unsafe { device.get_device_queue(video_queue_family.queue_family_index, 0) };
            let video_queue_device = ash::khr::video_queue::Device::new(&probe.instance, &device);
            let video_decode_queue_device =
                ash::khr::video_decode_queue::Device::new(&probe.instance, &device);
            let memory_properties = unsafe {
                probe
                    .instance
                    .get_physical_device_memory_properties(present_selection.physical_device)
            };

            swapchain_loader = Some(ash::khr::swapchain::Device::new(&probe.instance, &device));
            let swapchain_loader_ref = swapchain_loader
                .as_ref()
                .expect("swapchain loader was just created");
            let swapchain_plan = create_native_vulkan_swapchain_plan(
                &probe.surface_loader,
                present_selection.physical_device,
                probe.surface,
                surface_snapshot.wayland_surface_logical_size,
                surface_snapshot.wayland_surface_buffer_size,
            )?;
            swapchain =
                unsafe { swapchain_loader_ref.create_swapchain(&swapchain_plan.create_info, None) }
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkCreateSwapchainKHR(direct h264 ready-prefix video)",
                        result,
                    })?;
            let swapchain_images = unsafe { swapchain_loader_ref.get_swapchain_images(swapchain) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkGetSwapchainImagesKHR(direct h264 ready-prefix video)",
                    result,
                })?;
            swapchain_image_views = create_native_vulkan_swapchain_image_views(
                &device,
                &swapchain_images,
                swapchain_plan.format.format,
            )?;
            let present_command_pool_info = vk::CommandPoolCreateInfo::default()
                .flags(vk::CommandPoolCreateFlags::RESET_COMMAND_BUFFER)
                .queue_family_index(present_queue_family_index);
            present_command_pool =
                unsafe { device.create_command_pool(&present_command_pool_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkCreateCommandPool(direct h264 ready-prefix present)",
                        result,
                    },
                )?;
            let present_command_buffer_info = vk::CommandBufferAllocateInfo::default()
                .command_pool(present_command_pool)
                .level(vk::CommandBufferLevel::PRIMARY)
                .command_buffer_count(swapchain_images.len() as u32);
            present_command_buffers =
                unsafe { device.allocate_command_buffers(&present_command_buffer_info) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateCommandBuffers(direct h264 ready-prefix present)",
                        result,
                    },
                )?;
            let video_command_pool_info = vk::CommandPoolCreateInfo::default()
                .flags(
                    vk::CommandPoolCreateFlags::TRANSIENT
                        | vk::CommandPoolCreateFlags::RESET_COMMAND_BUFFER,
                )
                .queue_family_index(video_queue_family.queue_family_index);
            video_command_pool =
                unsafe { device.create_command_pool(&video_command_pool_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkCreateCommandPool(direct h264 ready-prefix decode)",
                        result,
                    },
                )?;
            let video_command_buffer_info = vk::CommandBufferAllocateInfo::default()
                .command_pool(video_command_pool)
                .level(vk::CommandBufferLevel::PRIMARY)
                .command_buffer_count(1);
            let video_command_buffer =
                unsafe { device.allocate_command_buffers(&video_command_buffer_info) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateCommandBuffers(direct h264 ready-prefix decode)",
                        result,
                    },
                )?[0];
            let semaphore_create_info = vk::SemaphoreCreateInfo::default();
            image_available = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h264 ready-prefix image_available)",
                    result,
                })?;
            decode_finished = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h264 ready-prefix decode_finished)",
                    result,
                })?;
            render_finished = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h264 ready-prefix render_finished)",
                    result,
                })?;
            let fence_create_info =
                vk::FenceCreateInfo::default().flags(vk::FenceCreateFlags::SIGNALED);
            in_flight =
                unsafe { device.create_fence(&fence_create_info, None) }.map_err(|result| {
                    NativeVulkanError::Vulkan {
                        operation: "vkCreateFence(direct h264 ready-prefix)",
                        result,
                    }
                })?;

            let streaming_bitstream = native_vulkan_h264_streaming_queue_bitstream_plan(
                &streaming_queue,
                width,
                height,
                capabilities.min_bitstream_buffer_offset_alignment,
                capabilities.min_bitstream_buffer_size_alignment,
            )?;
            let session_max_dpb_slots = native_vulkan_h265_session_dpb_slots_for_count(
                capabilities.max_dpb_slots,
                stream_dpb_slots,
            );
            if session_max_dpb_slots < stream_dpb_slots {
                return Err(NativeVulkanError::Video(format!(
                    "H.264 stream needs {stream_dpb_slots} DPB slots but driver/session allow {session_max_dpb_slots}"
                )));
            }
            let session_max_active_reference_pictures =
                native_vulkan_video_session_max_active_reference_pictures_for_stream(
                    capabilities.max_active_reference_pictures,
                    session_max_dpb_slots,
                    stream_max_active_reference_pictures.max(1),
                );
            let picture_format = vk::Format::G8_B8R8_2PLANE_420_UNORM;
            let create_info = vk::VideoSessionCreateInfoKHR::default()
                .queue_family_index(video_queue_family.queue_family_index)
                .video_profile(&profile_info)
                .picture_format(picture_format)
                .reference_picture_format(picture_format)
                .max_coded_extent(source_extent)
                .max_dpb_slots(session_max_dpb_slots)
                .max_active_reference_pictures(session_max_active_reference_pictures)
                .std_header_version(&capabilities.std_header_version);
            video_session = native_vulkan_create_video_session(&video_queue_device, &create_info)?;

            let memory_requirements = native_vulkan_video_session_memory_requirements(
                &video_queue_device,
                video_session,
            )?;
            let mut bind_infos = Vec::with_capacity(memory_requirements.len());
            let mut session_memory_bytes = 0u64;
            for requirement in memory_requirements.iter() {
                if requirement.memory_requirements.size == 0 {
                    return Err(NativeVulkanError::Video(format!(
                        "direct H.264 ready-prefix session memory bind {} reported zero size",
                        requirement.memory_bind_index
                    )));
                }
                let memory_type_index = native_vulkan_memory_type_index(
                    &memory_properties,
                    requirement.memory_requirements.memory_type_bits,
                    vk::MemoryPropertyFlags::DEVICE_LOCAL,
                )
                .or_else(|| {
                    native_vulkan_memory_type_index(
                        &memory_properties,
                        requirement.memory_requirements.memory_type_bits,
                        vk::MemoryPropertyFlags::empty(),
                    )
                })
                .ok_or(NativeVulkanError::MissingMemoryType(
                    "direct H.264 ready-prefix video session memory",
                ))?;
                let allocation_info = vk::MemoryAllocateInfo::default()
                    .allocation_size(requirement.memory_requirements.size)
                    .memory_type_index(memory_type_index);
                let memory = unsafe { device.allocate_memory(&allocation_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateMemory(direct h264 ready-prefix video session)",
                        result,
                    },
                )?;
                session_memories.push(memory);
                bind_infos.push(
                    vk::BindVideoSessionMemoryInfoKHR::default()
                        .memory_bind_index(requirement.memory_bind_index)
                        .memory(memory)
                        .memory_offset(0)
                        .memory_size(requirement.memory_requirements.size),
                );
                session_memory_bytes =
                    session_memory_bytes.saturating_add(requirement.memory_requirements.size);
            }
            native_vulkan_bind_video_session_memory(
                &video_queue_device,
                video_session,
                &bind_infos,
            )?;

            resource_image = Some(native_vulkan_create_video_session_resource_image(
                &video_queue_loader,
                &device,
                &memory_properties,
                present_selection.physical_device,
                &profile_info,
                source_extent,
                session_max_dpb_slots.max(1),
                picture_format,
                capabilities.decode_capability_flags,
                vk::ImageUsageFlags::empty(),
                &device_queue_family_indices,
                false,
            )?);

            bitstream_buffer = Some(
                native_vulkan_create_video_session_bitstream_buffer_with_mapping(
                    &device,
                    &memory_properties,
                    &profile_info,
                    streaming_bitstream.ring_capacity_bytes,
                    capabilities.min_bitstream_buffer_size_alignment,
                    None,
                    true,
                )?,
            );
            let parameters = native_vulkan_create_h264_video_session_parameters(
                &video_queue_device,
                video_session,
                &parameter_sets,
            )?;
            video_session_parameters = parameters.parameters;
            let image = resource_image
                .as_ref()
                .expect("video resource image was just created");
            let buffer = bitstream_buffer
                .as_ref()
                .expect("bitstream buffer was just created");
            renderer = Some(NativeVulkanVideoRenderer::new(
                &device,
                swapchain_plan.format.format,
                swapchain_plan.extent,
                &swapchain_image_views,
            )?);
            let renderer_ref = renderer.as_mut().expect("video renderer was just created");

            let mut image_layer_layouts =
                vec![vk::ImageLayout::UNDEFINED; image.snapshot.array_layers as usize];
            decoded_plane_view_cache = native_vulkan_create_decoded_video_plane_view_cache(
                &device,
                image.image,
                image.snapshot.array_layers,
            )?;
            let mut active_dpb_refs = vec![
                None::<NativeVulkanH264ActiveDpbReference>;
                image.snapshot.array_layers as usize
            ];
            let mut swapchain_image_layouts =
                vec![vk::ImageLayout::UNDEFINED; swapchain_images.len()];
            let fifo_present_paced = swapchain_plan.present_mode == vk::PresentModeKHR::FIFO;
            let pacing_strategy = if fifo_present_paced {
                "fifo-present-blocking-no-cpu-sleep"
            } else if target_max_fps.is_some_and(|fps| fps > 0) {
                "target-fps-cpu-sleep"
            } else {
                "unlimited"
            };
            let frame_interval = if fifo_present_paced {
                None
            } else {
                target_max_fps
                    .filter(|fps| *fps > 0)
                    .map(|fps| Duration::from_secs_f64(1.0 / fps as f64))
            };
            let mut next_frame = Instant::now();
            let started_at = Instant::now();
            let mut previous_pts_ms = None::<u64>;
            let mut previous_duration_ms = None::<u64>;
            let mut frames = Vec::with_capacity(playback_frame_count as usize);
            let mut loop_boundary_reset_count = 0u32;
            let mut frame_sleep_count = 0u32;
            let mut missed_frame_pacing_count = 0u32;
            let mut total_frame_sleep_us = 0u64;
            let mut max_frame_pacing_late_us = 0u64;
            let mut bitstream_ring = NativeVulkanVideoBitstreamRing::new(&streaming_bitstream);
            let mut streaming_reference_planner = NativeVulkanH264DecodeReferencePlanner::new(
                stream_dpb_slots,
                stream_max_active_reference_pictures.max(1),
                stream_max_frame_num,
                parameter_sets.sps.gaps_in_frame_num_value_allowed_flag,
            );
            let mut previous_source_loop_index = 0u32;

            for playback_frame_index in 0..playback_frame_count {
                probe.host.pump_events()?;
                if probe.host.is_closed() {
                    break;
                }
                let packet = streaming_queue.next_packet(true)?;
                let access_unit = packet.snapshot.clone();
                let entry = streaming_reference_planner.plan_next(&access_unit);
                if !entry.ready_for_decode_submit {
                    return Err(NativeVulkanError::Video(format!(
                        "H.264 streaming AU {} is not decodable: {}",
                        entry.access_unit_index,
                        entry
                            .unsupported_reason
                            .as_deref()
                            .unwrap_or("missing references")
                    )));
                }
                let playback_loop_index = packet.source_loop_index;
                let ready_prefix_frame_index = playback_frame_index;
                let loop_boundary_reset =
                    playback_frame_index > 0 && playback_loop_index != previous_source_loop_index;
                previous_source_loop_index = playback_loop_index;
                let fences = [in_flight];
                let fence_wait_started_at = Instant::now();
                unsafe {
                    device
                        .wait_for_fences(&fences, true, u64::MAX)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkWaitForFences(direct h264 ready-prefix)",
                            result,
                        })?;
                    for texture in retired_textures.drain(..) {
                        texture.destroy(&device);
                    }
                    device
                        .reset_fences(&fences)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkResetFences(direct h264 ready-prefix)",
                            result,
                        })?;
                }
                let fence_wait_elapsed_us =
                    native_vulkan_elapsed_us(fence_wait_started_at.elapsed());
                let pts_delta_ms = if loop_boundary_reset {
                    previous_duration_ms
                        .or(access_unit.duration_ms)
                        .or_else(|| frame_interval.map(|interval| interval.as_millis() as u64))
                } else {
                    access_unit.pts_ms.and_then(|pts_ms| {
                        previous_pts_ms.map(|previous| pts_ms.saturating_sub(previous))
                    })
                };
                let reset_before_decode = playback_frame_index == 0
                    || loop_boundary_reset
                    || access_unit
                        .first_slice
                        .as_ref()
                        .is_some_and(|slice| slice.idr);
                if loop_boundary_reset {
                    loop_boundary_reset_count = loop_boundary_reset_count.saturating_add(1);
                }
                if reset_before_decode {
                    active_dpb_refs.fill(None);
                }
                let bitstream_upload_started_at = Instant::now();
                let span = native_vulkan_write_h264_streaming_packet_to_bitstream_ring(
                    &packet,
                    &device,
                    buffer,
                    &mut bitstream_ring,
                )?;
                let bitstream_upload_elapsed_us =
                    native_vulkan_elapsed_us(bitstream_upload_started_at.elapsed());
                for dropped_slot in &entry.inferred_dropped_reference_slots {
                    if let Some(slot) = active_dpb_refs.get_mut(*dropped_slot as usize) {
                        *slot = None;
                    }
                }
                for inferred_reference in &entry.inferred_non_existing_references {
                    if let Some(slot) =
                        active_dpb_refs.get_mut(inferred_reference.dpb_slot as usize)
                    {
                        *slot = Some(NativeVulkanH264ActiveDpbReference {
                            frame_num: inferred_reference.frame_num,
                            pic_order_cnt_val: inferred_reference.pic_order_cnt_val,
                            used_for_long_term_reference: false,
                            non_existing: true,
                        });
                    }
                }
                let mut frame = native_vulkan_decode_h264_ready_prefix_frame_to_image(
                    &device,
                    &video_queue_device,
                    &video_decode_queue_device,
                    video_queue,
                    video_command_buffer,
                    video_session,
                    video_session_parameters,
                    source_extent,
                    image,
                    buffer,
                    buffer.snapshot.size,
                    &parameter_sets,
                    &entry,
                    &access_unit,
                    &span,
                    &active_dpb_refs,
                    &mut image_layer_layouts,
                    reset_before_decode,
                    pts_delta_ms,
                    decode_finished,
                    playback_frame_index,
                    playback_loop_index,
                    ready_prefix_frame_index,
                    loop_boundary_reset,
                    bitstream_upload_elapsed_us,
                )?;
                frame.fence_wait_elapsed_us = fence_wait_elapsed_us;
                for dropped_slot in &entry.dropped_reference_slots {
                    if *dropped_slot != frame.dst_base_array_layer
                        && let Some(slot) = active_dpb_refs.get_mut(*dropped_slot as usize)
                    {
                        *slot = None;
                    }
                }
                for conversion in &entry.long_term_reference_conversions {
                    if let Some(Some(reference)) =
                        active_dpb_refs.get_mut(conversion.dpb_slot as usize)
                        && reference.frame_num == conversion.frame_num
                    {
                        reference.used_for_long_term_reference = true;
                    }
                }
                if let Some(slot) = active_dpb_refs.get_mut(frame.dst_base_array_layer as usize) {
                    if frame.is_reference {
                        *slot = Some(NativeVulkanH264ActiveDpbReference {
                            frame_num: frame.frame_num,
                            pic_order_cnt_val: frame.pic_order_cnt_val,
                            used_for_long_term_reference: frame.used_for_long_term_reference,
                            non_existing: false,
                        });
                    } else {
                        *slot = None;
                    }
                }

                let present_started_at = Instant::now();
                let decoded_views = decoded_plane_view_cache
                    .get(frame.dst_base_array_layer as usize)
                    .copied()
                    .ok_or_else(|| {
                        NativeVulkanError::Video(format!(
                            "H.264 decoded view cache has {} layers but layer {} was requested",
                            decoded_plane_view_cache.len(),
                            frame.dst_base_array_layer
                        ))
                    })?;
                let texture = NativeVulkanVideoTexture::Decoded(
                    NativeVulkanDecodedVideoTexture::from_cached_views(
                        image.image,
                        width,
                        height,
                        frame.dst_base_array_layer,
                        decoded_views,
                        vk::ImageLayout::VIDEO_DECODE_DPB_KHR,
                        vk::AccessFlags::MEMORY_WRITE,
                    )?,
                );
                let descriptor_update_started_at = Instant::now();
                renderer_ref.update_descriptors(&device, &texture);
                frame.descriptor_update_elapsed_us =
                    native_vulkan_elapsed_us(descriptor_update_started_at.elapsed());
                let acquire_started_at = Instant::now();
                let (image_index, _) = unsafe {
                    swapchain_loader_ref.acquire_next_image(
                        swapchain,
                        u64::MAX,
                        image_available,
                        vk::Fence::null(),
                    )
                }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkAcquireNextImageKHR(direct h264 ready-prefix)",
                    result,
                })?;
                frame.acquire_elapsed_us = native_vulkan_elapsed_us(acquire_started_at.elapsed());
                let image_index = image_index as usize;
                let record_started_at = Instant::now();
                renderer_ref.record_frame(
                    &device,
                    present_command_buffers[image_index],
                    image_index,
                    swapchain_images[image_index],
                    swapchain_image_layouts[image_index],
                    &texture,
                    fit,
                )?;
                frame.record_elapsed_us = native_vulkan_elapsed_us(record_started_at.elapsed());
                swapchain_image_layouts[image_index] = renderer_ref.target_final_layout();
                let wait_semaphores = [image_available, decode_finished];
                let wait_stages = [
                    vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT,
                    vk::PipelineStageFlags::ALL_COMMANDS,
                ];
                let command_buffers_for_submit = [present_command_buffers[image_index]];
                let signal_semaphores = [render_finished];
                let submit_info = vk::SubmitInfo::default()
                    .wait_semaphores(&wait_semaphores)
                    .wait_dst_stage_mask(&wait_stages)
                    .command_buffers(&command_buffers_for_submit)
                    .signal_semaphores(&signal_semaphores);
                let submit_started_at = Instant::now();
                unsafe {
                    device
                        .queue_submit(present_queue, &[submit_info], in_flight)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkQueueSubmit(direct h264 ready-prefix present)",
                            result,
                        })?;
                }
                frame.submit_elapsed_us = native_vulkan_elapsed_us(submit_started_at.elapsed());
                let swapchains = [swapchain];
                let image_indices = [image_index as u32];
                let present_info = vk::PresentInfoKHR::default()
                    .wait_semaphores(&signal_semaphores)
                    .swapchains(&swapchains)
                    .image_indices(&image_indices);
                let queue_present_started_at = Instant::now();
                unsafe {
                    swapchain_loader_ref
                        .queue_present(present_queue, &present_info)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkQueuePresentKHR(direct h264 ready-prefix)",
                            result,
                        })?;
                }
                frame.queue_present_elapsed_us =
                    native_vulkan_elapsed_us(queue_present_started_at.elapsed());
                image_layer_layouts[frame.dst_base_array_layer as usize] =
                    vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL;
                frame.present_elapsed_us = native_vulkan_elapsed_us(present_started_at.elapsed());
                previous_pts_ms = access_unit.pts_ms;
                previous_duration_ms = access_unit.duration_ms;
                retired_textures.push(texture);
                frames.push(frame);

                if let Some(interval) = frame_interval
                    && playback_frame_index + 1 < playback_frame_count
                {
                    next_frame += interval;
                    let now = Instant::now();
                    if next_frame > now {
                        let sleep_duration = next_frame - now;
                        frame_sleep_count = frame_sleep_count.saturating_add(1);
                        total_frame_sleep_us = total_frame_sleep_us
                            .saturating_add(native_vulkan_elapsed_us(sleep_duration));
                        thread::sleep(sleep_duration);
                    } else {
                        missed_frame_pacing_count = missed_frame_pacing_count.saturating_add(1);
                        max_frame_pacing_late_us = max_frame_pacing_late_us
                            .max(native_vulkan_elapsed_us(now.duration_since(next_frame)));
                        next_frame = now;
                    }
                }
            }
            unsafe {
                device
                    .wait_for_fences(&[in_flight], true, u64::MAX)
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkWaitForFences(direct h264 ready-prefix final)",
                        result,
                    })?;
            }
            for texture in retired_textures.drain(..) {
                texture.destroy(&device);
            }

            let elapsed = started_at.elapsed();
            let presented_frame_count = frames.len() as u32;
            Ok(NativeVulkanDirectH264ReadyPrefixRuntimeSnapshot {
                runtime_elapsed_ms: elapsed.as_millis().min(u64::MAX as u128) as u64,
                requested_frame_count: playback_frame_count,
                ready_prefix_frame_count,
                requested_playback_frame_count: playback_frame_count,
                decoded_frame_count: frames.len() as u32,
                presented_frame_count,
                playback_loop_count: if frames.is_empty() {
                    0
                } else {
                    frames
                        .last()
                        .map(|frame| frame.playback_loop_index.saturating_add(1))
                        .unwrap_or(0)
                },
                loop_boundary_reset_count,
                frame_sleep_count,
                missed_frame_pacing_count,
                total_frame_sleep_us,
                max_frame_pacing_late_us,
                average_present_fps: if elapsed.is_zero() {
                    0.0
                } else {
                    f64::from(presented_frame_count) / elapsed.as_secs_f64()
                },
                configured: probe.host.snapshot().configured,
                source,
                source_extent: (width, height),
                fit,
                target_max_fps,
                wayland_surface_logical_size: surface_snapshot.wayland_surface_logical_size,
                wayland_surface_buffer_size: surface_snapshot.wayland_surface_buffer_size,
                selected_physical_device_name: present_selection.physical_device_name,
                selected_physical_device_type: present_selection.physical_device_type,
                present_queue_family_index,
                present_queue_flags: native_vulkan_queue_flag_labels(present_queue_flags),
                video_decode_queue_family_index: video_queue_family.queue_family_index,
                video_decode_queue_flags: native_vulkan_queue_flag_labels(
                    video_queue_family.queue_flags,
                ),
                video_decode_queue_codec_operations: native_vulkan_video_codec_operation_labels(
                    video_queue_family.video_codec_operations,
                ),
                cross_queue_sync_strategy: "per-frame-binary-semaphore-decode-signal-present-wait",
                driver_max_dpb_slots: capabilities.max_dpb_slots,
                stream_sps_dpb_slots,
                stream_dpb_slots,
                stream_max_active_reference_pictures,
                session_max_dpb_slots,
                session_max_active_reference_pictures,
                swapchain_extent: (swapchain_plan.extent.width, swapchain_plan.extent.height),
                swapchain_image_count: swapchain_images.len(),
                swapchain_format: native_vulkan_format_label(swapchain_plan.format.format)
                    .to_owned(),
                present_mode: native_vulkan_present_mode_label(swapchain_plan.present_mode),
                pacing_strategy,
                video_resource_memory_bytes: image.snapshot.memory_size,
                session_memory_bytes,
                bitstream_buffer_bytes: buffer.snapshot.size,
                bitstream_buffer_strategy: "fixed-capacity-persistent-mapped-ring",
                bitstream_buffer_slot_count: streaming_bitstream.ring_slot_count,
                bitstream_buffer_slot_bytes: streaming_bitstream.slot_bytes,
                bitstream_ring_capacity_bytes: streaming_bitstream.ring_capacity_bytes,
                bitstream_ring_min_offset_alignment: streaming_bitstream.min_offset_alignment,
                bitstream_ring_min_size_alignment: streaming_bitstream.min_size_alignment,
                bitstream_ring_wrap_count: bitstream_ring.wrap_count(),
                bitstream_window_payload_bytes: streaming_bitstream.window_payload_bytes,
                bitstream_upload_count: frames.len() as u32,
                bitstream_uploaded_bytes: frames.iter().map(|frame| frame.src_buffer_range).sum(),
                h264_input_mode: input_mode.as_str(),
                h264_packet_queue_capacity: streaming_queue.capacity.min(u32::MAX as usize) as u32,
                h264_packet_queue_pulled_count: streaming_queue.pulled_count,
                h264_packet_queue_eos_count: streaming_queue.eos_count,
                h264_packet_queue_loop_count: streaming_queue.loop_count,
                h264_packet_queue_loop_skip_access_units: streaming_queue.loop_skip_access_units,
                h264_packet_queue_bootstrap_discarded_access_units: streaming_queue
                    .bootstrap_discarded_access_units,
                h264_packet_queue_max_payload_bytes: streaming_queue.max_payload_bytes,
                h264_packet_queue_retained_payload_bytes: streaming_queue.retained_payload_bytes(),
                pts_delta_min_ms: frames.iter().filter_map(|frame| frame.pts_delta_ms).min(),
                pts_delta_max_ms: frames.iter().filter_map(|frame| frame.pts_delta_ms).max(),
                frames,
                last_render_error: None,
            })
        })();

    unsafe {
        let _ = device.device_wait_idle();
        for texture in retired_textures.drain(..) {
            texture.destroy(&device);
        }
        if let Some(renderer) = renderer.take() {
            renderer.destroy(&device);
        }
        native_vulkan_destroy_decoded_video_plane_view_cache(
            &device,
            std::mem::take(&mut decoded_plane_view_cache),
        );
        if image_available != vk::Semaphore::null() {
            device.destroy_semaphore(image_available, None);
        }
        if decode_finished != vk::Semaphore::null() {
            device.destroy_semaphore(decode_finished, None);
        }
        if render_finished != vk::Semaphore::null() {
            device.destroy_semaphore(render_finished, None);
        }
        if in_flight != vk::Fence::null() {
            device.destroy_fence(in_flight, None);
        }
        if video_command_pool != vk::CommandPool::null() {
            device.destroy_command_pool(video_command_pool, None);
        }
        if present_command_pool != vk::CommandPool::null() {
            device.destroy_command_pool(present_command_pool, None);
        }
        if let Some(buffer) = bitstream_buffer.take() {
            native_vulkan_destroy_video_session_bitstream_buffer(&device, buffer);
        }
        let video_queue_device = ash::khr::video_queue::Device::new(&probe.instance, &device);
        if video_session_parameters != vk::VideoSessionParametersKHR::null() {
            (video_queue_device.fp().destroy_video_session_parameters_khr)(
                video_queue_device.device(),
                video_session_parameters,
                ptr::null(),
            );
        }
        if let Some(image) = resource_image.take() {
            native_vulkan_destroy_video_session_resource_image(&device, image);
        }
        if video_session != vk::VideoSessionKHR::null() {
            (video_queue_device.fp().destroy_video_session_khr)(
                video_queue_device.device(),
                video_session,
                ptr::null(),
            );
        }
        for memory in session_memories {
            device.free_memory(memory, None);
        }
        for view in swapchain_image_views {
            device.destroy_image_view(view, None);
        }
        if swapchain != vk::SwapchainKHR::null()
            && let Some(loader) = swapchain_loader.as_ref()
        {
            loader.destroy_swapchain(swapchain, None);
        }
        device.destroy_device(None);
    }

    result
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(clippy::too_many_arguments)]
pub fn run_h265_ready_prefix_video(
    options: NativeVulkanOptions,
    source: PathBuf,
    width: u32,
    height: u32,
    fit: FitMode,
    _bitstream_samples: u32,
    ready_prefix_frame_count: u32,
    input_mode: NativeVulkanH265VideoInputMode,
    playback_frame_count: u32,
) -> Result<NativeVulkanDirectH265ReadyPrefixRuntimeSnapshot, NativeVulkanError> {
    if width == 0 || height == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.265 ready-prefix video requires a non-zero source extent".to_owned(),
        ));
    }
    if ready_prefix_frame_count == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.265 ready-prefix video requires at least one ready-prefix frame".to_owned(),
        ));
    }
    if playback_frame_count == 0 {
        return Err(NativeVulkanError::Video(
            "direct H.265 ready-prefix video requires at least one playback frame".to_owned(),
        ));
    }
    let target_max_fps = options.target_max_fps;
    let queue_capacity =
        native_vulkan_h265_streaming_packet_queue_capacity(ready_prefix_frame_count);
    let mut streaming_queue =
        native_vulkan_start_h265_streaming_packet_queue(&source, queue_capacity)?;
    let parameter_sets = streaming_queue.parameter_sets.clone();
    let streaming_bootstrap =
        native_vulkan_h265_align_streaming_bootstrap(&mut streaming_queue, &parameter_sets)?;
    native_vulkan_require_streaming_bootstrap_window(&streaming_queue, ready_prefix_frame_count)?;
    let stream_sps_dpb_slots = streaming_bootstrap.stream_sps_dpb_slots;
    let stream_max_pic_order_cnt_lsb = streaming_bootstrap.stream_max_pic_order_cnt_lsb;
    let stream_dpb_slots = streaming_bootstrap.stream_dpb_slots;
    let stream_max_active_reference_pictures =
        streaming_bootstrap.stream_max_active_reference_pictures;
    let mut probe = NativeVulkanSurfaceProbe::connect(NativeVulkanSurfaceProbeOptions {
        host: options.host,
        wait_configure_roundtrips: options.wait_configure_roundtrips,
    })?;
    probe.pump_events()?;
    let surface_snapshot = probe.snapshot();
    let present_query =
        select_native_vulkan_present_queue(&probe.instance, &probe.surface_loader, probe.surface)?;
    let present_selection = present_query.selection;
    let present_queue_family_index = present_selection.queue_family_index;
    let present_queue_families = unsafe {
        probe
            .instance
            .get_physical_device_queue_family_properties(present_selection.physical_device)
    };
    let present_queue_flags = present_queue_families
        .get(present_queue_family_index as usize)
        .map(|queue| queue.queue_flags)
        .unwrap_or_default();
    let video_queue_family = native_vulkan_video_decode_queue_family_infos(
        &probe.instance,
        present_selection.physical_device,
    )
    .into_iter()
    .find(|queue_family| {
        queue_family.queue_count > 0
            && queue_family
                .queue_flags
                .contains(vk::QueueFlags::VIDEO_DECODE_KHR)
            && queue_family
                .video_codec_operations
                .contains(vk::VideoCodecOperationFlagsKHR::DECODE_H265)
    })
    .ok_or_else(|| {
        NativeVulkanError::Video(format!(
            "selected present device {} has no same-device H.265 Vulkan Video decode queue",
            present_selection.physical_device_name
        ))
    })?;

    ensure_native_vulkan_device_extension(
        &probe.instance,
        present_selection.physical_device,
        ash::khr::swapchain::NAME,
    )?;
    for extension in native_vulkan_video_session_required_device_extensions(
        NativeVulkanVideoSessionCodec::H265Main8,
    ) {
        ensure_native_vulkan_device_extension(
            &probe.instance,
            present_selection.physical_device,
            extension,
        )?;
    }

    let mut h265_profile_info = vk::VideoDecodeH265ProfileInfoKHR::default()
        .std_profile_idc(vk::native::StdVideoH265ProfileIdc_STD_VIDEO_H265_PROFILE_IDC_MAIN);
    let profile_info = vk::VideoProfileInfoKHR::default()
        .video_codec_operation(vk::VideoCodecOperationFlagsKHR::DECODE_H265)
        .chroma_subsampling(vk::VideoChromaSubsamplingFlagsKHR::TYPE_420)
        .luma_bit_depth(vk::VideoComponentBitDepthFlagsKHR::TYPE_8)
        .chroma_bit_depth(vk::VideoComponentBitDepthFlagsKHR::TYPE_8)
        .push_next(&mut h265_profile_info);
    let video_queue_loader = ash::khr::video_queue::Instance::new(&probe._entry, &probe.instance);
    let capabilities = native_vulkan_video_session_h265_capabilities(
        &video_queue_loader,
        present_selection.physical_device,
        &profile_info,
    )?;
    let source_extent = vk::Extent2D { width, height };
    if !native_vulkan_video_session_extent_supported(source_extent, &capabilities) {
        return Err(NativeVulkanError::Video(format!(
            "direct H.265 ready-prefix source extent {width}x{height} is outside {:?}..{:?} or not aligned to {:?}",
            (
                capabilities.min_coded_extent.width,
                capabilities.min_coded_extent.height
            ),
            (
                capabilities.max_coded_extent.width,
                capabilities.max_coded_extent.height
            ),
            (
                capabilities.picture_access_granularity.width,
                capabilities.picture_access_granularity.height
            )
        )));
    }
    let format_probe = native_vulkan_video_decode_format_probe(
        &video_queue_loader,
        present_selection.physical_device,
        &profile_info,
        capabilities.decode_capability_flags,
    );
    if !format_probe.nv12_dpb_supported
        || !format_probe.nv12_output_supported
        || !format_probe.nv12_sampled_output_supported
    {
        return Err(NativeVulkanError::Video(format!(
            "direct H.265 ready-prefix video requires NV12 decode+sampled support{}",
            format_probe
                .query_error
                .as_ref()
                .map(|err| format!(": {err}"))
                .unwrap_or_default()
        )));
    }

    let mut device_queue_family_indices = vec![present_queue_family_index];
    if !device_queue_family_indices.contains(&video_queue_family.queue_family_index) {
        device_queue_family_indices.push(video_queue_family.queue_family_index);
    }
    let priorities = [1.0_f32];
    let queue_create_infos = device_queue_family_indices
        .iter()
        .copied()
        .map(|queue_family_index| {
            vk::DeviceQueueCreateInfo::default()
                .queue_family_index(queue_family_index)
                .queue_priorities(&priorities)
        })
        .collect::<Vec<_>>();
    let mut enabled_extensions = vec![ash::khr::swapchain::NAME.as_ptr()];
    enabled_extensions.extend(
        native_vulkan_video_session_required_device_extensions(
            NativeVulkanVideoSessionCodec::H265Main8,
        )
        .iter()
        .map(|extension| extension.as_ptr()),
    );
    let mut synchronization2_features =
        vk::PhysicalDeviceSynchronization2Features::default().synchronization2(true);
    let device_create_info = vk::DeviceCreateInfo::default()
        .queue_create_infos(&queue_create_infos)
        .enabled_extension_names(&enabled_extensions)
        .push_next(&mut synchronization2_features);
    let device = unsafe {
        probe
            .instance
            .create_device(present_selection.physical_device, &device_create_info, None)
    }
    .map_err(|result| NativeVulkanError::Vulkan {
        operation: "vkCreateDevice(direct h265 ready-prefix video)",
        result,
    })?;

    let mut swapchain_loader = None::<ash::khr::swapchain::Device>;
    let mut swapchain = vk::SwapchainKHR::null();
    let mut swapchain_image_views = Vec::<vk::ImageView>::new();
    let mut present_command_pool = vk::CommandPool::null();
    let mut present_command_buffers = Vec::<vk::CommandBuffer>::new();
    let mut video_command_pool = vk::CommandPool::null();
    let mut image_available = vk::Semaphore::null();
    let mut decode_finished = vk::Semaphore::null();
    let mut render_finished = vk::Semaphore::null();
    let mut in_flight = vk::Fence::null();
    let mut renderer = None::<NativeVulkanVideoRenderer>;
    let mut retired_textures = Vec::<NativeVulkanVideoTexture>::new();
    let mut decoded_plane_view_cache = Vec::<NativeVulkanDecodedVideoPlaneViews>::new();
    let mut video_session = vk::VideoSessionKHR::null();
    let mut video_session_parameters = vk::VideoSessionParametersKHR::null();
    let mut session_memories = Vec::<vk::DeviceMemory>::new();
    let mut resource_image = None::<NativeVulkanVideoResourceImage>;
    let mut bitstream_buffer = None::<NativeVulkanVideoBitstreamBuffer>;

    let result =
        (|| -> Result<NativeVulkanDirectH265ReadyPrefixRuntimeSnapshot, NativeVulkanError> {
            let present_queue = unsafe { device.get_device_queue(present_queue_family_index, 0) };
            let video_queue =
                unsafe { device.get_device_queue(video_queue_family.queue_family_index, 0) };
            let video_queue_device = ash::khr::video_queue::Device::new(&probe.instance, &device);
            let video_decode_queue_device =
                ash::khr::video_decode_queue::Device::new(&probe.instance, &device);
            let memory_properties = unsafe {
                probe
                    .instance
                    .get_physical_device_memory_properties(present_selection.physical_device)
            };

            swapchain_loader = Some(ash::khr::swapchain::Device::new(&probe.instance, &device));
            let swapchain_loader_ref = swapchain_loader
                .as_ref()
                .expect("swapchain loader was just created");
            let swapchain_plan = create_native_vulkan_swapchain_plan(
                &probe.surface_loader,
                present_selection.physical_device,
                probe.surface,
                surface_snapshot.wayland_surface_logical_size,
                surface_snapshot.wayland_surface_buffer_size,
            )?;
            swapchain =
                unsafe { swapchain_loader_ref.create_swapchain(&swapchain_plan.create_info, None) }
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkCreateSwapchainKHR(direct h265 ready-prefix video)",
                        result,
                    })?;
            let swapchain_images = unsafe { swapchain_loader_ref.get_swapchain_images(swapchain) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkGetSwapchainImagesKHR(direct h265 ready-prefix video)",
                    result,
                })?;
            swapchain_image_views = create_native_vulkan_swapchain_image_views(
                &device,
                &swapchain_images,
                swapchain_plan.format.format,
            )?;
            let present_command_pool_info = vk::CommandPoolCreateInfo::default()
                .flags(vk::CommandPoolCreateFlags::RESET_COMMAND_BUFFER)
                .queue_family_index(present_queue_family_index);
            present_command_pool =
                unsafe { device.create_command_pool(&present_command_pool_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkCreateCommandPool(direct h265 ready-prefix present)",
                        result,
                    },
                )?;
            let present_command_buffer_info = vk::CommandBufferAllocateInfo::default()
                .command_pool(present_command_pool)
                .level(vk::CommandBufferLevel::PRIMARY)
                .command_buffer_count(swapchain_images.len() as u32);
            present_command_buffers =
                unsafe { device.allocate_command_buffers(&present_command_buffer_info) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateCommandBuffers(direct h265 ready-prefix present)",
                        result,
                    },
                )?;
            let video_command_pool_info = vk::CommandPoolCreateInfo::default()
                .flags(
                    vk::CommandPoolCreateFlags::TRANSIENT
                        | vk::CommandPoolCreateFlags::RESET_COMMAND_BUFFER,
                )
                .queue_family_index(video_queue_family.queue_family_index);
            video_command_pool =
                unsafe { device.create_command_pool(&video_command_pool_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkCreateCommandPool(direct h265 ready-prefix decode)",
                        result,
                    },
                )?;
            let video_command_buffer_info = vk::CommandBufferAllocateInfo::default()
                .command_pool(video_command_pool)
                .level(vk::CommandBufferLevel::PRIMARY)
                .command_buffer_count(1);
            let video_command_buffer =
                unsafe { device.allocate_command_buffers(&video_command_buffer_info) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateCommandBuffers(direct h265 ready-prefix decode)",
                        result,
                    },
                )?[0];
            let semaphore_create_info = vk::SemaphoreCreateInfo::default();
            image_available = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h265 ready-prefix image_available)",
                    result,
                })?;
            decode_finished = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h265 ready-prefix decode_finished)",
                    result,
                })?;
            render_finished = unsafe { device.create_semaphore(&semaphore_create_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateSemaphore(direct h265 ready-prefix render_finished)",
                    result,
                })?;
            let fence_create_info =
                vk::FenceCreateInfo::default().flags(vk::FenceCreateFlags::SIGNALED);
            in_flight =
                unsafe { device.create_fence(&fence_create_info, None) }.map_err(|result| {
                    NativeVulkanError::Vulkan {
                        operation: "vkCreateFence(direct h265 ready-prefix)",
                        result,
                    }
                })?;

            let streaming_bitstream = native_vulkan_h265_streaming_queue_bitstream_plan(
                &streaming_queue,
                width,
                height,
                capabilities.min_bitstream_buffer_offset_alignment,
                capabilities.min_bitstream_buffer_size_alignment,
            )?;
            let session_max_dpb_slots = native_vulkan_h265_session_dpb_slots_for_count(
                capabilities.max_dpb_slots,
                stream_dpb_slots,
            );
            let session_max_active_reference_pictures =
                native_vulkan_video_session_max_active_reference_pictures_for_stream(
                    capabilities.max_active_reference_pictures,
                    session_max_dpb_slots,
                    stream_max_active_reference_pictures,
                );
            let picture_format = vk::Format::G8_B8R8_2PLANE_420_UNORM;
            let create_info = vk::VideoSessionCreateInfoKHR::default()
                .queue_family_index(video_queue_family.queue_family_index)
                .video_profile(&profile_info)
                .picture_format(picture_format)
                .reference_picture_format(picture_format)
                .max_coded_extent(source_extent)
                .max_dpb_slots(session_max_dpb_slots)
                .max_active_reference_pictures(session_max_active_reference_pictures)
                .std_header_version(&capabilities.std_header_version);
            video_session = native_vulkan_create_video_session(&video_queue_device, &create_info)?;

            let memory_requirements = native_vulkan_video_session_memory_requirements(
                &video_queue_device,
                video_session,
            )?;
            let mut bind_infos = Vec::with_capacity(memory_requirements.len());
            let mut session_memory_bytes = 0u64;
            for requirement in memory_requirements.iter() {
                if requirement.memory_requirements.size == 0 {
                    return Err(NativeVulkanError::Video(format!(
                        "direct H.265 ready-prefix session memory bind {} reported zero size",
                        requirement.memory_bind_index
                    )));
                }
                let memory_type_index = native_vulkan_memory_type_index(
                    &memory_properties,
                    requirement.memory_requirements.memory_type_bits,
                    vk::MemoryPropertyFlags::DEVICE_LOCAL,
                )
                .or_else(|| {
                    native_vulkan_memory_type_index(
                        &memory_properties,
                        requirement.memory_requirements.memory_type_bits,
                        vk::MemoryPropertyFlags::empty(),
                    )
                })
                .ok_or(NativeVulkanError::MissingMemoryType(
                    "direct H.265 ready-prefix video session memory",
                ))?;
                let allocation_info = vk::MemoryAllocateInfo::default()
                    .allocation_size(requirement.memory_requirements.size)
                    .memory_type_index(memory_type_index);
                let memory = unsafe { device.allocate_memory(&allocation_info, None) }.map_err(
                    |result| NativeVulkanError::Vulkan {
                        operation: "vkAllocateMemory(direct h265 ready-prefix video session)",
                        result,
                    },
                )?;
                session_memories.push(memory);
                bind_infos.push(
                    vk::BindVideoSessionMemoryInfoKHR::default()
                        .memory_bind_index(requirement.memory_bind_index)
                        .memory(memory)
                        .memory_offset(0)
                        .memory_size(requirement.memory_requirements.size),
                );
                session_memory_bytes =
                    session_memory_bytes.saturating_add(requirement.memory_requirements.size);
            }
            native_vulkan_bind_video_session_memory(
                &video_queue_device,
                video_session,
                &bind_infos,
            )?;

            resource_image = Some(native_vulkan_create_video_session_resource_image(
                &video_queue_loader,
                &device,
                &memory_properties,
                present_selection.physical_device,
                &profile_info,
                source_extent,
                session_max_dpb_slots.max(1),
                picture_format,
                capabilities.decode_capability_flags,
                vk::ImageUsageFlags::empty(),
                &device_queue_family_indices,
                false,
            )?);

            bitstream_buffer = Some(
                native_vulkan_create_video_session_bitstream_buffer_with_mapping(
                    &device,
                    &memory_properties,
                    &profile_info,
                    streaming_bitstream.ring_capacity_bytes,
                    capabilities.min_bitstream_buffer_size_alignment,
                    None,
                    true,
                )?,
            );
            let parameters = native_vulkan_create_h265_video_session_parameters(
                &video_queue_device,
                video_session,
                &parameter_sets,
            )?;
            video_session_parameters = parameters.parameters;
            let image = resource_image
                .as_ref()
                .expect("video resource image was just created");
            let buffer = bitstream_buffer
                .as_ref()
                .expect("bitstream buffer was just created");
            renderer = Some(NativeVulkanVideoRenderer::new(
                &device,
                swapchain_plan.format.format,
                swapchain_plan.extent,
                &swapchain_image_views,
            )?);
            let renderer_ref = renderer.as_mut().expect("video renderer was just created");

            let mut image_layer_layouts =
                vec![vk::ImageLayout::UNDEFINED; image.snapshot.array_layers as usize];
            decoded_plane_view_cache = native_vulkan_create_decoded_video_plane_view_cache(
                &device,
                image.image,
                image.snapshot.array_layers,
            )?;
            let mut active_dpb_pocs = vec![None::<i32>; image.snapshot.array_layers as usize];
            let mut swapchain_image_layouts =
                vec![vk::ImageLayout::UNDEFINED; swapchain_images.len()];
            let fifo_present_paced = swapchain_plan.present_mode == vk::PresentModeKHR::FIFO;
            let pacing_strategy = if fifo_present_paced {
                "fifo-present-blocking-no-cpu-sleep"
            } else if target_max_fps.is_some_and(|fps| fps > 0) {
                "target-fps-cpu-sleep"
            } else {
                "unlimited"
            };
            let frame_interval = if fifo_present_paced {
                None
            } else {
                target_max_fps
                    .filter(|fps| *fps > 0)
                    .map(|fps| Duration::from_secs_f64(1.0 / fps as f64))
            };
            let mut next_frame = Instant::now();
            let started_at = Instant::now();
            let mut previous_pts_ms = None::<u64>;
            let mut previous_duration_ms = None::<u64>;
            let mut frames = Vec::with_capacity(playback_frame_count as usize);
            let mut loop_boundary_reset_count = 0u32;
            let mut frame_sleep_count = 0u32;
            let mut missed_frame_pacing_count = 0u32;
            let mut total_frame_sleep_us = 0u64;
            let mut max_frame_pacing_late_us = 0u64;
            let mut bitstream_ring = NativeVulkanVideoBitstreamRing::new(&streaming_bitstream);
            let mut streaming_reference_planner = NativeVulkanH265DecodeReferencePlanner::new(
                stream_dpb_slots,
                stream_max_pic_order_cnt_lsb,
            );
            let mut previous_source_loop_index = 0u32;

            for playback_frame_index in 0..playback_frame_count {
                probe.host.pump_events()?;
                if probe.host.is_closed() {
                    break;
                }
                let packet = streaming_queue.next_packet(true)?;
                let access_unit = packet.snapshot.clone();
                let entry = streaming_reference_planner.plan_next(&access_unit);
                if !entry.ready_for_decode_submit {
                    return Err(NativeVulkanError::Video(format!(
                        "H.265 streaming AU {} is not decodable; missing POCs {:?}",
                        entry.access_unit_index, entry.missing_reference_pocs
                    )));
                }
                let playback_loop_index = packet.source_loop_index;
                let ready_prefix_frame_index = playback_frame_index;
                let loop_boundary_reset =
                    playback_frame_index > 0 && playback_loop_index != previous_source_loop_index;
                previous_source_loop_index = playback_loop_index;
                let fences = [in_flight];
                let fence_wait_started_at = Instant::now();
                unsafe {
                    device
                        .wait_for_fences(&fences, true, u64::MAX)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkWaitForFences(direct h265 ready-prefix)",
                            result,
                        })?;
                    for texture in retired_textures.drain(..) {
                        texture.destroy(&device);
                    }
                    device
                        .reset_fences(&fences)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkResetFences(direct h265 ready-prefix)",
                            result,
                        })?;
                }
                let fence_wait_elapsed_us =
                    native_vulkan_elapsed_us(fence_wait_started_at.elapsed());
                let pts_delta_ms = if loop_boundary_reset {
                    previous_duration_ms
                        .or(access_unit.duration_ms)
                        .or_else(|| frame_interval.map(|interval| interval.as_millis() as u64))
                } else {
                    access_unit.pts_ms.and_then(|pts_ms| {
                        previous_pts_ms.map(|previous| pts_ms.saturating_sub(previous))
                    })
                };
                let reset_before_decode = playback_frame_index == 0
                    || loop_boundary_reset
                    || access_unit
                        .first_slice
                        .as_ref()
                        .is_some_and(|slice| slice.idr);
                if loop_boundary_reset {
                    loop_boundary_reset_count = loop_boundary_reset_count.saturating_add(1);
                }
                if reset_before_decode {
                    active_dpb_pocs.fill(None);
                }
                let bitstream_upload_started_at = Instant::now();
                let span = native_vulkan_write_h265_streaming_packet_to_bitstream_ring(
                    &packet,
                    &device,
                    buffer,
                    &mut bitstream_ring,
                )?;
                let bitstream_upload_elapsed_us =
                    native_vulkan_elapsed_us(bitstream_upload_started_at.elapsed());
                let mut frame = native_vulkan_decode_h265_ready_prefix_frame_to_image(
                    &device,
                    &video_queue_device,
                    &video_decode_queue_device,
                    video_queue,
                    video_command_buffer,
                    video_session,
                    video_session_parameters,
                    source_extent,
                    image,
                    buffer,
                    buffer.snapshot.size,
                    &parameter_sets,
                    &entry,
                    &access_unit,
                    &span,
                    &active_dpb_pocs,
                    &mut image_layer_layouts,
                    reset_before_decode,
                    pts_delta_ms,
                    decode_finished,
                    playback_frame_index,
                    playback_loop_index,
                    ready_prefix_frame_index,
                    loop_boundary_reset,
                    bitstream_upload_elapsed_us,
                )?;
                frame.fence_wait_elapsed_us = fence_wait_elapsed_us;
                if let Some(slot) = active_dpb_pocs.get_mut(frame.dst_base_array_layer as usize) {
                    *slot = Some(frame.pic_order_cnt_val);
                }

                let present_started_at = Instant::now();
                let decoded_views = decoded_plane_view_cache
                    .get(frame.dst_base_array_layer as usize)
                    .copied()
                    .ok_or_else(|| {
                        NativeVulkanError::Video(format!(
                            "H.265 decoded view cache has {} layers but layer {} was requested",
                            decoded_plane_view_cache.len(),
                            frame.dst_base_array_layer
                        ))
                    })?;
                let texture = NativeVulkanVideoTexture::Decoded(
                    NativeVulkanDecodedVideoTexture::from_cached_views(
                        image.image,
                        width,
                        height,
                        frame.dst_base_array_layer,
                        decoded_views,
                        vk::ImageLayout::VIDEO_DECODE_DPB_KHR,
                        vk::AccessFlags::MEMORY_WRITE,
                    )?,
                );
                let descriptor_update_started_at = Instant::now();
                renderer_ref.update_descriptors(&device, &texture);
                frame.descriptor_update_elapsed_us =
                    native_vulkan_elapsed_us(descriptor_update_started_at.elapsed());
                let acquire_started_at = Instant::now();
                let (image_index, _) = unsafe {
                    swapchain_loader_ref.acquire_next_image(
                        swapchain,
                        u64::MAX,
                        image_available,
                        vk::Fence::null(),
                    )
                }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkAcquireNextImageKHR(direct h265 ready-prefix)",
                    result,
                })?;
                frame.acquire_elapsed_us = native_vulkan_elapsed_us(acquire_started_at.elapsed());
                let image_index = image_index as usize;
                let record_started_at = Instant::now();
                renderer_ref.record_frame(
                    &device,
                    present_command_buffers[image_index],
                    image_index,
                    swapchain_images[image_index],
                    swapchain_image_layouts[image_index],
                    &texture,
                    fit,
                )?;
                frame.record_elapsed_us = native_vulkan_elapsed_us(record_started_at.elapsed());
                swapchain_image_layouts[image_index] = renderer_ref.target_final_layout();
                let wait_semaphores = [image_available, decode_finished];
                let wait_stages = [
                    vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT,
                    vk::PipelineStageFlags::ALL_COMMANDS,
                ];
                let command_buffers_for_submit = [present_command_buffers[image_index]];
                let signal_semaphores = [render_finished];
                let submit_info = vk::SubmitInfo::default()
                    .wait_semaphores(&wait_semaphores)
                    .wait_dst_stage_mask(&wait_stages)
                    .command_buffers(&command_buffers_for_submit)
                    .signal_semaphores(&signal_semaphores);
                let submit_started_at = Instant::now();
                unsafe {
                    device
                        .queue_submit(present_queue, &[submit_info], in_flight)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkQueueSubmit(direct h265 ready-prefix present)",
                            result,
                        })?;
                }
                frame.submit_elapsed_us = native_vulkan_elapsed_us(submit_started_at.elapsed());
                let swapchains = [swapchain];
                let image_indices = [image_index as u32];
                let present_info = vk::PresentInfoKHR::default()
                    .wait_semaphores(&signal_semaphores)
                    .swapchains(&swapchains)
                    .image_indices(&image_indices);
                let queue_present_started_at = Instant::now();
                unsafe {
                    swapchain_loader_ref
                        .queue_present(present_queue, &present_info)
                        .map_err(|result| NativeVulkanError::Vulkan {
                            operation: "vkQueuePresentKHR(direct h265 ready-prefix)",
                            result,
                        })?;
                }
                frame.queue_present_elapsed_us =
                    native_vulkan_elapsed_us(queue_present_started_at.elapsed());
                image_layer_layouts[frame.dst_base_array_layer as usize] =
                    vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL;
                frame.present_elapsed_us = native_vulkan_elapsed_us(present_started_at.elapsed());
                previous_pts_ms = access_unit.pts_ms;
                previous_duration_ms = access_unit.duration_ms;
                retired_textures.push(texture);
                frames.push(frame);

                if let Some(interval) = frame_interval
                    && playback_frame_index + 1 < playback_frame_count
                {
                    next_frame += interval;
                    let now = Instant::now();
                    if next_frame > now {
                        let sleep_duration = next_frame - now;
                        frame_sleep_count = frame_sleep_count.saturating_add(1);
                        total_frame_sleep_us = total_frame_sleep_us
                            .saturating_add(native_vulkan_elapsed_us(sleep_duration));
                        thread::sleep(sleep_duration);
                    } else {
                        missed_frame_pacing_count = missed_frame_pacing_count.saturating_add(1);
                        max_frame_pacing_late_us = max_frame_pacing_late_us
                            .max(native_vulkan_elapsed_us(now.duration_since(next_frame)));
                        next_frame = now;
                    }
                }
            }
            unsafe {
                device
                    .wait_for_fences(&[in_flight], true, u64::MAX)
                    .map_err(|result| NativeVulkanError::Vulkan {
                        operation: "vkWaitForFences(direct h265 ready-prefix final)",
                        result,
                    })?;
            }
            for texture in retired_textures.drain(..) {
                texture.destroy(&device);
            }

            let elapsed = started_at.elapsed();
            let presented_frame_count = frames.len() as u32;
            Ok(NativeVulkanDirectH265ReadyPrefixRuntimeSnapshot {
                runtime_elapsed_ms: elapsed.as_millis().min(u64::MAX as u128) as u64,
                requested_frame_count: playback_frame_count,
                ready_prefix_frame_count,
                requested_playback_frame_count: playback_frame_count,
                decoded_frame_count: frames.len() as u32,
                presented_frame_count,
                playback_loop_count: if frames.is_empty() {
                    0
                } else {
                    frames
                        .last()
                        .map(|frame| frame.playback_loop_index.saturating_add(1))
                        .unwrap_or(0)
                },
                loop_boundary_reset_count,
                frame_sleep_count,
                missed_frame_pacing_count,
                total_frame_sleep_us,
                max_frame_pacing_late_us,
                average_present_fps: if elapsed.is_zero() {
                    0.0
                } else {
                    f64::from(presented_frame_count) / elapsed.as_secs_f64()
                },
                configured: probe.host.snapshot().configured,
                source,
                source_extent: (width, height),
                fit,
                target_max_fps,
                wayland_surface_logical_size: surface_snapshot.wayland_surface_logical_size,
                wayland_surface_buffer_size: surface_snapshot.wayland_surface_buffer_size,
                selected_physical_device_name: present_selection.physical_device_name,
                selected_physical_device_type: present_selection.physical_device_type,
                present_queue_family_index,
                present_queue_flags: native_vulkan_queue_flag_labels(present_queue_flags),
                video_decode_queue_family_index: video_queue_family.queue_family_index,
                video_decode_queue_flags: native_vulkan_queue_flag_labels(
                    video_queue_family.queue_flags,
                ),
                video_decode_queue_codec_operations: native_vulkan_video_codec_operation_labels(
                    video_queue_family.video_codec_operations,
                ),
                cross_queue_sync_strategy: "per-frame-binary-semaphore-decode-signal-present-wait",
                driver_max_dpb_slots: capabilities.max_dpb_slots,
                stream_sps_dpb_slots,
                stream_dpb_slots,
                stream_max_active_reference_pictures,
                session_max_dpb_slots,
                session_max_active_reference_pictures,
                swapchain_extent: (swapchain_plan.extent.width, swapchain_plan.extent.height),
                swapchain_image_count: swapchain_images.len(),
                swapchain_format: native_vulkan_format_label(swapchain_plan.format.format)
                    .to_owned(),
                present_mode: native_vulkan_present_mode_label(swapchain_plan.present_mode),
                pacing_strategy,
                video_resource_memory_bytes: image.snapshot.memory_size,
                session_memory_bytes,
                bitstream_buffer_bytes: buffer.snapshot.size,
                bitstream_buffer_strategy: "fixed-capacity-persistent-mapped-ring",
                bitstream_buffer_slot_count: streaming_bitstream.ring_slot_count,
                bitstream_buffer_slot_bytes: streaming_bitstream.slot_bytes,
                bitstream_ring_capacity_bytes: streaming_bitstream.ring_capacity_bytes,
                bitstream_ring_min_offset_alignment: streaming_bitstream.min_offset_alignment,
                bitstream_ring_min_size_alignment: streaming_bitstream.min_size_alignment,
                bitstream_ring_wrap_count: bitstream_ring.wrap_count(),
                bitstream_window_payload_bytes: streaming_bitstream.window_payload_bytes,
                bitstream_upload_count: frames.len() as u32,
                bitstream_uploaded_bytes: frames.iter().map(|frame| frame.src_buffer_range).sum(),
                h265_input_mode: input_mode.as_str(),
                h265_packet_queue_capacity: streaming_queue.capacity.min(u32::MAX as usize) as u32,
                h265_packet_queue_pulled_count: streaming_queue.pulled_count,
                h265_packet_queue_eos_count: streaming_queue.eos_count,
                h265_packet_queue_loop_count: streaming_queue.loop_count,
                h265_packet_queue_loop_skip_access_units: streaming_queue.loop_skip_access_units,
                h265_packet_queue_bootstrap_discarded_access_units: streaming_queue
                    .bootstrap_discarded_access_units,
                h265_packet_queue_max_payload_bytes: streaming_queue.max_payload_bytes,
                h265_packet_queue_retained_payload_bytes: streaming_queue.retained_payload_bytes(),
                pts_delta_min_ms: frames.iter().filter_map(|frame| frame.pts_delta_ms).min(),
                pts_delta_max_ms: frames.iter().filter_map(|frame| frame.pts_delta_ms).max(),
                frames,
                last_render_error: None,
            })
        })();

    unsafe {
        let _ = device.device_wait_idle();
        for texture in retired_textures.drain(..) {
            texture.destroy(&device);
        }
        if let Some(renderer) = renderer.take() {
            renderer.destroy(&device);
        }
        native_vulkan_destroy_decoded_video_plane_view_cache(
            &device,
            std::mem::take(&mut decoded_plane_view_cache),
        );
        if image_available != vk::Semaphore::null() {
            device.destroy_semaphore(image_available, None);
        }
        if decode_finished != vk::Semaphore::null() {
            device.destroy_semaphore(decode_finished, None);
        }
        if render_finished != vk::Semaphore::null() {
            device.destroy_semaphore(render_finished, None);
        }
        if in_flight != vk::Fence::null() {
            device.destroy_fence(in_flight, None);
        }
        if video_command_pool != vk::CommandPool::null() {
            device.destroy_command_pool(video_command_pool, None);
        }
        if present_command_pool != vk::CommandPool::null() {
            device.destroy_command_pool(present_command_pool, None);
        }
        if let Some(buffer) = bitstream_buffer.take() {
            native_vulkan_destroy_video_session_bitstream_buffer(&device, buffer);
        }
        let video_queue_device = ash::khr::video_queue::Device::new(&probe.instance, &device);
        if video_session_parameters != vk::VideoSessionParametersKHR::null() {
            (video_queue_device.fp().destroy_video_session_parameters_khr)(
                video_queue_device.device(),
                video_session_parameters,
                ptr::null(),
            );
        }
        if let Some(image) = resource_image.take() {
            native_vulkan_destroy_video_session_resource_image(&device, image);
        }
        if video_session != vk::VideoSessionKHR::null() {
            (video_queue_device.fp().destroy_video_session_khr)(
                video_queue_device.device(),
                video_session,
                ptr::null(),
            );
        }
        for memory in session_memories {
            device.free_memory(memory, None);
        }
        for view in swapchain_image_views {
            device.destroy_image_view(view, None);
        }
        if swapchain != vk::SwapchainKHR::null()
            && let Some(loader) = swapchain_loader.as_ref()
        {
            loader.destroy_swapchain(swapchain, None);
        }
        device.destroy_device(None);
    }

    result
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanGstVideoFrontend {
    pipeline: gst::Element,
    sink: gst::Element,
    bus: gst::Bus,
    loop_playback: bool,
    decoder_policy: VideoDecoderPolicy,
    eos_messages: u64,
    segment_done_messages: u64,
    frames_received: u64,
    last_sample_caps: Option<String>,
    last_sample_format: Option<String>,
    last_sample_size: Option<(u32, u32)>,
    last_sample_pts_ms: Option<u64>,
    last_sample_duration_ms: Option<u64>,
    last_sample_pts_delta_ms: Option<u64>,
    last_sample_memory_types: Vec<String>,
    latest_sample: Option<gst::Sample>,
    last_error: Option<String>,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanGstVideoFrontend {
    fn new(item: &NativeVulkanRenderItem) -> Result<Self, NativeVulkanError> {
        let NativeVulkanRenderItem::Video {
            source,
            loop_playback,
            decoder_policy,
            start_offset_ms,
            ..
        } = item
        else {
            return Err(NativeVulkanError::Video(
                "GStreamer frontend requires a video render item".to_owned(),
            ));
        };

        gst::init().map_err(|err| NativeVulkanError::Video(err.to_string()))?;
        apply_decoder_rank_policy(*decoder_policy);
        native_vulkan_apply_memory_path_decoder_policy();
        let pipeline = native_vulkan_gst_video_pipeline(source)?;
        let sink = pipeline
            .by_name("gilder-native-vulkan-video-appsink")
            .ok_or_else(|| NativeVulkanError::Video("video appsink not found".to_owned()))?;
        let bus = pipeline
            .bus()
            .ok_or_else(|| NativeVulkanError::Video("video pipeline has no bus".to_owned()))?;
        pipeline
            .set_state(gst::State::Paused)
            .map_err(|err| NativeVulkanError::Video(err.to_string()))?;
        let _ = pipeline.state(gst::ClockTime::from_seconds(5));
        if *loop_playback {
            native_vulkan_gst_seek_loop_segment(pipeline.upcast_ref(), *start_offset_ms)?;
        } else if *start_offset_ms > 0 {
            native_vulkan_gst_seek_once(pipeline.upcast_ref(), *start_offset_ms)?;
        }
        pipeline
            .set_state(gst::State::Playing)
            .map_err(|err| NativeVulkanError::Video(err.to_string()))?;

        Ok(Self {
            pipeline: pipeline.upcast::<gst::Element>(),
            sink,
            bus,
            loop_playback: *loop_playback,
            decoder_policy: *decoder_policy,
            eos_messages: 0,
            segment_done_messages: 0,
            frames_received: 0,
            last_sample_caps: None,
            last_sample_format: None,
            last_sample_size: None,
            last_sample_pts_ms: None,
            last_sample_duration_ms: None,
            last_sample_pts_delta_ms: None,
            last_sample_memory_types: Vec::new(),
            latest_sample: None,
            last_error: None,
        })
    }

    fn poll(&mut self) -> Result<(), NativeVulkanError> {
        self.poll_bus()?;
        self.pull_available_samples();
        Ok(())
    }

    fn poll_bus(&mut self) -> Result<(), NativeVulkanError> {
        while let Some(message) = self.bus.pop() {
            match message.view() {
                gst::MessageView::Eos(_) => {
                    self.eos_messages = self.eos_messages.saturating_add(1);
                    if self.loop_playback {
                        native_vulkan_gst_seek_loop_segment(&self.pipeline, 0)?;
                    } else {
                        self.pipeline
                            .set_state(gst::State::Paused)
                            .map_err(|err| NativeVulkanError::Video(err.to_string()))?;
                    }
                }
                gst::MessageView::SegmentDone(_) => {
                    self.segment_done_messages = self.segment_done_messages.saturating_add(1);
                    if self.loop_playback {
                        native_vulkan_gst_seek_loop_segment(&self.pipeline, 0)?;
                    }
                }
                gst::MessageView::Error(err) => {
                    let mut message = format!(
                        "{}: {}",
                        err.src()
                            .map(|src| src.path_string())
                            .unwrap_or_else(|| "gstreamer".into()),
                        err.error()
                    );
                    if let Some(debug) = err.debug() {
                        message.push_str(": ");
                        message.push_str(&debug);
                    }
                    self.last_error = Some(message.clone());
                    return Err(NativeVulkanError::Video(message));
                }
                _ => {}
            }
        }
        Ok(())
    }

    fn pull_available_samples(&mut self) {
        let sample = self
            .sink
            .emit_by_name::<Option<gst::Sample>>("try-pull-sample", &[&0u64]);
        let Some(sample) = sample else {
            return;
        };
        self.record_sample(&sample);
        self.latest_sample = Some(sample);
    }

    fn record_sample(&mut self, sample: &gst::Sample) {
        self.frames_received = self.frames_received.saturating_add(1);
        self.last_sample_caps = sample.caps().map(|caps| caps.to_string());
        if let Some(caps) = sample.caps()
            && let Some(structure) = caps.structure(0)
        {
            self.last_sample_format = structure.get::<String>("format").ok();
            let width = structure.get::<i32>("width").ok();
            let height = structure.get::<i32>("height").ok();
            self.last_sample_size = width.zip(height).and_then(|(width, height)| {
                Some((u32::try_from(width).ok()?, u32::try_from(height).ok()?))
            });
        }
        self.last_sample_memory_types = sample
            .buffer()
            .map(|buffer| {
                let pts_ms = native_vulkan_clock_time_ms(buffer.pts());
                self.last_sample_pts_delta_ms = self
                    .last_sample_pts_ms
                    .zip(pts_ms)
                    .and_then(|(previous, current)| current.checked_sub(previous));
                self.last_sample_pts_ms = pts_ms;
                self.last_sample_duration_ms = native_vulkan_clock_time_ms(buffer.duration());
                native_vulkan_gst_memory_types(buffer)
            })
            .unwrap_or_else(|| {
                self.last_sample_pts_ms = None;
                self.last_sample_duration_ms = None;
                self.last_sample_pts_delta_ms = None;
                Vec::new()
            });
        self.last_error = None;
    }

    fn take_latest_sample(&mut self) -> Option<gst::Sample> {
        self.latest_sample.take()
    }

    fn snapshot(&self) -> NativeVulkanGstVideoFrontendSnapshot {
        let gst_state = Some(
            self.pipeline
                .state(gst::ClockTime::ZERO)
                .1
                .name()
                .to_string(),
        );
        let decoder_reports = actual_decoder_reports(&self.pipeline);
        let actual_decoders = decoder_reports
            .iter()
            .map(|report| report.element.clone())
            .collect::<Vec<_>>();
        let decoder_policy_status = Some(format!(
            "{:?}",
            decoder_policy_status(self.decoder_policy, &decoder_reports)
        ));
        let caps_reports = video_caps_reports(&self.pipeline);
        let mut caps_memory_features = caps_reports
            .iter()
            .flat_map(|report| report.memory_features.iter().cloned())
            .collect::<Vec<_>>();
        caps_memory_features.sort();
        caps_memory_features.dedup();
        let caps_report_count = caps_reports.len();
        let caps_reports = caps_reports
            .into_iter()
            .map(|report| NativeVulkanVideoCapsSnapshot {
                element: report.element,
                pad: report.pad,
                direction: report.direction,
                caps: report.caps,
                source: report.source,
                memory_features: report.memory_features,
            })
            .collect();

        NativeVulkanGstVideoFrontendSnapshot {
            gst_state,
            eos_messages: self.eos_messages,
            segment_done_messages: self.segment_done_messages,
            frames_received: self.frames_received,
            last_sample_caps: self.last_sample_caps.clone(),
            last_sample_format: self.last_sample_format.clone(),
            last_sample_size: self.last_sample_size,
            last_sample_pts_ms: self.last_sample_pts_ms,
            last_sample_duration_ms: self.last_sample_duration_ms,
            last_sample_pts_delta_ms: self.last_sample_pts_delta_ms,
            last_sample_memory_types: self.last_sample_memory_types.clone(),
            actual_decoders,
            decoder_policy_status,
            caps_report_count,
            caps_memory_features,
            caps_reports,
            last_error: self.last_error.clone(),
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
impl Drop for NativeVulkanGstVideoFrontend {
    fn drop(&mut self) {
        let _ = self.pipeline.set_state(gst::State::Null);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_video_pipeline(source: &PathBuf) -> Result<gst::Pipeline, NativeVulkanError> {
    let pipeline = gst::Pipeline::new();
    let filesrc = native_vulkan_gst_element("filesrc")?;
    filesrc.set_property("location", source.to_string_lossy().as_ref());
    let decodebin = native_vulkan_gst_element("decodebin")?;
    if let Ok(decodebin_bin) = decodebin.clone().dynamic_cast::<gst::Bin>() {
        decodebin_bin.connect_element_added(|_, element| {
            native_vulkan_configure_decoder_low_memory(element);
        });
    }
    let queue = native_vulkan_gst_element("queue")?;
    native_vulkan_configure_queue(&queue);
    let sink = native_vulkan_gst_element("appsink")?;
    sink.set_property("name", "gilder-native-vulkan-video-appsink");
    native_vulkan_configure_appsink(&sink);

    pipeline
        .add_many([&filesrc, &decodebin, &queue, &sink])
        .map_err(|err| NativeVulkanError::Video(err.to_string()))?;
    filesrc
        .link(&decodebin)
        .map_err(|err| NativeVulkanError::Video(err.to_string()))?;
    queue
        .link(&sink)
        .map_err(|err| NativeVulkanError::Video(err.to_string()))?;

    let queue_sink = queue
        .static_pad("sink")
        .ok_or_else(|| NativeVulkanError::Video("queue has no sink pad".to_owned()))?;
    decodebin.connect_pad_added(move |_, pad| {
        if queue_sink.is_linked() {
            return;
        }
        let caps = pad.current_caps().unwrap_or_else(|| pad.query_caps(None));
        let is_video = caps
            .structure(0)
            .map(|structure| structure.name().starts_with("video/"))
            .unwrap_or(false);
        if is_video {
            let _ = pad.link(&queue_sink);
        }
    });

    Ok(pipeline)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_element(name: &str) -> Result<gst::Element, NativeVulkanError> {
    gst::ElementFactory::make(name)
        .build()
        .map_err(|err| NativeVulkanError::Video(format!("create {name}: {err}")))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_seek_once(
    pipeline: &gst::Element,
    start_offset_ms: u64,
) -> Result<(), NativeVulkanError> {
    pipeline
        .seek_simple(
            gst::SeekFlags::FLUSH | gst::SeekFlags::KEY_UNIT,
            gst::ClockTime::from_mseconds(start_offset_ms),
        )
        .map_err(|err| NativeVulkanError::Video(err.to_string()))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_seek_loop_segment(
    pipeline: &gst::Element,
    start_offset_ms: u64,
) -> Result<(), NativeVulkanError> {
    pipeline
        .seek(
            1.0,
            gst::SeekFlags::FLUSH | gst::SeekFlags::SEGMENT | gst::SeekFlags::KEY_UNIT,
            gst::SeekType::Set,
            gst::ClockTime::from_mseconds(start_offset_ms),
            gst::SeekType::None,
            gst::ClockTime::NONE,
        )
        .map_err(|err| NativeVulkanError::Video(err.to_string()))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_configure_decoder_low_memory(decoder: &gst::Element) {
    if decoder.find_property("qos").is_some() {
        decoder.set_property("qos", false);
    }
    if decoder.find_property("max-display-delay").is_some() {
        decoder.set_property("max-display-delay", 0i32);
    }
    if decoder.find_property("num-output-surfaces").is_some() {
        decoder.set_property(
            "num-output-surfaces",
            native_vulkan_gst_nvdec_output_surfaces(),
        );
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_configure_queue(queue: &gst::Element) {
    if queue.find_property("max-size-buffers").is_some() {
        queue.set_property("max-size-buffers", native_vulkan_gst_video_queue_frames());
    }
    if queue.find_property("max-size-bytes").is_some() {
        queue.set_property("max-size-bytes", 0u32);
    }
    if queue.find_property("max-size-time").is_some() {
        queue.set_property("max-size-time", 0u64);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_nvdec_output_surfaces() -> u32 {
    std::env::var("GILDER_VULKAN_GST_NVDEC_OUTPUT_SURFACES")
        .ok()
        .and_then(|value| value.parse::<u32>().ok())
        .map(|value| value.clamp(1, 64))
        .unwrap_or(1)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_configure_appsink(sink: &gst::Element) {
    if let Some(caps) = native_vulkan_gst_forced_sink_caps() {
        sink.set_property("caps", &caps);
    }
    if sink.find_property("sync").is_some() {
        sink.set_property("sync", true);
    }
    if sink.find_property("async").is_some() {
        sink.set_property("async", false);
    }
    if sink.find_property("emit-signals").is_some() {
        sink.set_property("emit-signals", false);
    }
    if sink.find_property("enable-last-sample").is_some() {
        sink.set_property("enable-last-sample", false);
    }
    if sink.find_property("wait-on-eos").is_some() {
        sink.set_property("wait-on-eos", false);
    }
    if sink.find_property("max-buffers").is_some() {
        sink.set_property("max-buffers", native_vulkan_gst_video_queue_frames());
    }
    if sink.find_property("drop").is_some() {
        sink.set_property("drop", false);
    }
    if sink.find_property("qos").is_some() {
        sink.set_property("qos", false);
    }
    if sink.find_property("max-lateness").is_some() {
        sink.set_property("max-lateness", -1i64);
    }
    if sink.find_property("processing-deadline").is_some() {
        sink.set_property("processing-deadline", 0u64);
    }
    if sink.find_property("render-delay").is_some() {
        sink.set_property("render-delay", 0u64);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_video_queue_frames() -> u32 {
    1
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_forced_sink_caps() -> Option<gst::Caps> {
    if !native_vulkan_gst_prefers_dmabuf() {
        return None;
    }
    Some(
        gst::Caps::builder_full()
            .structure_with_features(
                gst::Structure::builder("video/x-raw")
                    .field("format", "NV12")
                    .build(),
                gst::CapsFeatures::new(["memory:VAMemory"]),
            )
            .structure_with_features(
                gst::Structure::builder("video/x-raw")
                    .field("format", "P010_10LE")
                    .build(),
                gst::CapsFeatures::new(["memory:VAMemory"]),
            )
            .structure_with_features(
                gst::Structure::builder("video/x-raw")
                    .field("format", "DMA_DRM")
                    .build(),
                gst::CapsFeatures::new(["memory:DMABuf"]),
            )
            .build(),
    )
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_apply_memory_path_decoder_policy() {
    if !native_vulkan_gst_prefers_dmabuf() {
        return;
    }
    for element in [
        "vah264dec",
        "vah265dec",
        "vavp8dec",
        "vavp9dec",
        "vaav1dec",
        "nvh264dec",
        "nvh265dec",
        "nvvp8dec",
        "nvvp9dec",
        "nvav1dec",
        "avdec_h264",
        "openh264dec",
        "vp9dec",
        "avdec_vp9",
        "dav1ddec",
        "avdec_av1",
        "av1dec",
    ] {
        let Some(factory) = gst::ElementFactory::find(element) else {
            continue;
        };
        if element.starts_with("va") {
            factory.set_rank(gst::Rank::PRIMARY + 2048);
        } else {
            factory.set_rank(gst::Rank::NONE);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_prefers_dmabuf() -> bool {
    std::env::var("GILDER_VULKAN_GST_MEMORY_PATH")
        .map(|memory_path| {
            matches!(
                memory_path.as_str(),
                "dmabuf" | "DMABuf" | "gst-dmabuf" | "direct-dmabuf"
            )
        })
        .unwrap_or(false)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_trim_process_heap() {
    #[cfg(target_os = "linux")]
    unsafe {
        libc::malloc_trim(0);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_clock_time_ms(value: Option<gst::ClockTime>) -> Option<u64> {
    value.map(|value| value.mseconds())
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_elapsed_us(value: Duration) -> u64 {
    value.as_micros().min(u128::from(u64::MAX)) as u64
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_memory_types(buffer: &gst::BufferRef) -> Vec<String> {
    (0..buffer.n_memory())
        .map(|index| native_vulkan_gst_memory_type(buffer.peek_memory(index)))
        .collect()
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_memory_type(memory: &gst::MemoryRef) -> String {
    for memory_type in [
        "CUDAMemory",
        "GLMemory",
        "DMABuf",
        "VAMemory",
        "SystemMemory",
    ] {
        if memory.is_type(memory_type) {
            return memory_type.to_owned();
        }
    }
    let Some(memory_type) = memory
        .allocator()
        .map(|allocator| allocator.memory_type().to_string())
    else {
        return "unknown".to_owned();
    };
    let lower = memory_type.to_ascii_lowercase();
    if lower.contains("cuda") {
        "CUDAMemory".to_owned()
    } else if lower.contains("gl") {
        "GLMemory".to_owned()
    } else if lower.contains("dmabuf") || lower.contains("dma-buf") {
        "DMABuf".to_owned()
    } else if lower.contains("va") {
        "VAMemory".to_owned()
    } else if lower.contains("system") {
        "SystemMemory".to_owned()
    } else {
        memory_type
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_dmabuf_frame(
    sample: &gst::Sample,
    buffer: &gst::BufferRef,
    meta: &NativeVulkanGstSystemNv12Meta,
) -> Result<NativeVulkanDmabufVideoFrame, NativeVulkanError> {
    let (fourcc, modifier) = native_vulkan_gst_sample_drm_format(sample)?;
    if fourcc != meta.format.drm_format() {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan DMABuf importer expected {} fourcc=0x{:08x}, got fourcc=0x{fourcc:08x}",
            meta.format.label(),
            meta.format.drm_format()
        )));
    }
    let y = native_vulkan_gst_dmabuf_plane(buffer, meta.y)?;
    let uv = native_vulkan_gst_dmabuf_plane(buffer, meta.uv)?;
    if y.fd != uv.fd {
        return Err(NativeVulkanError::Video(
            "native Vulkan DMABuf importer currently requires y/uv planes in one fd".to_owned(),
        ));
    }
    Ok(NativeVulkanDmabufVideoFrame {
        format: meta.format,
        width: meta.width,
        height: meta.height,
        fd: y.fd,
        modifier,
        y,
        uv,
        _owned_fds: Vec::new(),
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_sample_drm_format(
    sample: &gst::Sample,
) -> Result<(u32, u64), NativeVulkanError> {
    let caps = sample
        .caps()
        .ok_or_else(|| NativeVulkanError::Video("DMABuf sample has no caps".to_owned()))?;
    let structure = caps.structure(0).ok_or_else(|| {
        NativeVulkanError::Video("DMABuf sample caps has no structure".to_owned())
    })?;
    if let Ok(drm_format) = structure.get::<String>("drm-format") {
        let (fourcc, modifier) = native_vulkan_drm_fourcc_modifier_from_caps_format(&drm_format)
            .ok_or_else(|| {
                NativeVulkanError::Video(format!(
                    "native Vulkan DMABuf could not parse drm-format={drm_format}"
                ))
            })?;
        let modifier = modifier.ok_or_else(|| {
            NativeVulkanError::Video(format!(
                "native Vulkan DMABuf drm-format={drm_format} has no explicit modifier"
            ))
        })?;
        return Ok((fourcc, modifier));
    }

    let format = structure
        .get::<String>("format")
        .unwrap_or_else(|_| "unknown".to_owned());
    if let Some(format) = NativeVulkanVideoSampleFormat::from_caps_format(&format) {
        return Ok((format.drm_format(), DRM_FORMAT_MOD_LINEAR));
    }
    Err(NativeVulkanError::Video(format!(
        "native Vulkan DMABuf expected drm-format or NV12 caps, got format={format}"
    )))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_drm_fourcc_modifier_from_caps_format(format: &str) -> Option<(u32, Option<u64>)> {
    let format = CString::new(format).ok()?;
    let mut modifier = 0u64;
    let fourcc = unsafe { gst_video_dma_drm_fourcc_from_string(format.as_ptr(), &mut modifier) };
    (fourcc != 0).then_some((
        fourcc,
        (modifier != DRM_FORMAT_MOD_INVALID).then_some(modifier),
    ))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_dmabuf_plane(
    buffer: &gst::BufferRef,
    plane: NativeVulkanGstSystemNv12Plane,
) -> Result<NativeVulkanDmabufVideoPlane, NativeVulkanError> {
    let plane_end = plane.offset.checked_add(1).ok_or_else(|| {
        NativeVulkanError::Video("native Vulkan DMABuf plane offset overflow".to_owned())
    })?;
    let (memory_range, memory_skip) = buffer
        .find_memory(plane.offset..plane_end)
        .ok_or_else(|| NativeVulkanError::Video("DMABuf plane has no memory".to_owned()))?;
    let memory_index = memory_range.start;
    if memory_index >= buffer.n_memory() {
        return Err(NativeVulkanError::Video(
            "native Vulkan DMABuf memory index out of range".to_owned(),
        ));
    }
    let memory = buffer.peek_memory(memory_index);
    let fd = native_vulkan_dmabuf_memory_fd(memory).ok_or_else(|| {
        NativeVulkanError::Video(format!(
            "native Vulkan DMABuf plane memory is not GstDmaBufMemory: {}",
            native_vulkan_gst_memory_type(memory)
        ))
    })?;
    let (_, memory_offset, _) = memory.sizes();
    let offset = memory_offset
        .checked_add(memory_skip)
        .and_then(|offset| u64::try_from(offset).ok())
        .ok_or_else(|| {
            NativeVulkanError::Video("native Vulkan DMABuf plane offset too large".to_owned())
        })?;
    Ok(NativeVulkanDmabufVideoPlane {
        fd,
        offset,
        stride: plane.stride,
        height: plane.height,
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_buffer_has_dmabuf_memory(buffer: &gst::BufferRef) -> bool {
    (0..buffer.n_memory()).any(|index| native_vulkan_is_dmabuf_memory(buffer.peek_memory(index)))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_is_dmabuf_memory(memory: &gst::MemoryRef) -> bool {
    let is_dmabuf =
        unsafe { gst_is_dmabuf_memory(memory.as_ptr().cast_mut()) } != gst::glib::ffi::GFALSE;
    is_dmabuf || memory.is_type("DMABuf")
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_memory_fd(memory: &gst::MemoryRef) -> Option<i32> {
    if !native_vulkan_is_dmabuf_memory(memory) {
        return None;
    }
    let fd = unsafe { gst_dmabuf_memory_get_fd(memory.as_ptr().cast_mut()) };
    (fd >= 0).then_some(fd)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_buffer_has_va_memory(buffer: &gst::BufferRef) -> bool {
    (0..buffer.n_memory()).any(|index| native_vulkan_is_va_memory(buffer.peek_memory(index)))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_is_va_memory(memory: &gst::MemoryRef) -> bool {
    #[cfg(feature = "native-vulkan-gst-va")]
    {
        memory.is_type("VAMemory") || native_vulkan_gst_memory_type(memory) == "VAMemory"
    }
    #[cfg(not(feature = "native-vulkan-gst-va"))]
    {
        let _ = memory;
        false
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_va_dmabuf_frame(
    buffer: &gst::BufferRef,
    meta: &NativeVulkanGstSystemNv12Meta,
) -> Result<NativeVulkanDmabufVideoFrame, NativeVulkanError> {
    let va_surface = native_vulkan_gst_va_surface(buffer)?;
    native_vulkan_va_check(
        unsafe { vaSyncSurface(va_surface.display, va_surface.surface) },
        "vaSyncSurface(video VAMemory)",
    )?;
    let exported = native_vulkan_va_export_prime_surface(va_surface)?;
    native_vulkan_va_prime_surface_to_dmabuf_frame(exported, meta)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_va_surface(
    buffer: &gst::BufferRef,
) -> Result<NativeVulkanVaSurface, NativeVulkanError> {
    let display = unsafe { gst_va_buffer_peek_display(buffer.as_mut_ptr()) };
    let surface = unsafe { gst_va_buffer_get_surface(buffer.as_mut_ptr()) };
    if !display.is_null() && surface != VA_INVALID_SURFACE {
        let va_display = unsafe { gst_va_display_get_va_dpy(display) };
        if !va_display.is_null() {
            return Ok(NativeVulkanVaSurface {
                display: va_display,
                surface,
            });
        }
    }

    for index in 0..buffer.n_memory() {
        let memory = buffer.peek_memory(index);
        if !native_vulkan_is_va_memory(memory) {
            continue;
        }
        let display = unsafe { gst_va_memory_peek_display(memory.as_ptr().cast_mut()) };
        let surface = unsafe { gst_va_memory_get_surface(memory.as_ptr().cast_mut()) };
        if display.is_null() || surface == VA_INVALID_SURFACE {
            continue;
        }
        let va_display = unsafe { gst_va_display_get_va_dpy(display) };
        if !va_display.is_null() {
            return Ok(NativeVulkanVaSurface {
                display: va_display,
                surface,
            });
        }
    }

    Err(NativeVulkanError::Video(
        "native Vulkan VAMemory importer could not find a VA display/surface".to_owned(),
    ))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_va_export_prime_surface(
    surface: NativeVulkanVaSurface,
) -> Result<NativeVulkanVaExportedPrimeSurface, NativeVulkanError> {
    let separate_flags = VA_EXPORT_SURFACE_READ_ONLY | VA_EXPORT_SURFACE_SEPARATE_LAYERS;
    match native_vulkan_va_export_prime_surface_with_flags(surface, separate_flags) {
        Ok(exported) => Ok(exported),
        Err(separate_err) => {
            let composed_flags = VA_EXPORT_SURFACE_READ_ONLY | VA_EXPORT_SURFACE_COMPOSED_LAYERS;
            native_vulkan_va_export_prime_surface_with_flags(surface, composed_flags).map_err(
                |composed_err| {
                    NativeVulkanError::Video(format!(
                        "{separate_err}; composed VA DRM PRIME export also failed: {composed_err}"
                    ))
                },
            )
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_va_export_prime_surface_with_flags(
    surface: NativeVulkanVaSurface,
    flags: u32,
) -> Result<NativeVulkanVaExportedPrimeSurface, NativeVulkanError> {
    let mut descriptor = NativeVulkanVaDrmPrimeSurfaceDescriptor::default();
    native_vulkan_va_check(
        unsafe {
            vaExportSurfaceHandle(
                surface.display,
                surface.surface,
                VA_SURFACE_ATTRIB_MEM_TYPE_DRM_PRIME_2,
                flags,
                (&mut descriptor as *mut NativeVulkanVaDrmPrimeSurfaceDescriptor).cast(),
            )
        },
        "vaExportSurfaceHandle(video VAMemory DRM PRIME)",
    )?;
    NativeVulkanVaExportedPrimeSurface::new(descriptor)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_va_prime_surface_to_dmabuf_frame(
    exported: NativeVulkanVaExportedPrimeSurface,
    meta: &NativeVulkanGstSystemNv12Meta,
) -> Result<NativeVulkanDmabufVideoFrame, NativeVulkanError> {
    let descriptor = exported.descriptor;
    native_vulkan_validate_va_prime_descriptor(&descriptor, meta)?;
    let (y_object, y_offset, y_pitch, uv_object, uv_offset, uv_pitch) =
        native_vulkan_va_yuv420_plane_layouts(&descriptor, meta.format)?;
    if y_object != uv_object {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan VA DMABuf importer currently requires a single DRM object, got y_object={y_object} uv_object={uv_object}"
        )));
    }
    let object = descriptor.objects.get(y_object).ok_or_else(|| {
        NativeVulkanError::Video("VA DRM PRIME object index out of range".to_owned())
    })?;
    if object.drm_format_modifier == DRM_FORMAT_MOD_INVALID {
        return Err(NativeVulkanError::Video(
            "VA DRM PRIME export returned an invalid DRM modifier".to_owned(),
        ));
    }

    Ok(NativeVulkanDmabufVideoFrame {
        format: meta.format,
        width: meta.width,
        height: meta.height,
        fd: exported
            .owned_fds
            .get(y_object)
            .ok_or_else(|| {
                NativeVulkanError::Video("VA DRM PRIME fd index out of range".to_owned())
            })?
            .as_raw_fd(),
        modifier: object.drm_format_modifier,
        y: NativeVulkanDmabufVideoPlane {
            fd: exported
                .owned_fds
                .get(y_object)
                .expect("VA DRM PRIME fd checked above")
                .as_raw_fd(),
            offset: u64::from(y_offset),
            stride: y_pitch,
            height: meta.height,
        },
        uv: NativeVulkanDmabufVideoPlane {
            fd: exported
                .owned_fds
                .get(uv_object)
                .ok_or_else(|| {
                    NativeVulkanError::Video("VA DRM PRIME uv fd index out of range".to_owned())
                })?
                .as_raw_fd(),
            offset: u64::from(uv_offset),
            stride: uv_pitch,
            height: meta.height / 2,
        },
        _owned_fds: exported.owned_fds,
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_validate_va_prime_descriptor(
    descriptor: &NativeVulkanVaDrmPrimeSurfaceDescriptor,
    meta: &NativeVulkanGstSystemNv12Meta,
) -> Result<(), NativeVulkanError> {
    if descriptor.fourcc != meta.format.drm_format() {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan VA DMABuf importer expected {} fourcc=0x{:08x}, got fourcc=0x{:08x}",
            meta.format.label(),
            meta.format.drm_format(),
            descriptor.fourcc
        )));
    }
    if descriptor.width != meta.width || descriptor.height != meta.height {
        return Err(NativeVulkanError::Video(format!(
            "VA DRM PRIME descriptor size {}x{} does not match sample {}x{}",
            descriptor.width, descriptor.height, meta.width, meta.height
        )));
    }
    if descriptor.num_objects == 0 || descriptor.num_objects > 4 {
        return Err(NativeVulkanError::Video(format!(
            "VA DRM PRIME descriptor has invalid object count {}",
            descriptor.num_objects
        )));
    }
    if descriptor.num_layers == 0 || descriptor.num_layers > 4 {
        return Err(NativeVulkanError::Video(format!(
            "VA DRM PRIME descriptor has invalid layer count {}",
            descriptor.num_layers
        )));
    }
    Ok(())
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_va_yuv420_plane_layouts(
    descriptor: &NativeVulkanVaDrmPrimeSurfaceDescriptor,
    format: NativeVulkanVideoSampleFormat,
) -> Result<(usize, u32, u32, usize, u32, u32), NativeVulkanError> {
    let layer_count = descriptor.num_layers as usize;
    for layer in descriptor.layers[..layer_count].iter() {
        if layer.drm_format == format.drm_format() && layer.num_planes >= 2 {
            let y_object = native_vulkan_va_layer_object_index(layer, 0, descriptor)?;
            let uv_object = native_vulkan_va_layer_object_index(layer, 1, descriptor)?;
            return Ok((
                y_object,
                layer.offset[0],
                layer.pitch[0],
                uv_object,
                layer.offset[1],
                layer.pitch[1],
            ));
        }
    }

    let y_fourcc = match format {
        NativeVulkanVideoSampleFormat::Nv12 => DRM_FORMAT_R8,
        NativeVulkanVideoSampleFormat::P010 => DRM_FORMAT_R16,
    };
    let uv_fourcc = match format {
        NativeVulkanVideoSampleFormat::Nv12 => DRM_FORMAT_GR88,
        NativeVulkanVideoSampleFormat::P010 => DRM_FORMAT_GR1616,
    };
    let y_layer = descriptor.layers[..layer_count]
        .iter()
        .find(|layer| layer.drm_format == y_fourcc && layer.num_planes >= 1)
        .ok_or_else(|| {
            NativeVulkanError::Video(format!(
                "VA DRM PRIME separate-layer export has no {} luma layer",
                format.label()
            ))
        })?;
    let uv_layer = descriptor.layers[..layer_count]
        .iter()
        .find(|layer| layer.drm_format == uv_fourcc && layer.num_planes >= 1)
        .ok_or_else(|| {
            NativeVulkanError::Video(format!(
                "VA DRM PRIME separate-layer export has no {} chroma layer",
                format.label()
            ))
        })?;
    let y_object = native_vulkan_va_layer_object_index(y_layer, 0, descriptor)?;
    let uv_object = native_vulkan_va_layer_object_index(uv_layer, 0, descriptor)?;
    Ok((
        y_object,
        y_layer.offset[0],
        y_layer.pitch[0],
        uv_object,
        uv_layer.offset[0],
        uv_layer.pitch[0],
    ))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_va_layer_object_index(
    layer: &NativeVulkanVaDrmPrimeLayer,
    plane: usize,
    descriptor: &NativeVulkanVaDrmPrimeSurfaceDescriptor,
) -> Result<usize, NativeVulkanError> {
    let object_index = layer.object_index[plane] as usize;
    if object_index >= descriptor.num_objects as usize {
        return Err(NativeVulkanError::Video(format!(
            "VA DRM PRIME layer object index {object_index} is out of range"
        )));
    }
    Ok(object_index)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_va_check(
    status: NativeVulkanVaStatus,
    operation: &'static str,
) -> Result<(), NativeVulkanError> {
    if status == VA_STATUS_SUCCESS {
        return Ok(());
    }
    let message = unsafe {
        let error = vaErrorStr(status);
        if error.is_null() {
            format!("{operation} failed with VAStatus {status}")
        } else {
            format!(
                "{operation} failed with VAStatus {status}: {}",
                CStr::from_ptr(error).to_string_lossy()
            )
        }
    };
    Err(NativeVulkanError::Video(message))
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct NativeVulkanVideoImportReport {
    width: u32,
    height: u32,
    memory_path: String,
    elapsed_us: u64,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct NativeVulkanVideoImportStatus {
    frames_imported: u64,
    last_import_size: Option<(u32, u32)>,
    last_import_memory_path: Option<String>,
    last_import_error: Option<String>,
    last_import_elapsed_us: Option<u64>,
    max_import_elapsed_us: Option<u64>,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoImportStatus {
    fn record_import(&mut self, report: NativeVulkanVideoImportReport) {
        self.frames_imported = self.frames_imported.saturating_add(1);
        self.last_import_size = Some((report.width, report.height));
        self.last_import_memory_path = Some(report.memory_path);
        self.last_import_error = None;
        self.last_import_elapsed_us = Some(report.elapsed_us);
        self.max_import_elapsed_us = Some(
            self.max_import_elapsed_us
                .map(|current| current.max(report.elapsed_us))
                .unwrap_or(report.elapsed_us),
        );
    }

    fn record_error(&mut self, error: String) {
        self.last_import_error = Some(error);
    }

    fn snapshot(&self) -> NativeVulkanVideoImportSnapshot {
        let texture_import_status = if self.frames_imported > 0 {
            match self.last_import_memory_path.as_deref() {
                Some(path) if path.contains("GstDmaBufMemory") => "importing-dmabuf-vulkan-image",
                _ => "importing-cuda-vulkan-image-planes",
            }
        } else if self.last_import_error.is_some() {
            "waiting-for-supported-importer"
        } else {
            "waiting-for-importable-sample"
        };
        NativeVulkanVideoImportSnapshot {
            texture_import_status,
            frames_imported: self.frames_imported,
            last_import_size: self.last_import_size,
            last_import_memory_path: self.last_import_memory_path.clone(),
            last_import_error: self.last_import_error.clone(),
            last_import_elapsed_us: self.last_import_elapsed_us,
            max_import_elapsed_us: self.max_import_elapsed_us,
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanVideoRenderer {
    render_pass: vk::RenderPass,
    framebuffers: Vec<vk::Framebuffer>,
    descriptor_set_layout: vk::DescriptorSetLayout,
    descriptor_pool: vk::DescriptorPool,
    descriptor_set: vk::DescriptorSet,
    pipeline_layout: vk::PipelineLayout,
    pipeline: vk::Pipeline,
    sampler: vk::Sampler,
    extent: vk::Extent2D,
    target_final_layout: vk::ImageLayout,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoRenderer {
    fn new(
        device: &ash::Device,
        swapchain_format: vk::Format,
        extent: vk::Extent2D,
        swapchain_image_views: &[vk::ImageView],
    ) -> Result<Self, NativeVulkanError> {
        Self::new_with_target_final_layout(
            device,
            swapchain_format,
            extent,
            swapchain_image_views,
            vk::ImageLayout::PRESENT_SRC_KHR,
        )
    }

    fn new_with_target_final_layout(
        device: &ash::Device,
        target_format: vk::Format,
        extent: vk::Extent2D,
        target_image_views: &[vk::ImageView],
        target_final_layout: vk::ImageLayout,
    ) -> Result<Self, NativeVulkanError> {
        let render_pass =
            native_vulkan_create_video_render_pass(device, target_format, target_final_layout)?;
        let framebuffers = native_vulkan_create_video_framebuffers(
            device,
            render_pass,
            extent,
            target_image_views,
        )?;
        let bindings = [
            native_vulkan_video_sampler_binding(0),
            native_vulkan_video_sampler_binding(1),
        ];
        let descriptor_set_layout_info =
            vk::DescriptorSetLayoutCreateInfo::default().bindings(&bindings);
        let descriptor_set_layout =
            unsafe { device.create_descriptor_set_layout(&descriptor_set_layout_info, None) }
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkCreateDescriptorSetLayout(video)",
                    result,
                })?;
        let pool_sizes = [vk::DescriptorPoolSize {
            ty: vk::DescriptorType::COMBINED_IMAGE_SAMPLER,
            descriptor_count: 2,
        }];
        let descriptor_pool_info = vk::DescriptorPoolCreateInfo::default()
            .max_sets(1)
            .pool_sizes(&pool_sizes);
        let descriptor_pool =
            match unsafe { device.create_descriptor_pool(&descriptor_pool_info, None) } {
                Ok(pool) => pool,
                Err(result) => {
                    unsafe {
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(NativeVulkanError::Vulkan {
                        operation: "vkCreateDescriptorPool(video)",
                        result,
                    });
                }
            };
        let set_layouts = [descriptor_set_layout];
        let descriptor_set_allocate_info = vk::DescriptorSetAllocateInfo::default()
            .descriptor_pool(descriptor_pool)
            .set_layouts(&set_layouts);
        let descriptor_set =
            match unsafe { device.allocate_descriptor_sets(&descriptor_set_allocate_info) } {
                Ok(sets) => sets[0],
                Err(result) => {
                    unsafe {
                        device.destroy_descriptor_pool(descriptor_pool, None);
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(NativeVulkanError::Vulkan {
                        operation: "vkAllocateDescriptorSets(video)",
                        result,
                    });
                }
            };
        let sampler_info = vk::SamplerCreateInfo::default()
            .mag_filter(vk::Filter::LINEAR)
            .min_filter(vk::Filter::LINEAR)
            .mipmap_mode(vk::SamplerMipmapMode::NEAREST)
            .address_mode_u(vk::SamplerAddressMode::CLAMP_TO_EDGE)
            .address_mode_v(vk::SamplerAddressMode::CLAMP_TO_EDGE)
            .address_mode_w(vk::SamplerAddressMode::CLAMP_TO_EDGE)
            .max_lod(1.0);
        let sampler = match unsafe { device.create_sampler(&sampler_info, None) } {
            Ok(sampler) => sampler,
            Err(result) => {
                unsafe {
                    device.destroy_descriptor_pool(descriptor_pool, None);
                    device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                    for framebuffer in framebuffers {
                        device.destroy_framebuffer(framebuffer, None);
                    }
                    device.destroy_render_pass(render_pass, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateSampler(video)",
                    result,
                });
            }
        };
        let push_constant_ranges = [vk::PushConstantRange::default()
            .stage_flags(vk::ShaderStageFlags::VERTEX)
            .offset(0)
            .size(16)];
        let pipeline_set_layouts = [descriptor_set_layout];
        let pipeline_layout_info = vk::PipelineLayoutCreateInfo::default()
            .set_layouts(&pipeline_set_layouts)
            .push_constant_ranges(&push_constant_ranges);
        let pipeline_layout =
            match unsafe { device.create_pipeline_layout(&pipeline_layout_info, None) } {
                Ok(layout) => layout,
                Err(result) => {
                    unsafe {
                        device.destroy_sampler(sampler, None);
                        device.destroy_descriptor_pool(descriptor_pool, None);
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(NativeVulkanError::Vulkan {
                        operation: "vkCreatePipelineLayout(video)",
                        result,
                    });
                }
            };
        let pipeline =
            match native_vulkan_create_video_pipeline(device, render_pass, pipeline_layout, extent)
            {
                Ok(pipeline) => pipeline,
                Err(err) => {
                    unsafe {
                        device.destroy_pipeline_layout(pipeline_layout, None);
                        device.destroy_sampler(sampler, None);
                        device.destroy_descriptor_pool(descriptor_pool, None);
                        device.destroy_descriptor_set_layout(descriptor_set_layout, None);
                        for framebuffer in framebuffers {
                            device.destroy_framebuffer(framebuffer, None);
                        }
                        device.destroy_render_pass(render_pass, None);
                    }
                    return Err(err);
                }
            };

        Ok(Self {
            render_pass,
            framebuffers,
            descriptor_set_layout,
            descriptor_pool,
            descriptor_set,
            pipeline_layout,
            pipeline,
            sampler,
            extent,
            target_final_layout,
        })
    }

    fn target_final_layout(&self) -> vk::ImageLayout {
        self.target_final_layout
    }

    fn update_descriptors(&mut self, device: &ash::Device, texture: &NativeVulkanVideoTexture) {
        let image_infos = [
            vk::DescriptorImageInfo::default()
                .sampler(self.sampler)
                .image_view(texture.y_view())
                .image_layout(texture.image_layout()),
            vk::DescriptorImageInfo::default()
                .sampler(self.sampler)
                .image_view(texture.uv_view())
                .image_layout(texture.image_layout()),
        ];
        let writes = [
            vk::WriteDescriptorSet::default()
                .dst_set(self.descriptor_set)
                .dst_binding(0)
                .descriptor_type(vk::DescriptorType::COMBINED_IMAGE_SAMPLER)
                .image_info(&image_infos[0..1]),
            vk::WriteDescriptorSet::default()
                .dst_set(self.descriptor_set)
                .dst_binding(1)
                .descriptor_type(vk::DescriptorType::COMBINED_IMAGE_SAMPLER)
                .image_info(&image_infos[1..2]),
        ];
        unsafe {
            device.update_descriptor_sets(&writes, &[]);
        }
    }

    fn record_frame(
        &self,
        device: &ash::Device,
        command_buffer: vk::CommandBuffer,
        image_index: usize,
        swapchain_image: vk::Image,
        swapchain_old_layout: vk::ImageLayout,
        texture: &NativeVulkanVideoTexture,
        fit: FitMode,
    ) -> Result<(), NativeVulkanError> {
        unsafe {
            device
                .reset_command_buffer(command_buffer, vk::CommandBufferResetFlags::empty())
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkResetCommandBuffer(video)",
                    result,
                })?;
            let begin_info = vk::CommandBufferBeginInfo::default()
                .flags(vk::CommandBufferUsageFlags::ONE_TIME_SUBMIT);
            device
                .begin_command_buffer(command_buffer, &begin_info)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkBeginCommandBuffer(video)",
                    result,
                })?;

            let swapchain_to_attachment = vk::ImageMemoryBarrier::default()
                .old_layout(swapchain_old_layout)
                .new_layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL)
                .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
                .image(swapchain_image)
                .subresource_range(native_vulkan_color_subresource_range())
                .src_access_mask(vk::AccessFlags::empty())
                .dst_access_mask(vk::AccessFlags::COLOR_ATTACHMENT_WRITE);
            let texture_barriers = texture.shader_read_barriers();
            let barriers = [
                swapchain_to_attachment,
                texture_barriers[0],
                texture_barriers[1],
            ];
            device.cmd_pipeline_barrier(
                command_buffer,
                vk::PipelineStageFlags::TOP_OF_PIPE | vk::PipelineStageFlags::ALL_COMMANDS,
                vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT
                    | vk::PipelineStageFlags::FRAGMENT_SHADER,
                vk::DependencyFlags::empty(),
                &[],
                &[],
                &barriers,
            );

            let clear_values = [vk::ClearValue {
                color: vk::ClearColorValue {
                    float32: [0.0, 0.0, 0.0, 1.0],
                },
            }];
            let render_area = vk::Rect2D {
                offset: vk::Offset2D { x: 0, y: 0 },
                extent: self.extent,
            };
            let render_pass_begin = vk::RenderPassBeginInfo::default()
                .render_pass(self.render_pass)
                .framebuffer(self.framebuffers[image_index])
                .render_area(render_area)
                .clear_values(&clear_values);
            device.cmd_begin_render_pass(
                command_buffer,
                &render_pass_begin,
                vk::SubpassContents::INLINE,
            );
            device.cmd_bind_pipeline(
                command_buffer,
                vk::PipelineBindPoint::GRAPHICS,
                self.pipeline,
            );
            device.cmd_bind_descriptor_sets(
                command_buffer,
                vk::PipelineBindPoint::GRAPHICS,
                self.pipeline_layout,
                0,
                &[self.descriptor_set],
                &[],
            );
            let push = native_vulkan_video_fit_push_constants(
                fit,
                (texture.width(), texture.height()),
                (self.extent.width, self.extent.height),
            );
            let push_bytes = std::slice::from_raw_parts(
                push.as_ptr().cast::<u8>(),
                std::mem::size_of_val(&push),
            );
            device.cmd_push_constants(
                command_buffer,
                self.pipeline_layout,
                vk::ShaderStageFlags::VERTEX,
                0,
                push_bytes,
            );
            device.cmd_draw(command_buffer, 3, 1, 0, 0);
            device.cmd_end_render_pass(command_buffer);

            device
                .end_command_buffer(command_buffer)
                .map_err(|result| NativeVulkanError::Vulkan {
                    operation: "vkEndCommandBuffer(video)",
                    result,
                })?;
        }
        Ok(())
    }

    fn destroy(self, device: &ash::Device) {
        unsafe {
            device.destroy_pipeline(self.pipeline, None);
            device.destroy_pipeline_layout(self.pipeline_layout, None);
            device.destroy_sampler(self.sampler, None);
            device.destroy_descriptor_pool(self.descriptor_pool, None);
            device.destroy_descriptor_set_layout(self.descriptor_set_layout, None);
            for framebuffer in self.framebuffers {
                device.destroy_framebuffer(framebuffer, None);
            }
            device.destroy_render_pass(self.render_pass, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_video_sampler_binding(binding: u32) -> vk::DescriptorSetLayoutBinding<'static> {
    vk::DescriptorSetLayoutBinding::default()
        .binding(binding)
        .descriptor_type(vk::DescriptorType::COMBINED_IMAGE_SAMPLER)
        .descriptor_count(1)
        .stage_flags(vk::ShaderStageFlags::FRAGMENT)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_video_render_pass(
    device: &ash::Device,
    swapchain_format: vk::Format,
    final_layout: vk::ImageLayout,
) -> Result<vk::RenderPass, NativeVulkanError> {
    let color_attachment = vk::AttachmentDescription::default()
        .format(swapchain_format)
        .samples(vk::SampleCountFlags::TYPE_1)
        .load_op(vk::AttachmentLoadOp::CLEAR)
        .store_op(vk::AttachmentStoreOp::STORE)
        .stencil_load_op(vk::AttachmentLoadOp::DONT_CARE)
        .stencil_store_op(vk::AttachmentStoreOp::DONT_CARE)
        .initial_layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL)
        .final_layout(final_layout);
    let color_attachment_ref = vk::AttachmentReference::default()
        .attachment(0)
        .layout(vk::ImageLayout::COLOR_ATTACHMENT_OPTIMAL);
    let color_attachment_refs = [color_attachment_ref];
    let subpass = vk::SubpassDescription::default()
        .pipeline_bind_point(vk::PipelineBindPoint::GRAPHICS)
        .color_attachments(&color_attachment_refs);
    let dependency = vk::SubpassDependency::default()
        .src_subpass(vk::SUBPASS_EXTERNAL)
        .dst_subpass(0)
        .src_stage_mask(vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT)
        .dst_stage_mask(vk::PipelineStageFlags::COLOR_ATTACHMENT_OUTPUT)
        .dst_access_mask(vk::AccessFlags::COLOR_ATTACHMENT_WRITE);
    let attachments = [color_attachment];
    let subpasses = [subpass];
    let dependencies = [dependency];
    let render_pass_info = vk::RenderPassCreateInfo::default()
        .attachments(&attachments)
        .subpasses(&subpasses)
        .dependencies(&dependencies);
    unsafe { device.create_render_pass(&render_pass_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: "vkCreateRenderPass(video)",
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_video_framebuffers(
    device: &ash::Device,
    render_pass: vk::RenderPass,
    extent: vk::Extent2D,
    swapchain_image_views: &[vk::ImageView],
) -> Result<Vec<vk::Framebuffer>, NativeVulkanError> {
    let mut framebuffers = Vec::with_capacity(swapchain_image_views.len());
    for view in swapchain_image_views {
        let attachments = [*view];
        let info = vk::FramebufferCreateInfo::default()
            .render_pass(render_pass)
            .attachments(&attachments)
            .width(extent.width)
            .height(extent.height)
            .layers(1);
        let framebuffer = match unsafe { device.create_framebuffer(&info, None) } {
            Ok(framebuffer) => framebuffer,
            Err(result) => {
                for framebuffer in framebuffers {
                    unsafe {
                        device.destroy_framebuffer(framebuffer, None);
                    }
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateFramebuffer(video)",
                    result,
                });
            }
        };
        framebuffers.push(framebuffer);
    }
    Ok(framebuffers)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_video_pipeline(
    device: &ash::Device,
    render_pass: vk::RenderPass,
    pipeline_layout: vk::PipelineLayout,
    extent: vk::Extent2D,
) -> Result<vk::Pipeline, NativeVulkanError> {
    let vertex_module = native_vulkan_create_shader_module(
        device,
        &NATIVE_VULKAN_VIDEO_VERTEX_SPIRV,
        "video vertex",
    )?;
    let fragment_module = match native_vulkan_create_shader_module(
        device,
        &NATIVE_VULKAN_VIDEO_FRAGMENT_SPIRV,
        "video fragment",
    ) {
        Ok(module) => module,
        Err(err) => {
            unsafe {
                device.destroy_shader_module(vertex_module, None);
            }
            return Err(err);
        }
    };
    let entry = c"main";
    let stages = [
        vk::PipelineShaderStageCreateInfo::default()
            .stage(vk::ShaderStageFlags::VERTEX)
            .module(vertex_module)
            .name(entry),
        vk::PipelineShaderStageCreateInfo::default()
            .stage(vk::ShaderStageFlags::FRAGMENT)
            .module(fragment_module)
            .name(entry),
    ];
    let vertex_input = vk::PipelineVertexInputStateCreateInfo::default();
    let input_assembly = vk::PipelineInputAssemblyStateCreateInfo::default()
        .topology(vk::PrimitiveTopology::TRIANGLE_LIST);
    let viewport = vk::Viewport {
        x: 0.0,
        y: 0.0,
        width: extent.width as f32,
        height: extent.height as f32,
        min_depth: 0.0,
        max_depth: 1.0,
    };
    let scissor = vk::Rect2D {
        offset: vk::Offset2D { x: 0, y: 0 },
        extent,
    };
    let viewports = [viewport];
    let scissors = [scissor];
    let viewport_state = vk::PipelineViewportStateCreateInfo::default()
        .viewports(&viewports)
        .scissors(&scissors);
    let rasterization = vk::PipelineRasterizationStateCreateInfo::default()
        .polygon_mode(vk::PolygonMode::FILL)
        .cull_mode(vk::CullModeFlags::NONE)
        .front_face(vk::FrontFace::COUNTER_CLOCKWISE)
        .line_width(1.0);
    let multisample = vk::PipelineMultisampleStateCreateInfo::default()
        .rasterization_samples(vk::SampleCountFlags::TYPE_1);
    let color_attachment = vk::PipelineColorBlendAttachmentState::default()
        .color_write_mask(
            vk::ColorComponentFlags::R
                | vk::ColorComponentFlags::G
                | vk::ColorComponentFlags::B
                | vk::ColorComponentFlags::A,
        )
        .blend_enable(false);
    let color_attachments = [color_attachment];
    let color_blend =
        vk::PipelineColorBlendStateCreateInfo::default().attachments(&color_attachments);
    let pipeline_info = vk::GraphicsPipelineCreateInfo::default()
        .stages(&stages)
        .vertex_input_state(&vertex_input)
        .input_assembly_state(&input_assembly)
        .viewport_state(&viewport_state)
        .rasterization_state(&rasterization)
        .multisample_state(&multisample)
        .color_blend_state(&color_blend)
        .layout(pipeline_layout)
        .render_pass(render_pass)
        .subpass(0);
    let pipelines = unsafe {
        device.create_graphics_pipelines(vk::PipelineCache::null(), &[pipeline_info], None)
    };
    unsafe {
        device.destroy_shader_module(fragment_module, None);
        device.destroy_shader_module(vertex_module, None);
    }
    pipelines
        .map(|pipelines| pipelines[0])
        .map_err(|(_, result)| NativeVulkanError::Vulkan {
            operation: "vkCreateGraphicsPipelines(video)",
            result,
        })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_shader_module(
    device: &ash::Device,
    code: &[u32],
    label: &'static str,
) -> Result<vk::ShaderModule, NativeVulkanError> {
    let info = vk::ShaderModuleCreateInfo::default().code(code);
    unsafe { device.create_shader_module(&info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: match label {
                "video vertex" => "vkCreateShaderModule(video vertex)",
                "video fragment" => "vkCreateShaderModule(video fragment)",
                _ => "vkCreateShaderModule(video)",
            },
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_video_fit_push_constants(
    fit: FitMode,
    source_size: (u32, u32),
    surface_size: (u32, u32),
) -> [f32; 4] {
    let (offset, scale) = native_vulkan_video_uv_transform(fit, source_size, surface_size);
    [offset[0], offset[1], scale[0], scale[1]]
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_video_uv_transform(
    fit: FitMode,
    source_size: (u32, u32),
    surface_size: (u32, u32),
) -> ([f32; 2], [f32; 2]) {
    if matches!(fit, FitMode::Stretch | FitMode::Contain | FitMode::Center) {
        return ([0.0, 0.0], [1.0, 1.0]);
    }
    let source_aspect = source_size.0.max(1) as f32 / source_size.1.max(1) as f32;
    let surface_aspect = surface_size.0.max(1) as f32 / surface_size.1.max(1) as f32;
    if source_aspect > surface_aspect {
        let width = (surface_aspect / source_aspect).clamp(0.0, 1.0);
        ([(1.0 - width) * 0.5, 0.0], [width, 1.0])
    } else {
        let height = (source_aspect / surface_aspect).clamp(0.0, 1.0);
        ([0.0, (1.0 - height) * 0.5], [1.0, height])
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
enum NativeVulkanVideoTexture {
    Cuda(NativeVulkanCudaVideoTexture),
    Dmabuf(NativeVulkanDmabufVideoTexture),
    Decoded(NativeVulkanDecodedVideoTexture),
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoTexture {
    fn width(&self) -> u32 {
        match self {
            Self::Cuda(texture) => texture.width,
            Self::Dmabuf(texture) => texture.width,
            Self::Decoded(texture) => texture.width,
        }
    }

    fn height(&self) -> u32 {
        match self {
            Self::Cuda(texture) => texture.height,
            Self::Dmabuf(texture) => texture.height,
            Self::Decoded(texture) => texture.height,
        }
    }

    fn y_view(&self) -> vk::ImageView {
        match self {
            Self::Cuda(texture) => texture.y.view,
            Self::Dmabuf(texture) => texture.y_view,
            Self::Decoded(texture) => texture.y_view,
        }
    }

    fn uv_view(&self) -> vk::ImageView {
        match self {
            Self::Cuda(texture) => texture.uv.view,
            Self::Dmabuf(texture) => texture.uv_view,
            Self::Decoded(texture) => texture.uv_view,
        }
    }

    fn image_layout(&self) -> vk::ImageLayout {
        match self {
            Self::Cuda(_) | Self::Dmabuf(_) => vk::ImageLayout::GENERAL,
            Self::Decoded(texture) => texture.shader_layout,
        }
    }

    fn shader_read_barriers(&self) -> [vk::ImageMemoryBarrier<'static>; 2] {
        match self {
            Self::Cuda(texture) => texture.shader_read_barriers(),
            Self::Dmabuf(texture) => texture.shader_read_barriers(),
            Self::Decoded(texture) => texture.shader_read_barriers(),
        }
    }

    fn destroy(self, device: &ash::Device) {
        match self {
            Self::Cuda(texture) => texture.destroy(device),
            Self::Dmabuf(texture) => texture.destroy(device),
            Self::Decoded(texture) => texture.destroy(device),
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanDecodedVideoTexture {
    image: vk::Image,
    width: u32,
    height: u32,
    base_array_layer: u32,
    y_view: vk::ImageView,
    uv_view: vk::ImageView,
    owns_views: bool,
    source_layout: vk::ImageLayout,
    shader_layout: vk::ImageLayout,
    source_access: vk::AccessFlags,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanDecodedVideoTexture {
    fn new(
        device: &ash::Device,
        image: vk::Image,
        width: u32,
        height: u32,
        base_array_layer: u32,
        source_layout: vk::ImageLayout,
        source_access: vk::AccessFlags,
    ) -> Result<Self, NativeVulkanError> {
        if width == 0 || height == 0 || !width.is_multiple_of(2) || !height.is_multiple_of(2) {
            return Err(NativeVulkanError::Video(format!(
                "decoded NV12 texture requires non-zero even dimensions, got {width}x{height}"
            )));
        }
        let y_view = native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_0,
            vk::Format::R8_UNORM,
            base_array_layer,
            "y",
        )?;
        let uv_view = match native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_1,
            vk::Format::R8G8_UNORM,
            base_array_layer,
            "uv",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(y_view, None);
                }
                return Err(err);
            }
        };
        Ok(Self {
            image,
            width,
            height,
            base_array_layer,
            y_view,
            uv_view,
            owns_views: true,
            source_layout,
            shader_layout: vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL,
            source_access,
        })
    }

    fn from_cached_views(
        image: vk::Image,
        width: u32,
        height: u32,
        base_array_layer: u32,
        views: NativeVulkanDecodedVideoPlaneViews,
        source_layout: vk::ImageLayout,
        source_access: vk::AccessFlags,
    ) -> Result<Self, NativeVulkanError> {
        if width == 0 || height == 0 || !width.is_multiple_of(2) || !height.is_multiple_of(2) {
            return Err(NativeVulkanError::Video(format!(
                "decoded NV12 texture requires non-zero even dimensions, got {width}x{height}"
            )));
        }
        Ok(Self {
            image,
            width,
            height,
            base_array_layer,
            y_view: views.y_view,
            uv_view: views.uv_view,
            owns_views: false,
            source_layout,
            shader_layout: vk::ImageLayout::SHADER_READ_ONLY_OPTIMAL,
            source_access,
        })
    }

    fn shader_read_barriers(&self) -> [vk::ImageMemoryBarrier<'static>; 2] {
        [
            self.shader_read_barrier(vk::ImageAspectFlags::PLANE_0),
            self.shader_read_barrier(vk::ImageAspectFlags::PLANE_1),
        ]
    }

    fn shader_read_barrier(
        &self,
        aspect_mask: vk::ImageAspectFlags,
    ) -> vk::ImageMemoryBarrier<'static> {
        vk::ImageMemoryBarrier::default()
            .old_layout(self.source_layout)
            .new_layout(self.shader_layout)
            .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .image(self.image)
            .subresource_range(vk::ImageSubresourceRange {
                aspect_mask,
                base_mip_level: 0,
                level_count: 1,
                base_array_layer: self.base_array_layer,
                layer_count: 1,
            })
            .src_access_mask(self.source_access)
            .dst_access_mask(vk::AccessFlags::SHADER_READ)
    }

    fn destroy(self, device: &ash::Device) {
        if self.owns_views {
            unsafe {
                device.destroy_image_view(self.uv_view, None);
                device.destroy_image_view(self.y_view, None);
            }
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy)]
struct NativeVulkanDecodedVideoPlaneViews {
    y_view: vk::ImageView,
    uv_view: vk::ImageView,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_decoded_video_plane_view_cache(
    device: &ash::Device,
    image: vk::Image,
    array_layers: u32,
) -> Result<Vec<NativeVulkanDecodedVideoPlaneViews>, NativeVulkanError> {
    let mut views = Vec::with_capacity(array_layers as usize);
    for base_array_layer in 0..array_layers {
        let y_view = native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_0,
            vk::Format::R8_UNORM,
            base_array_layer,
            "y",
        )?;
        let uv_view = match native_vulkan_create_decoded_video_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_1,
            vk::Format::R8G8_UNORM,
            base_array_layer,
            "uv",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(y_view, None);
                }
                native_vulkan_destroy_decoded_video_plane_view_cache(device, views);
                return Err(err);
            }
        };
        views.push(NativeVulkanDecodedVideoPlaneViews { y_view, uv_view });
    }
    Ok(views)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_destroy_decoded_video_plane_view_cache(
    device: &ash::Device,
    views: Vec<NativeVulkanDecodedVideoPlaneViews>,
) {
    unsafe {
        for view in views {
            device.destroy_image_view(view.uv_view, None);
            device.destroy_image_view(view.y_view, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_decoded_video_plane_view(
    device: &ash::Device,
    image: vk::Image,
    aspect_mask: vk::ImageAspectFlags,
    format: vk::Format,
    base_array_layer: u32,
    label: &'static str,
) -> Result<vk::ImageView, NativeVulkanError> {
    let mut view_usage_info =
        vk::ImageViewUsageCreateInfo::default().usage(vk::ImageUsageFlags::SAMPLED);
    let view_info = vk::ImageViewCreateInfo::default()
        .image(image)
        .view_type(vk::ImageViewType::TYPE_2D)
        .format(format)
        .subresource_range(vk::ImageSubresourceRange {
            aspect_mask,
            base_mip_level: 0,
            level_count: 1,
            base_array_layer,
            layer_count: 1,
        })
        .push_next(&mut view_usage_info);
    unsafe { device.create_image_view(&view_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: match label {
                "y" => "vkCreateImageView(decoded video y plane)",
                "uv" => "vkCreateImageView(decoded video uv plane)",
                _ => "vkCreateImageView(decoded video plane)",
            },
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanDmabufVideoPlane {
    fd: i32,
    offset: u64,
    stride: u32,
    height: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug)]
struct NativeVulkanDmabufVideoFrame {
    format: NativeVulkanVideoSampleFormat,
    width: u32,
    height: u32,
    fd: i32,
    modifier: u64,
    y: NativeVulkanDmabufVideoPlane,
    uv: NativeVulkanDmabufVideoPlane,
    _owned_fds: Vec<OwnedFd>,
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanDmabufVideoTexture {
    width: u32,
    height: u32,
    image: vk::Image,
    memory: vk::DeviceMemory,
    y_view: vk::ImageView,
    uv_view: vk::ImageView,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanDmabufVideoTexture {
    #[allow(clippy::too_many_arguments)]
    fn new(
        instance: &ash::Instance,
        physical_device: vk::PhysicalDevice,
        _queue: vk::Queue,
        _command_pool: vk::CommandPool,
        device: &ash::Device,
        _queue_family_index: u32,
        frame: &NativeVulkanDmabufVideoFrame,
    ) -> Result<Self, NativeVulkanError> {
        if frame.width == 0 || frame.height == 0 {
            return Err(NativeVulkanError::Video(
                "native Vulkan DMABuf video frame has zero dimension".to_owned(),
            ));
        }
        if frame.width % 2 != 0 || frame.height % 2 != 0 {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan DMABuf video dimensions must be even, got {}x{}",
                frame.width, frame.height
            )));
        }
        if frame.fd < 0 || frame.y.fd != frame.fd || frame.uv.fd != frame.fd {
            return Err(NativeVulkanError::Video(
                "native Vulkan DMABuf importer currently requires a single fd two-plane YUV420 frame"
                    .to_owned(),
            ));
        }

        let plane_layouts = [
            native_vulkan_dmabuf_plane_layout(frame.y),
            native_vulkan_dmabuf_plane_layout(frame.uv),
        ];
        let handle_type = vk::ExternalMemoryHandleTypeFlags::DMA_BUF_EXT;
        let mut external_image_info =
            vk::ExternalMemoryImageCreateInfo::default().handle_types(handle_type);
        let mut drm_modifier_info = vk::ImageDrmFormatModifierExplicitCreateInfoEXT::default()
            .drm_format_modifier(frame.modifier)
            .plane_layouts(&plane_layouts);
        let image_info = vk::ImageCreateInfo::default()
            .flags(vk::ImageCreateFlags::MUTABLE_FORMAT)
            .image_type(vk::ImageType::TYPE_2D)
            .format(frame.format.vulkan_image_format())
            .extent(vk::Extent3D {
                width: frame.width,
                height: frame.height,
                depth: 1,
            })
            .mip_levels(1)
            .array_layers(1)
            .samples(vk::SampleCountFlags::TYPE_1)
            .tiling(vk::ImageTiling::DRM_FORMAT_MODIFIER_EXT)
            .usage(vk::ImageUsageFlags::SAMPLED)
            .sharing_mode(vk::SharingMode::EXCLUSIVE)
            .initial_layout(vk::ImageLayout::UNDEFINED)
            .push_next(&mut external_image_info)
            .push_next(&mut drm_modifier_info);
        let image = unsafe { device.create_image(&image_info, None) }.map_err(|result| {
            NativeVulkanError::Vulkan {
                operation: "vkCreateImage(video DMABuf image)",
                result,
            }
        })?;

        let requirements = unsafe { device.get_image_memory_requirements(image) };
        let external_memory_fd = ash::khr::external_memory_fd::Device::new(instance, device);
        let mut fd_properties = vk::MemoryFdPropertiesKHR::default();
        unsafe {
            external_memory_fd
                .get_memory_fd_properties(handle_type, frame.fd, &mut fd_properties)
                .map_err(|result| {
                    device.destroy_image(image, None);
                    NativeVulkanError::Vulkan {
                        operation: "vkGetMemoryFdPropertiesKHR(video DMABuf)",
                        result,
                    }
                })?;
        }
        let memory_type_bits = requirements.memory_type_bits & fd_properties.memory_type_bits;
        if memory_type_bits == 0 {
            unsafe {
                device.destroy_image(image, None);
            }
            return Err(NativeVulkanError::Video(
                "native Vulkan DMABuf import has zero compatible memory_type_bits".to_owned(),
            ));
        }
        let memory_properties =
            unsafe { instance.get_physical_device_memory_properties(physical_device) };
        let memory_type_index = native_vulkan_memory_type_index_prefer(
            &memory_properties,
            memory_type_bits,
            vk::MemoryPropertyFlags::DEVICE_LOCAL,
            vk::MemoryPropertyFlags::empty(),
        )
        .ok_or_else(|| {
            unsafe {
                device.destroy_image(image, None);
            }
            NativeVulkanError::MissingMemoryType("video DMABuf image")
        })?;

        let duplicated_fd = native_vulkan_dup_fd(frame.fd).map_err(|err| {
            unsafe {
                device.destroy_image(image, None);
            }
            err
        })?;
        let mut import_info = vk::ImportMemoryFdInfoKHR::default()
            .handle_type(handle_type)
            .fd(duplicated_fd.as_raw_fd());
        let mut dedicated_info = vk::MemoryDedicatedAllocateInfo::default().image(image);
        let allocate_info = vk::MemoryAllocateInfo::default()
            .allocation_size(requirements.size)
            .memory_type_index(memory_type_index)
            .push_next(&mut dedicated_info)
            .push_next(&mut import_info);
        let memory = match unsafe { device.allocate_memory(&allocate_info, None) } {
            Ok(memory) => {
                let _ = duplicated_fd.into_raw_fd();
                memory
            }
            Err(result) => {
                unsafe {
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkAllocateMemory(video DMABuf image)",
                    result,
                });
            }
        };
        if let Err(result) = unsafe { device.bind_image_memory(image, memory, 0) } {
            unsafe {
                device.free_memory(memory, None);
                device.destroy_image(image, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkBindImageMemory(video DMABuf image)",
                result,
            });
        }

        let y_view = match native_vulkan_create_dmabuf_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_0,
            frame.format.y_view_format(),
            "y",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(err);
            }
        };
        let uv_view = match native_vulkan_create_dmabuf_plane_view(
            device,
            image,
            vk::ImageAspectFlags::PLANE_1,
            frame.format.uv_view_format(),
            "uv",
        ) {
            Ok(view) => view,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(y_view, None);
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(err);
            }
        };

        Ok(Self {
            width: frame.width,
            height: frame.height,
            image,
            memory,
            y_view,
            uv_view,
        })
    }

    fn shader_read_barriers(&self) -> [vk::ImageMemoryBarrier<'static>; 2] {
        [
            native_vulkan_dmabuf_shader_read_barrier(self.image, vk::ImageAspectFlags::PLANE_0),
            native_vulkan_dmabuf_shader_read_barrier(self.image, vk::ImageAspectFlags::PLANE_1),
        ]
    }

    fn destroy(self, device: &ash::Device) {
        unsafe {
            device.destroy_image_view(self.uv_view, None);
            device.destroy_image_view(self.y_view, None);
            device.free_memory(self.memory, None);
            device.destroy_image(self.image, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_plane_layout(plane: NativeVulkanDmabufVideoPlane) -> vk::SubresourceLayout {
    vk::SubresourceLayout {
        offset: plane.offset,
        size: u64::from(plane.stride) * u64::from(plane.height),
        row_pitch: u64::from(plane.stride),
        array_pitch: 0,
        depth_pitch: 0,
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dmabuf_shader_read_barrier(
    image: vk::Image,
    aspect_mask: vk::ImageAspectFlags,
) -> vk::ImageMemoryBarrier<'static> {
    vk::ImageMemoryBarrier::default()
        .old_layout(vk::ImageLayout::GENERAL)
        .new_layout(vk::ImageLayout::GENERAL)
        .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
        .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
        .image(image)
        .subresource_range(vk::ImageSubresourceRange {
            aspect_mask,
            base_mip_level: 0,
            level_count: 1,
            base_array_layer: 0,
            layer_count: 1,
        })
        .src_access_mask(vk::AccessFlags::MEMORY_WRITE)
        .dst_access_mask(vk::AccessFlags::SHADER_READ)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_create_dmabuf_plane_view(
    device: &ash::Device,
    image: vk::Image,
    aspect_mask: vk::ImageAspectFlags,
    format: vk::Format,
    label: &'static str,
) -> Result<vk::ImageView, NativeVulkanError> {
    let view_info = vk::ImageViewCreateInfo::default()
        .image(image)
        .view_type(vk::ImageViewType::TYPE_2D)
        .format(format)
        .subresource_range(vk::ImageSubresourceRange {
            aspect_mask,
            base_mip_level: 0,
            level_count: 1,
            base_array_layer: 0,
            layer_count: 1,
        });
    unsafe { device.create_image_view(&view_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: match label {
                "y" => "vkCreateImageView(video DMABuf y plane)",
                "uv" => "vkCreateImageView(video DMABuf uv plane)",
                _ => "vkCreateImageView(video DMABuf plane)",
            },
            result,
        }
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_dup_fd(fd: i32) -> Result<OwnedFd, NativeVulkanError> {
    let duplicated = unsafe { libc::dup(fd) };
    if duplicated < 0 {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan DMABuf dup fd failed: {}",
            std::io::Error::last_os_error()
        )));
    }
    Ok(unsafe { OwnedFd::from_raw_fd(duplicated) })
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaVideoTexture {
    cuda_context: *mut NativeVulkanGstCudaContext,
    format: NativeVulkanVideoSampleFormat,
    width: u32,
    height: u32,
    cuda_stream: NativeVulkanCudaStream,
    y: NativeVulkanCudaVideoPlane,
    uv: NativeVulkanCudaVideoPlane,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaVideoTexture {
    fn new(
        instance: &ash::Instance,
        physical_device: vk::PhysicalDevice,
        queue: vk::Queue,
        command_pool: vk::CommandPool,
        device: &ash::Device,
        queue_family_index: u32,
        cuda_context: *mut NativeVulkanGstCudaContext,
        width: u32,
        height: u32,
        format: NativeVulkanVideoSampleFormat,
    ) -> Result<Self, NativeVulkanError> {
        if width == 0 || height == 0 {
            return Err(NativeVulkanError::Video(
                "native Vulkan CUDA video frame has zero dimension".to_owned(),
            ));
        }
        if width % 2 != 0 || height % 2 != 0 {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan CUDA video dimensions must be even, got {width}x{height}"
            )));
        }
        if cuda_context.is_null() {
            return Err(NativeVulkanError::Video(
                "native Vulkan CUDA video sample has null GstCudaContext".to_owned(),
            ));
        }
        let _guard = NativeVulkanGstCudaContextPushGuard::new(cuda_context)?;
        let cuda_stream = NativeVulkanCudaStream::new()?;
        let y = NativeVulkanCudaVideoPlane::new(
            instance,
            physical_device,
            queue,
            command_pool,
            device,
            queue_family_index,
            width,
            height,
            format.y_view_format(),
            1,
            format.bytes_per_component(),
            format.cuda_array_format(),
            "y",
        )?;
        let uv = match NativeVulkanCudaVideoPlane::new(
            instance,
            physical_device,
            queue,
            command_pool,
            device,
            queue_family_index,
            width / 2,
            height / 2,
            format.uv_view_format(),
            2,
            format.bytes_per_component(),
            format.cuda_array_format(),
            "uv",
        ) {
            Ok(plane) => plane,
            Err(err) => {
                y.destroy(device);
                return Err(err);
            }
        };
        Ok(Self {
            cuda_context,
            format,
            width,
            height,
            cuda_stream,
            y,
            uv,
        })
    }

    fn matches(
        &self,
        cuda_context: *mut NativeVulkanGstCudaContext,
        width: u32,
        height: u32,
        format: NativeVulkanVideoSampleFormat,
    ) -> bool {
        self.cuda_context == cuda_context
            && self.width == width
            && self.height == height
            && self.format == format
    }

    fn copy_sample(
        &mut self,
        buffer: &gst::BufferRef,
        meta: &NativeVulkanGstSystemNv12Meta,
    ) -> Result<(), NativeVulkanError> {
        let _guard = NativeVulkanGstCudaContextPushGuard::new(self.cuda_context)?;
        let y_map = native_vulkan_copy_gst_cuda_plane_to_vulkan_image(
            buffer,
            0,
            meta.y.offset,
            meta.y.stride,
            meta.y.row_bytes,
            meta.y.height,
            self.cuda_context,
            self.cuda_stream.handle,
            &self.y,
            "y",
        )?;
        let uv_map = match native_vulkan_copy_gst_cuda_plane_to_vulkan_image(
            buffer,
            1,
            meta.uv.offset,
            meta.uv.stride,
            meta.uv.row_bytes,
            meta.uv.height,
            self.cuda_context,
            self.cuda_stream.handle,
            &self.uv,
            "uv",
        ) {
            Ok(map) => map,
            Err(err) => {
                let sync_result = native_vulkan_cuda_result(
                    unsafe { CuStreamSynchronize(self.cuda_stream.handle) },
                    "native Vulkan CUDA synchronize after failed uv copy",
                );
                drop(y_map);
                sync_result?;
                return Err(err);
            }
        };
        let sync_result = native_vulkan_cuda_result(
            unsafe { CuStreamSynchronize(self.cuda_stream.handle) },
            "native Vulkan CUDA synchronize copy stream",
        );
        drop(uv_map);
        drop(y_map);
        sync_result?;
        Ok(())
    }

    fn shader_read_barriers(&self) -> [vk::ImageMemoryBarrier<'static>; 2] {
        [self.y.shader_read_barrier(), self.uv.shader_read_barrier()]
    }

    fn destroy(self, device: &ash::Device) {
        let _ = unsafe { CuStreamSynchronize(self.cuda_stream.handle) };
        self.uv.destroy(device);
        self.y.destroy(device);
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaVideoPlane {
    cuda_external_memory: NativeVulkanCudaExternalImageMemory,
    image: vk::Image,
    memory: vk::DeviceMemory,
    view: vk::ImageView,
    width: u32,
    height: u32,
    channels: u32,
    bytes_per_channel: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaVideoPlane {
    #[allow(clippy::too_many_arguments)]
    fn new(
        instance: &ash::Instance,
        physical_device: vk::PhysicalDevice,
        queue: vk::Queue,
        command_pool: vk::CommandPool,
        device: &ash::Device,
        queue_family_index: u32,
        width: u32,
        height: u32,
        format: vk::Format,
        channels: u32,
        bytes_per_channel: u32,
        cuda_array_format: u32,
        label: &'static str,
    ) -> Result<Self, NativeVulkanError> {
        let handle_type = vk::ExternalMemoryHandleTypeFlags::OPAQUE_FD;
        let mut external_image_info =
            vk::ExternalMemoryImageCreateInfo::default().handle_types(handle_type);
        let image_info = vk::ImageCreateInfo::default()
            .image_type(vk::ImageType::TYPE_2D)
            .format(format)
            .extent(vk::Extent3D {
                width,
                height,
                depth: 1,
            })
            .mip_levels(1)
            .array_layers(1)
            .samples(vk::SampleCountFlags::TYPE_1)
            .tiling(vk::ImageTiling::OPTIMAL)
            .usage(vk::ImageUsageFlags::SAMPLED)
            .sharing_mode(vk::SharingMode::EXCLUSIVE)
            .initial_layout(vk::ImageLayout::UNDEFINED)
            .push_next(&mut external_image_info);
        let image = unsafe { device.create_image(&image_info, None) }.map_err(|result| {
            NativeVulkanError::Vulkan {
                operation: "vkCreateImage(video CUDA plane)",
                result,
            }
        })?;
        let requirements = unsafe { device.get_image_memory_requirements(image) };
        let memory_properties =
            unsafe { instance.get_physical_device_memory_properties(physical_device) };
        let memory_type_index = native_vulkan_memory_type_index_prefer(
            &memory_properties,
            requirements.memory_type_bits,
            vk::MemoryPropertyFlags::DEVICE_LOCAL,
            vk::MemoryPropertyFlags::empty(),
        )
        .ok_or_else(|| {
            unsafe {
                device.destroy_image(image, None);
            }
            NativeVulkanError::MissingMemoryType("video CUDA external image")
        })?;
        let mut export_info = vk::ExportMemoryAllocateInfo::default().handle_types(handle_type);
        let mut dedicated_info = vk::MemoryDedicatedAllocateInfo::default().image(image);
        let allocate_info = vk::MemoryAllocateInfo::default()
            .allocation_size(requirements.size)
            .memory_type_index(memory_type_index)
            .push_next(&mut dedicated_info)
            .push_next(&mut export_info);
        let memory = match unsafe { device.allocate_memory(&allocate_info, None) } {
            Ok(memory) => memory,
            Err(result) => {
                unsafe {
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkAllocateMemory(video CUDA plane)",
                    result,
                });
            }
        };
        if let Err(result) = unsafe { device.bind_image_memory(image, memory, 0) } {
            unsafe {
                device.free_memory(memory, None);
                device.destroy_image(image, None);
            }
            return Err(NativeVulkanError::Vulkan {
                operation: "vkBindImageMemory(video CUDA plane)",
                result,
            });
        }
        let view_info = vk::ImageViewCreateInfo::default()
            .image(image)
            .view_type(vk::ImageViewType::TYPE_2D)
            .format(format)
            .subresource_range(native_vulkan_color_subresource_range());
        let view = match unsafe { device.create_image_view(&view_info, None) } {
            Ok(view) => view,
            Err(result) => {
                unsafe {
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkCreateImageView(video CUDA plane)",
                    result,
                });
            }
        };
        let external_memory_fd = ash::khr::external_memory_fd::Device::new(instance, device);
        let fd_info = vk::MemoryGetFdInfoKHR::default()
            .memory(memory)
            .handle_type(handle_type);
        let fd = match unsafe { external_memory_fd.get_memory_fd(&fd_info) } {
            Ok(fd) => fd,
            Err(result) => {
                unsafe {
                    device.destroy_image_view(view, None);
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(NativeVulkanError::Vulkan {
                    operation: "vkGetMemoryFdKHR(video CUDA plane)",
                    result,
                });
            }
        };
        let cuda_external_memory = match NativeVulkanCudaExternalImageMemory::import_opaque_fd(
            fd,
            requirements.size,
            width,
            height,
            channels,
            cuda_array_format,
            label,
        ) {
            Ok(memory) => memory,
            Err(err) => {
                unsafe {
                    device.destroy_image_view(view, None);
                    device.free_memory(memory, None);
                    device.destroy_image(image, None);
                }
                return Err(err);
            }
        };
        if let Err(err) = native_vulkan_transition_image_to_general(
            device,
            queue,
            command_pool,
            image,
            queue_family_index,
        ) {
            unsafe {
                device.destroy_image_view(view, None);
                device.free_memory(memory, None);
                device.destroy_image(image, None);
            }
            drop(cuda_external_memory);
            return Err(err);
        }

        Ok(Self {
            cuda_external_memory,
            image,
            memory,
            view,
            width,
            height,
            channels,
            bytes_per_channel,
        })
    }

    fn shader_read_barrier(&self) -> vk::ImageMemoryBarrier<'static> {
        vk::ImageMemoryBarrier::default()
            .old_layout(vk::ImageLayout::GENERAL)
            .new_layout(vk::ImageLayout::GENERAL)
            .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .image(self.image)
            .subresource_range(native_vulkan_color_subresource_range())
            .src_access_mask(vk::AccessFlags::MEMORY_WRITE)
            .dst_access_mask(vk::AccessFlags::SHADER_READ)
    }

    fn destroy(self, device: &ash::Device) {
        drop(self.cuda_external_memory);
        unsafe {
            device.destroy_image_view(self.view, None);
            device.free_memory(self.memory, None);
            device.destroy_image(self.image, None);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_transition_image_to_general(
    device: &ash::Device,
    queue: vk::Queue,
    command_pool: vk::CommandPool,
    image: vk::Image,
    queue_family_index: u32,
) -> Result<(), NativeVulkanError> {
    let allocate_info = vk::CommandBufferAllocateInfo::default()
        .command_pool(command_pool)
        .level(vk::CommandBufferLevel::PRIMARY)
        .command_buffer_count(1);
    let command_buffer =
        unsafe { device.allocate_command_buffers(&allocate_info) }.map_err(|result| {
            NativeVulkanError::Vulkan {
                operation: "vkAllocateCommandBuffers(video image transition)",
                result,
            }
        })?[0];
    let result = unsafe {
        let begin_info = vk::CommandBufferBeginInfo::default()
            .flags(vk::CommandBufferUsageFlags::ONE_TIME_SUBMIT);
        device
            .begin_command_buffer(command_buffer, &begin_info)
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkBeginCommandBuffer(video image transition)",
                result,
            })?;
        let barrier = vk::ImageMemoryBarrier::default()
            .old_layout(vk::ImageLayout::UNDEFINED)
            .new_layout(vk::ImageLayout::GENERAL)
            .src_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .dst_queue_family_index(vk::QUEUE_FAMILY_IGNORED)
            .image(image)
            .subresource_range(native_vulkan_color_subresource_range())
            .src_access_mask(vk::AccessFlags::empty())
            .dst_access_mask(vk::AccessFlags::SHADER_READ);
        device.cmd_pipeline_barrier(
            command_buffer,
            vk::PipelineStageFlags::TOP_OF_PIPE,
            vk::PipelineStageFlags::FRAGMENT_SHADER,
            vk::DependencyFlags::empty(),
            &[],
            &[],
            &[barrier],
        );
        device
            .end_command_buffer(command_buffer)
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkEndCommandBuffer(video image transition)",
                result,
            })?;
        let command_buffers = [command_buffer];
        let submit_info = vk::SubmitInfo::default().command_buffers(&command_buffers);
        device
            .queue_submit(queue, &[submit_info], vk::Fence::null())
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkQueueSubmit(video image transition)",
                result,
            })?;
        device
            .queue_wait_idle(queue)
            .map_err(|result| NativeVulkanError::Vulkan {
                operation: "vkQueueWaitIdle(video image transition)",
                result,
            })
    };
    unsafe {
        device.free_command_buffers(command_pool, &[command_buffer]);
    }
    let _ = queue_family_index;
    result
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_memory_type_index_prefer(
    memory_properties: &vk::PhysicalDeviceMemoryProperties,
    memory_type_bits: u32,
    preferred: vk::MemoryPropertyFlags,
    required: vk::MemoryPropertyFlags,
) -> Option<u32> {
    let mut fallback = None;
    for (index, memory_type) in memory_properties.memory_types
        [..memory_properties.memory_type_count as usize]
        .iter()
        .enumerate()
    {
        let supported = (memory_type_bits & (1 << index)) != 0;
        if !supported || !memory_type.property_flags.contains(required) {
            continue;
        }
        let index = index as u32;
        if memory_type.property_flags.contains(preferred) {
            return Some(index);
        }
        fallback.get_or_insert(index);
    }
    fallback
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum NativeVulkanVideoSampleFormat {
    Nv12,
    P010,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoSampleFormat {
    fn from_caps_format(format: &str) -> Option<Self> {
        match format {
            "NV12" => Some(Self::Nv12),
            "P010_10LE" | "P010" => Some(Self::P010),
            _ => None,
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Nv12 => "NV12",
            Self::P010 => "P010_10LE",
        }
    }

    fn vulkan_image_format(self) -> vk::Format {
        match self {
            Self::Nv12 => vk::Format::G8_B8R8_2PLANE_420_UNORM,
            Self::P010 => vk::Format::G10X6_B10X6R10X6_2PLANE_420_UNORM_3PACK16,
        }
    }

    fn y_view_format(self) -> vk::Format {
        match self {
            Self::Nv12 => vk::Format::R8_UNORM,
            Self::P010 => vk::Format::R16_UNORM,
        }
    }

    fn uv_view_format(self) -> vk::Format {
        match self {
            Self::Nv12 => vk::Format::R8G8_UNORM,
            Self::P010 => vk::Format::R16G16_UNORM,
        }
    }

    fn bytes_per_component(self) -> u32 {
        match self {
            Self::Nv12 => 1,
            Self::P010 => 2,
        }
    }

    fn cuda_array_format(self) -> u32 {
        match self {
            Self::Nv12 => CUDA_ARRAY_FORMAT_UNSIGNED_INT8,
            Self::P010 => CUDA_ARRAY_FORMAT_UNSIGNED_INT16,
        }
    }

    fn drm_format(self) -> u32 {
        match self {
            Self::Nv12 => DRM_FORMAT_NV12,
            Self::P010 => DRM_FORMAT_P010,
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanGstSystemNv12Plane {
    offset: usize,
    stride: u32,
    height: u32,
    row_bytes: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct NativeVulkanGstSystemNv12Meta {
    format: NativeVulkanVideoSampleFormat,
    width: u32,
    height: u32,
    y: NativeVulkanGstSystemNv12Plane,
    uv: NativeVulkanGstSystemNv12Plane,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_system_yuv420_meta(
    sample: &gst::Sample,
    buffer: &gst::BufferRef,
) -> Result<NativeVulkanGstSystemNv12Meta, NativeVulkanError> {
    let meta = match native_vulkan_gst_yuv420_meta_from_video_meta(sample.caps(), buffer) {
        Ok(meta) => meta,
        Err(meta_err) => native_vulkan_gst_yuv420_meta_from_caps(sample)
            .map_err(|caps_err| NativeVulkanError::Video(format!("{meta_err};{caps_err}")))?,
    };
    Ok(meta)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_yuv420_meta_from_video_meta(
    caps: Option<&gst::CapsRef>,
    buffer: &gst::BufferRef,
) -> Result<NativeVulkanGstSystemNv12Meta, String> {
    let meta = buffer
        .meta::<gst_video::VideoMeta>()
        .ok_or_else(|| "appsink buffer has no GstVideoMeta".to_owned())?;
    let caps_format = caps
        .and_then(|caps| caps.structure(0))
        .and_then(|structure| structure.get::<String>("format").ok())
        .unwrap_or_else(|| meta.format().to_str().to_string());
    let format = NativeVulkanVideoSampleFormat::from_caps_format(&caps_format)
        .ok_or_else(|| format!("expected NV12 or P010 appsink frame, got {caps_format}"))?;
    let width = meta.width();
    let height = meta.height();
    if width == 0 || height == 0 {
        return Err("NV12 frame has zero dimension".to_owned());
    }
    if width % 2 != 0 || height % 2 != 0 {
        return Err(format!(
            "{} frame dimensions must be even, got {width}x{height}",
            format.label()
        ));
    }
    if meta.offset().len() < 2 || meta.stride().len() < 2 {
        return Err(format!(
            "{} frame needs 2 planes, got offsets={} strides={}",
            format.label(),
            meta.offset().len(),
            meta.stride().len()
        ));
    }
    let y_stride =
        native_vulkan_positive_stride(format!("{} y", format.label()), meta.stride()[0])?;
    let uv_stride =
        native_vulkan_positive_stride(format!("{} uv", format.label()), meta.stride()[1])?;
    let row_bytes = width
        .checked_mul(format.bytes_per_component())
        .ok_or_else(|| format!("{} row byte width overflow", format.label()))?;
    if y_stride < row_bytes || uv_stride < row_bytes {
        return Err(format!(
            "{} stride too small: y={y_stride} uv={uv_stride} row_bytes={row_bytes}",
            format.label()
        ));
    }
    Ok(NativeVulkanGstSystemNv12Meta {
        format,
        width,
        height,
        y: NativeVulkanGstSystemNv12Plane {
            offset: meta.offset()[0],
            stride: y_stride,
            height,
            row_bytes,
        },
        uv: NativeVulkanGstSystemNv12Plane {
            offset: meta.offset()[1],
            stride: uv_stride,
            height: height / 2,
            row_bytes,
        },
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_yuv420_meta_from_caps(
    sample: &gst::Sample,
) -> Result<NativeVulkanGstSystemNv12Meta, String> {
    let caps = sample
        .caps()
        .ok_or_else(|| "appsink sample has no caps".to_owned())?;
    let structure = caps
        .structure(0)
        .ok_or_else(|| "appsink caps has no structure".to_owned())?;
    let format = structure
        .get::<String>("format")
        .unwrap_or_else(|_| "unknown".to_owned());
    let format = NativeVulkanVideoSampleFormat::from_caps_format(&format)
        .ok_or_else(|| format!("caps fallback expected NV12 or P010, got {format}"))?;
    let width = structure
        .get::<i32>("width")
        .map_err(|_| "appsink caps missing width".to_owned())
        .and_then(|width| {
            u32::try_from(width)
                .ok()
                .filter(|width| *width > 0)
                .ok_or_else(|| "invalid appsink frame width".to_owned())
        })?;
    let height = structure
        .get::<i32>("height")
        .map_err(|_| "appsink caps missing height".to_owned())
        .and_then(|height| {
            u32::try_from(height)
                .ok()
                .filter(|height| *height > 0)
                .ok_or_else(|| "invalid appsink frame height".to_owned())
        })?;
    if width % 2 != 0 || height % 2 != 0 {
        return Err(format!(
            "{} frame dimensions must be even, got {width}x{height}",
            format.label()
        ));
    }
    let row_bytes = width
        .checked_mul(format.bytes_per_component())
        .ok_or_else(|| format!("{} row byte width overflow", format.label()))?;
    let y_size = usize::try_from(u64::from(row_bytes) * u64::from(height))
        .map_err(|_| format!("{} plane offset overflow", format.label()))?;
    Ok(NativeVulkanGstSystemNv12Meta {
        format,
        width,
        height,
        y: NativeVulkanGstSystemNv12Plane {
            offset: 0,
            stride: row_bytes,
            height,
            row_bytes,
        },
        uv: NativeVulkanGstSystemNv12Plane {
            offset: y_size,
            stride: row_bytes,
            height: height / 2,
            row_bytes,
        },
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_positive_stride(label: String, stride: i32) -> Result<u32, String> {
    u32::try_from(stride)
        .ok()
        .filter(|stride| *stride > 0)
        .ok_or_else(|| format!("{label} stride must be positive, got {stride}"))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_buffer_has_cuda_memory(buffer: &gst::BufferRef) -> bool {
    (0..buffer.n_memory()).any(|index| native_vulkan_is_cuda_memory(buffer.peek_memory(index)))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_gst_cuda_context_from_buffer(
    buffer: &gst::BufferRef,
) -> Result<*mut NativeVulkanGstCudaContext, NativeVulkanError> {
    for memory_index in 0..buffer.n_memory() {
        let memory = buffer.peek_memory(memory_index);
        if !native_vulkan_is_cuda_memory(memory) {
            continue;
        }
        let cuda_memory = memory
            .as_ptr()
            .cast_mut()
            .cast::<NativeVulkanGstCudaMemory>();
        let context = unsafe { (*cuda_memory).context };
        if !context.is_null() {
            return Ok(context);
        }
    }
    Err(NativeVulkanError::Video(
        "native Vulkan CUDA buffer has no GstCudaContext".to_owned(),
    ))
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(clippy::too_many_arguments)]
fn native_vulkan_copy_gst_cuda_plane_to_vulkan_image(
    buffer: &gst::BufferRef,
    plane_index: usize,
    plane_offset: usize,
    source_stride: u32,
    row_bytes: u32,
    height: u32,
    expected_context: *mut NativeVulkanGstCudaContext,
    stream: NativeVulkanCudaStreamHandle,
    image: &NativeVulkanCudaVideoPlane,
    label: &str,
) -> Result<NativeVulkanCudaMemoryMap, NativeVulkanError> {
    let expected_row_bytes = image
        .width
        .checked_mul(image.channels)
        .and_then(|bytes| bytes.checked_mul(image.bytes_per_channel))
        .ok_or_else(|| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} row byte overflow"))
        })?;
    if row_bytes != expected_row_bytes || height != image.height {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} plane shape mismatch: row_bytes={row_bytes} height={height} image={}x{} channels={}",
            image.width, image.height, image.channels
        )));
    }
    let plane_end = plane_offset.checked_add(1).ok_or_else(|| {
        NativeVulkanError::Video(format!("native Vulkan CUDA {label} offset overflow"))
    })?;
    let (memory_range, memory_skip) =
        buffer.find_memory(plane_offset..plane_end).ok_or_else(|| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} plane has no memory"))
        })?;
    let memory_index = memory_range.start;
    if memory_index >= buffer.n_memory() {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} memory index out of range"
        )));
    }
    let memory = buffer.peek_memory(memory_index);
    if !native_vulkan_is_cuda_memory(memory) {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} plane memory is not CUDAMemory: {}",
            native_vulkan_gst_memory_type(memory)
        )));
    }
    let cuda_memory = memory
        .as_ptr()
        .cast_mut()
        .cast::<NativeVulkanGstCudaMemory>();
    let context = unsafe { (*cuda_memory).context };
    if context != expected_context {
        return Err(NativeVulkanError::Video(format!(
            "native Vulkan CUDA {label} plane context changed"
        )));
    }
    unsafe {
        gst_cuda_memory_sync(cuda_memory);
    }
    let map = NativeVulkanCudaMemoryMap::new(memory).map_err(|err| {
        NativeVulkanError::Video(format!("native Vulkan CUDA {label} map failed: {err}"))
    })?;
    let source = map
        .device_ptr()
        .checked_add(u64::try_from(memory_skip).map_err(|_| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} memory skip too large"))
        })?)
        .ok_or_else(|| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} source overflow"))
        })?;
    let copy = NativeVulkanCudaMemcpy2D {
        src_x_in_bytes: 0,
        src_y: 0,
        src_memory_type: CUDA_MEMORYTYPE_DEVICE,
        src_host: ptr::null(),
        src_device: source,
        src_array: ptr::null_mut(),
        src_pitch: usize::try_from(source_stride).map_err(|_| {
            NativeVulkanError::Video(format!(
                "native Vulkan CUDA {label} source stride too large"
            ))
        })?,
        dst_x_in_bytes: 0,
        dst_y: 0,
        dst_memory_type: CUDA_MEMORYTYPE_ARRAY,
        dst_host: ptr::null_mut(),
        dst_device: 0,
        dst_array: image.cuda_external_memory.array,
        dst_pitch: 0,
        width_in_bytes: usize::try_from(row_bytes).map_err(|_| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} row bytes too large"))
        })?,
        height: usize::try_from(height).map_err(|_| {
            NativeVulkanError::Video(format!("native Vulkan CUDA {label} height too large"))
        })?,
    };
    native_vulkan_cuda_result(
        unsafe { CuMemcpy2DAsync(&copy, stream) },
        &format!("native Vulkan CUDA copy {label} plane {plane_index}"),
    )?;
    Ok(map)
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaMemoryMap {
    memory: *mut gst::ffi::GstMemory,
    info: gst::ffi::GstMapInfo,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaMemoryMap {
    fn new(memory: &gst::MemoryRef) -> Result<Self, String> {
        let memory_ptr = memory.as_ptr().cast_mut();
        let mut info = std::mem::MaybeUninit::<gst::ffi::GstMapInfo>::zeroed();
        let mapped =
            unsafe { gst::ffi::gst_memory_map(memory_ptr, info.as_mut_ptr(), GST_MAP_READ_CUDA) }
                != gst::glib::ffi::GFALSE;
        if !mapped {
            return Err(native_vulkan_gst_memory_type(memory));
        }
        let info = unsafe { info.assume_init() };
        if info.data.is_null() {
            unsafe {
                let mut info = info;
                gst::ffi::gst_memory_unmap(memory_ptr, &mut info);
            }
            return Err("null CUDA map pointer".to_owned());
        }
        Ok(Self {
            memory: memory_ptr,
            info,
        })
    }

    fn device_ptr(&self) -> NativeVulkanCudaDevicePtr {
        self.info.data as usize as NativeVulkanCudaDevicePtr
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
impl Drop for NativeVulkanCudaMemoryMap {
    fn drop(&mut self) {
        unsafe {
            gst::ffi::gst_memory_unmap(self.memory, &mut self.info);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanCudaExternalImageMemory {
    handle: NativeVulkanCudaExternalMemoryHandle,
    _mipmapped_array: NativeVulkanCudaMipmappedArrayHandle,
    array: NativeVulkanCudaArrayHandle,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanCudaExternalImageMemory {
    fn import_opaque_fd(
        fd: i32,
        allocation_size: u64,
        width: u32,
        height: u32,
        channels: u32,
        cuda_array_format: u32,
        label: &str,
    ) -> Result<Self, NativeVulkanError> {
        let mut external_memory = ptr::null_mut();
        let desc = NativeVulkanCudaExternalMemoryHandleDesc {
            type_: CUDA_EXTERNAL_MEMORY_HANDLE_TYPE_OPAQUE_FD,
            handle: NativeVulkanCudaExternalMemoryHandleUnion { fd },
            size: allocation_size,
            flags: 0,
            reserved: [0; 16],
        };
        native_vulkan_cuda_result(
            unsafe { CuImportExternalMemory(&mut external_memory, &desc) },
            &format!("native Vulkan CUDA import {label} Vulkan image external memory"),
        )?;
        if external_memory.is_null() {
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan CUDA imported {label} external memory is null"
            )));
        }
        let mut mipmapped_array = ptr::null_mut();
        let mipmapped_desc = NativeVulkanCudaExternalMemoryMipmappedArrayDesc {
            offset: 0,
            array_desc: NativeVulkanCudaArray3dDesc {
                width: usize::try_from(width).map_err(|_| {
                    NativeVulkanError::Video(format!("native Vulkan CUDA {label} width too large"))
                })?,
                height: usize::try_from(height).map_err(|_| {
                    NativeVulkanError::Video(format!("native Vulkan CUDA {label} height too large"))
                })?,
                depth: 0,
                format: cuda_array_format,
                num_channels: channels,
                flags: 0,
            },
            num_levels: 1,
            reserved: [0; 16],
        };
        if let Err(err) = native_vulkan_cuda_result(
            unsafe {
                CuExternalMemoryGetMappedMipmappedArray(
                    &mut mipmapped_array,
                    external_memory,
                    &mipmapped_desc,
                )
            },
            &format!("native Vulkan CUDA map {label} Vulkan image mipmapped array"),
        ) {
            let _ = unsafe { CuDestroyExternalMemory(external_memory) };
            return Err(err);
        }
        if mipmapped_array.is_null() {
            let _ = unsafe { CuDestroyExternalMemory(external_memory) };
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan CUDA mapped {label} mipmapped array is null"
            )));
        }
        let mut array = ptr::null_mut();
        if let Err(err) = native_vulkan_cuda_result(
            unsafe { cuMipmappedArrayGetLevel(&mut array, mipmapped_array, 0) },
            &format!("native Vulkan CUDA get {label} mipmapped array level 0"),
        ) {
            let _ = unsafe { CuDestroyExternalMemory(external_memory) };
            return Err(err);
        }
        if array.is_null() {
            let _ = unsafe { CuDestroyExternalMemory(external_memory) };
            return Err(NativeVulkanError::Video(format!(
                "native Vulkan CUDA {label} CUDA array level is null"
            )));
        }
        Ok(Self {
            handle: external_memory,
            _mipmapped_array: mipmapped_array,
            array,
        })
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
impl Drop for NativeVulkanCudaExternalImageMemory {
    fn drop(&mut self) {
        if !self.handle.is_null() {
            let _ = unsafe { CuDestroyExternalMemory(self.handle) };
        }
    }
}

