#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone)]
struct NativeVulkanVideoBitstreamRing {
    capacity_bytes: u64,
    min_offset_alignment: u64,
    min_size_alignment: u64,
    cursor: u64,
    wrap_count: u32,
    allocation_count: u64,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanVideoBitstreamRing {
    fn new(plan: &NativeVulkanH265ReadyPrefixStreamingBitstreamPlan) -> Self {
        Self {
            capacity_bytes: plan.ring_capacity_bytes,
            min_offset_alignment: plan.min_offset_alignment.max(1),
            min_size_alignment: plan.min_size_alignment.max(1),
            cursor: 0,
            wrap_count: 0,
            allocation_count: 0,
        }
    }

    fn allocate(
        &mut self,
        payload_bytes: u64,
        slice_segment_offset: u32,
    ) -> Result<NativeVulkanH265ReadyPrefixBitstreamSpan, NativeVulkanError> {
        let range = native_vulkan_align_up(payload_bytes, self.min_size_alignment);
        if range == 0 {
            return Err(NativeVulkanError::Video(
                "bitstream ring cannot allocate an empty access unit".to_owned(),
            ));
        }
        if range > self.capacity_bytes {
            return Err(NativeVulkanError::Video(format!(
                "bitstream ring allocation range {range} exceeds capacity {}",
                self.capacity_bytes
            )));
        }

        let mut offset = native_vulkan_align_up(self.cursor, self.min_offset_alignment);
        if offset
            .checked_add(range)
            .ok_or_else(|| NativeVulkanError::Video("bitstream ring range overflow".to_owned()))?
            > self.capacity_bytes
        {
            offset = 0;
            self.wrap_count = self.wrap_count.saturating_add(1);
        }
        let end = offset
            .checked_add(range)
            .ok_or_else(|| NativeVulkanError::Video("bitstream ring range overflow".to_owned()))?;
        if end > self.capacity_bytes {
            return Err(NativeVulkanError::Video(format!(
                "bitstream ring allocation {offset}..{end} exceeds capacity {}",
                self.capacity_bytes
            )));
        }

        let span = NativeVulkanH265ReadyPrefixBitstreamSpan {
            offset,
            range,
            payload_bytes,
            slice_segment_offset,
            ring_allocation_index: self.allocation_count,
            ring_wrap_count: self.wrap_count,
        };
        self.cursor = end;
        self.allocation_count = self.allocation_count.saturating_add(1);
        Ok(span)
    }

    fn allocate_h264(
        &mut self,
        payload_bytes: u64,
        slice_offsets: Vec<u32>,
    ) -> Result<NativeVulkanH264ReadyPrefixBitstreamSpan, NativeVulkanError> {
        let range = native_vulkan_align_up(payload_bytes, self.min_size_alignment);
        if range == 0 {
            return Err(NativeVulkanError::Video(
                "H.264 bitstream ring cannot allocate an empty access unit".to_owned(),
            ));
        }
        if range > self.capacity_bytes {
            return Err(NativeVulkanError::Video(format!(
                "H.264 bitstream ring allocation range {range} exceeds capacity {}",
                self.capacity_bytes
            )));
        }

        let mut offset = native_vulkan_align_up(self.cursor, self.min_offset_alignment);
        if offset.checked_add(range).ok_or_else(|| {
            NativeVulkanError::Video("H.264 bitstream ring range overflow".to_owned())
        })? > self.capacity_bytes
        {
            offset = 0;
            self.wrap_count = self.wrap_count.saturating_add(1);
        }
        let end = offset.checked_add(range).ok_or_else(|| {
            NativeVulkanError::Video("H.264 bitstream ring range overflow".to_owned())
        })?;
        if end > self.capacity_bytes {
            return Err(NativeVulkanError::Video(format!(
                "H.264 bitstream ring allocation {offset}..{end} exceeds capacity {}",
                self.capacity_bytes
            )));
        }

        let span = NativeVulkanH264ReadyPrefixBitstreamSpan {
            offset,
            range,
            payload_bytes,
            slice_offsets,
            ring_allocation_index: self.allocation_count,
            ring_wrap_count: self.wrap_count,
        };
        self.cursor = end;
        self.allocation_count = self.allocation_count.saturating_add(1);
        Ok(span)
    }

    fn wrap_count(&self) -> u32 {
        self.wrap_count
    }
}

fn native_vulkan_create_video_decode_status_query_pool(
    device: &ash::Device,
    profile_info: &vk::VideoProfileInfoKHR<'_>,
    query_count: u32,
) -> Result<vk::QueryPool, NativeVulkanError> {
    let mut query_profile_info = *profile_info;
    let query_pool_info = vk::QueryPoolCreateInfo::default()
        .query_type(vk::QueryType::RESULT_STATUS_ONLY_KHR)
        .query_count(query_count)
        .push_next(&mut query_profile_info);
    unsafe { device.create_query_pool(&query_pool_info, None) }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: "vkCreateQueryPool(video decode status)",
            result,
        }
    })
}

fn native_vulkan_video_decode_status_query_results(
    device: &ash::Device,
    query_pool: vk::QueryPool,
    query_count: u32,
) -> Result<Vec<vk::QueryResultStatusKHR>, NativeVulkanError> {
    let mut results = vec![vk::QueryResultStatusKHR::NOT_READY; query_count as usize];
    unsafe {
        device.get_query_pool_results(
            query_pool,
            0,
            &mut results,
            vk::QueryResultFlags::WAIT | vk::QueryResultFlags::WITH_STATUS_KHR,
        )
    }
    .map_err(|result| NativeVulkanError::Vulkan {
        operation: "vkGetQueryPoolResults(video decode status)",
        result,
    })?;
    Ok(results)
}

fn native_vulkan_query_result_status_label(status: vk::QueryResultStatusKHR) -> &'static str {
    if status == vk::QueryResultStatusKHR::COMPLETE {
        "complete"
    } else if status == vk::QueryResultStatusKHR::NOT_READY {
        "not-ready"
    } else if status == vk::QueryResultStatusKHR::ERROR {
        "error"
    } else if status == vk::QueryResultStatusKHR::INSUFFICIENTSTREAM_BUFFER_RANGE {
        "insufficient-bitstream-buffer-range"
    } else if status.as_raw() < 0 {
        "error-other"
    } else {
        "unknown-positive"
    }
}

fn native_vulkan_apply_decode_query_status(
    frame: &mut NativeVulkanH265DecodedFrameSnapshot,
    status: vk::QueryResultStatusKHR,
) {
    frame.decode_query_status_raw = Some(status.as_raw());
    frame.decode_query_status = Some(native_vulkan_query_result_status_label(status));
}

fn native_vulkan_video_session_smoke_inner(
    entry: &ash::Entry,
    instance: &ash::Instance,
    options: NativeVulkanVideoSessionSmokeOptions,
) -> Result<NativeVulkanVideoSessionSmokeSnapshot, NativeVulkanError> {
    let video_queue_loader = ash::khr::video_queue::Instance::new(entry, instance);
    let selection = select_native_vulkan_video_decode_queue(instance, options.codec)?;

    match options.codec {
        NativeVulkanVideoSessionCodec::H264High8 => {
            let mut h264_profile_info = vk::VideoDecodeH264ProfileInfoKHR::default()
                .std_profile_idc(options.codec.h264_std_profile_idc().ok_or_else(|| {
                    NativeVulkanError::Video(format!(
                        "{} is not an H.264 Vulkan Video codec",
                        options.codec.label()
                    ))
                })?)
                .picture_layout(vk::VideoDecodeH264PictureLayoutFlagsKHR::PROGRESSIVE);
            let profile_info = vk::VideoProfileInfoKHR::default()
                .video_codec_operation(options.codec.codec_operation())
                .chroma_subsampling(vk::VideoChromaSubsamplingFlagsKHR::TYPE_420)
                .luma_bit_depth(options.codec.bit_depth_flags())
                .chroma_bit_depth(options.codec.bit_depth_flags())
                .push_next(&mut h264_profile_info);
            let capabilities = native_vulkan_video_session_h264_capabilities(
                &video_queue_loader,
                selection.physical_device,
                &profile_info,
            )?;
            native_vulkan_video_session_create_and_bind(
                &video_queue_loader,
                instance,
                selection,
                options,
                &profile_info,
                capabilities,
            )
        }
        NativeVulkanVideoSessionCodec::H265Main8 | NativeVulkanVideoSessionCodec::H265Main10 => {
            let mut h265_profile_info = vk::VideoDecodeH265ProfileInfoKHR::default()
                .std_profile_idc(options.codec.h265_std_profile_idc().ok_or_else(|| {
                    NativeVulkanError::Video(format!(
                        "{} is not an H.265 Vulkan Video codec",
                        options.codec.label()
                    ))
                })?);
            let profile_info = vk::VideoProfileInfoKHR::default()
                .video_codec_operation(options.codec.codec_operation())
                .chroma_subsampling(vk::VideoChromaSubsamplingFlagsKHR::TYPE_420)
                .luma_bit_depth(options.codec.bit_depth_flags())
                .chroma_bit_depth(options.codec.bit_depth_flags())
                .push_next(&mut h265_profile_info);
            let capabilities = native_vulkan_video_session_h265_capabilities(
                &video_queue_loader,
                selection.physical_device,
                &profile_info,
            )?;
            native_vulkan_video_session_create_and_bind(
                &video_queue_loader,
                instance,
                selection,
                options,
                &profile_info,
                capabilities,
            )
        }
        NativeVulkanVideoSessionCodec::Av1Main8 | NativeVulkanVideoSessionCodec::Av1Main10 => {
            let mut av1_profile_info = vk::VideoDecodeAV1ProfileInfoKHR::default()
                .std_profile(options.codec.av1_std_profile().ok_or_else(|| {
                    NativeVulkanError::Video(format!(
                        "{} is not an AV1 Vulkan Video codec",
                        options.codec.label()
                    ))
                })?)
                .film_grain_support(false);
            let profile_info = vk::VideoProfileInfoKHR::default()
                .video_codec_operation(options.codec.codec_operation())
                .chroma_subsampling(vk::VideoChromaSubsamplingFlagsKHR::TYPE_420)
                .luma_bit_depth(options.codec.bit_depth_flags())
                .chroma_bit_depth(options.codec.bit_depth_flags())
                .push_next(&mut av1_profile_info);
            let capabilities = native_vulkan_video_session_av1_capabilities(
                &video_queue_loader,
                selection.physical_device,
                &profile_info,
            )?;
            native_vulkan_video_session_create_and_bind(
                &video_queue_loader,
                instance,
                selection,
                options,
                &profile_info,
                capabilities,
            )
        }
    }
}

fn select_native_vulkan_video_decode_queue(
    instance: &ash::Instance,
    codec: NativeVulkanVideoSessionCodec,
) -> Result<NativeVulkanVideoDecodeQueueSelection, NativeVulkanError> {
    let physical_devices = unsafe { instance.enumerate_physical_devices() }.map_err(|result| {
        NativeVulkanError::Vulkan {
            operation: "vkEnumeratePhysicalDevices",
            result,
        }
    })?;
    let required_extensions = native_vulkan_video_session_required_device_extensions(codec);
    let mut selected = None::<NativeVulkanVideoDecodeQueueSelection>;

    for (physical_device_index, physical_device) in physical_devices.iter().copied().enumerate() {
        let extensions = native_vulkan_device_extension_names(instance, physical_device)?;
        if !required_extensions.iter().all(|extension| {
            native_vulkan_extension_available_by_name(&extensions, ash_extension_name(extension))
        }) {
            continue;
        }

        let properties = unsafe { instance.get_physical_device_properties(physical_device) };
        let queue_families =
            native_vulkan_video_decode_queue_family_infos(instance, physical_device);
        for queue_family in queue_families {
            if queue_family.queue_count == 0
                || !queue_family
                    .queue_flags
                    .contains(vk::QueueFlags::VIDEO_DECODE_KHR)
                || !queue_family
                    .video_codec_operations
                    .contains(codec.codec_operation())
            {
                continue;
            }

            let candidate = NativeVulkanVideoDecodeQueueSelection {
                physical_device,
                physical_device_index,
                physical_device_name: native_vulkan_physical_device_name(properties),
                physical_device_type: native_vulkan_physical_device_type_label(
                    properties.device_type,
                ),
                properties,
                queue_family_index: queue_family.queue_family_index,
                queue_count: queue_family.queue_count,
                queue_flags: queue_family.queue_flags,
                video_codec_operations: queue_family.video_codec_operations,
                query_result_status_support: queue_family.query_result_status_support,
            };
            let prefer_candidate = selected.as_ref().is_none_or(|current| {
                properties.device_type == vk::PhysicalDeviceType::DISCRETE_GPU
                    && current.properties.device_type != vk::PhysicalDeviceType::DISCRETE_GPU
            });
            if prefer_candidate {
                selected = Some(candidate);
            }
        }
    }

    selected.ok_or_else(|| {
        NativeVulkanError::Video(format!(
            "no Vulkan device exposes {} with a matching video decode queue",
            codec.label()
        ))
    })
}

#[derive(Clone, Copy)]
struct NativeVulkanVideoDecodeQueueFamilyInfo {
    queue_family_index: u32,
    queue_count: u32,
    queue_flags: vk::QueueFlags,
    video_codec_operations: vk::VideoCodecOperationFlagsKHR,
    query_result_status_support: bool,
}

fn native_vulkan_video_decode_queue_family_infos(
    instance: &ash::Instance,
    physical_device: vk::PhysicalDevice,
) -> Vec<NativeVulkanVideoDecodeQueueFamilyInfo> {
    let queue_family_count =
        unsafe { instance.get_physical_device_queue_family_properties2_len(physical_device) };
    let mut queue_properties = vec![vk::QueueFamilyProperties2::default(); queue_family_count];
    let mut video_properties =
        vec![vk::QueueFamilyVideoPropertiesKHR::default(); queue_family_count];
    let mut query_result_status_properties =
        vec![vk::QueueFamilyQueryResultStatusPropertiesKHR::default(); queue_family_count];
    for ((queue, video), query_result) in queue_properties
        .iter_mut()
        .zip(video_properties.iter_mut())
        .zip(query_result_status_properties.iter_mut())
    {
        query_result.p_next = (video as *mut vk::QueueFamilyVideoPropertiesKHR<'_>).cast();
        queue.p_next =
            (query_result as *mut vk::QueueFamilyQueryResultStatusPropertiesKHR<'_>).cast();
    }
    unsafe {
        instance
            .get_physical_device_queue_family_properties2(physical_device, &mut queue_properties);
    }

    queue_properties
        .iter()
        .zip(video_properties.iter())
        .zip(query_result_status_properties.iter())
        .enumerate()
        .map(|(queue_family_index, ((queue, video), query_result))| {
            NativeVulkanVideoDecodeQueueFamilyInfo {
                queue_family_index: queue_family_index as u32,
                queue_count: queue.queue_family_properties.queue_count,
                queue_flags: queue.queue_family_properties.queue_flags,
                video_codec_operations: video.video_codec_operations,
                query_result_status_support: query_result.query_result_status_support != 0,
            }
        })
        .collect()
}

fn native_vulkan_graphics_queue_family_index(
    instance: &ash::Instance,
    physical_device: vk::PhysicalDevice,
    preferred_queue_family_index: u32,
) -> Result<u32, NativeVulkanError> {
    let queue_families =
        unsafe { instance.get_physical_device_queue_family_properties(physical_device) };
    if queue_families
        .get(preferred_queue_family_index as usize)
        .is_some_and(|queue_family| {
            queue_family.queue_count > 0
                && queue_family.queue_flags.contains(vk::QueueFlags::GRAPHICS)
        })
    {
        return Ok(preferred_queue_family_index);
    }
    queue_families
        .iter()
        .enumerate()
        .find_map(|(queue_family_index, queue_family)| {
            (queue_family.queue_count > 0
                && queue_family.queue_flags.contains(vk::QueueFlags::GRAPHICS))
            .then_some(queue_family_index as u32)
        })
        .ok_or_else(|| {
            NativeVulkanError::Video(
                "decoded first-frame sampling requires a graphics-capable queue family".to_owned(),
            )
        })
}

fn native_vulkan_video_session_required_device_extensions(
    codec: NativeVulkanVideoSessionCodec,
) -> Vec<&'static CStr> {
    vec![
        vk::KHR_VIDEO_QUEUE_NAME,
        vk::KHR_VIDEO_DECODE_QUEUE_NAME,
        codec.codec_extension_name(),
    ]
}

fn native_vulkan_video_session_h264_capabilities(
    video_queue_loader: &ash::khr::video_queue::Instance,
    physical_device: vk::PhysicalDevice,
    profile_info: &vk::VideoProfileInfoKHR<'_>,
) -> Result<NativeVulkanVideoSessionCapabilityQuery, NativeVulkanError> {
    let mut h264_capabilities = vk::VideoDecodeH264CapabilitiesKHR::default();
    let mut decode_capabilities = vk::VideoDecodeCapabilitiesKHR::default();
    let mut capabilities = vk::VideoCapabilitiesKHR::default()
        .push_next(&mut h264_capabilities)
        .push_next(&mut decode_capabilities);

    unsafe {
        (video_queue_loader
            .fp()
            .get_physical_device_video_capabilities_khr)(
            physical_device,
            profile_info,
            &mut capabilities,
        )
    }
    .result()
    .map_err(|result| NativeVulkanError::Vulkan {
        operation: "vkGetPhysicalDeviceVideoCapabilitiesKHR(h264 session)",
        result,
    })?;

    let capability_flags = capabilities.flags;
    let min_bitstream_buffer_offset_alignment = capabilities.min_bitstream_buffer_offset_alignment;
    let min_bitstream_buffer_size_alignment = capabilities.min_bitstream_buffer_size_alignment;
    let picture_access_granularity = capabilities.picture_access_granularity;
    let min_coded_extent = capabilities.min_coded_extent;
    let max_coded_extent = capabilities.max_coded_extent;
    let max_dpb_slots = capabilities.max_dpb_slots;
    let max_active_reference_pictures = capabilities.max_active_reference_pictures;
    let std_header_version = capabilities.std_header_version;
    let decode_capability_flags = decode_capabilities.flags;
    let codec_max_level =
        native_vulkan_h264_level_label(h264_capabilities.max_level_idc).map(str::to_owned);

    Ok(NativeVulkanVideoSessionCapabilityQuery {
        capability_flags,
        min_bitstream_buffer_offset_alignment,
        min_bitstream_buffer_size_alignment,
        picture_access_granularity,
        min_coded_extent,
        max_coded_extent,
        max_dpb_slots,
        max_active_reference_pictures,
        decode_capability_flags,
        codec_max_level,
        std_header_version,
    })
}

