#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_access_unit_snapshot(
    index: u32,
    access_unit: &NativeVulkanH264AccessUnitExtract,
    parameter_sets: &NativeVulkanH264ParameterSetSnapshot,
) -> NativeVulkanH264AccessUnitSnapshot {
    let first_frame = native_vulkan_h264_picture_decode_info(&access_unit.bytes, parameter_sets);
    let (first_slice, first_slice_parse_error) = match first_frame {
        Ok(first_frame) => (
            Some(NativeVulkanH264AccessUnitSliceSnapshot {
                nal_type: first_frame.nal_type,
                nal_type_label: first_frame.nal_type_label,
                nal_ref_idc: first_frame.nal_ref_idc,
                first_mb_in_slice: first_frame.first_mb_in_slice,
                first_slice_segment_in_pic_flag: first_frame.first_slice_segment_in_pic_flag,
                slice_type: first_frame.slice_type,
                slice_type_normalized: first_frame.slice_type_normalized,
                pps_id: first_frame.pps_id,
                frame_num: first_frame.frame_num,
                idr_pic_id: first_frame.idr_pic_id,
                num_ref_idx_l0_active_minus1: first_frame.num_ref_idx_l0_active_minus1,
                num_ref_idx_l1_active_minus1: first_frame.num_ref_idx_l1_active_minus1,
                ref_pic_list_modification_l0: first_frame.ref_pic_list_modification_l0,
                ref_pic_list_modifications_l0: first_frame.ref_pic_list_modifications_l0,
                ref_pic_list_modification_l1: first_frame.ref_pic_list_modification_l1,
                ref_pic_list_modifications_l1: first_frame.ref_pic_list_modifications_l1,
                adaptive_ref_pic_marking_mode_flag: first_frame.adaptive_ref_pic_marking_mode_flag,
                memory_management_control_operations: first_frame
                    .memory_management_control_operations,
                field_pic_flag: first_frame.field_pic_flag,
                bottom_field_flag: first_frame.bottom_field_flag,
                is_reference: first_frame.is_reference,
                is_intra: first_frame.is_intra,
                is_p: first_frame.is_p,
                is_b: first_frame.is_b,
                long_term_reference_flag: first_frame.long_term_reference_flag,
                pic_order_cnt: first_frame.pic_order_cnt,
                slice_offsets: first_frame.slice_offsets,
                idr: first_frame.idr,
                irap: first_frame.irap,
            }),
            None,
        ),
        Err(err) => (None, Some(err)),
    };
    let idr_decode_ready = first_slice.as_ref().is_some_and(|slice| {
        slice.idr
            && slice.irap
            && slice.is_intra
            && !slice.field_pic_flag
            && !slice.slice_offsets.is_empty()
    });
    let decode_ready = first_slice.as_ref().is_some_and(|slice| {
        let active_l0_refs = slice
            .num_ref_idx_l0_active_minus1
            .map(|value| value.saturating_add(1))
            .unwrap_or(0);
        !slice.field_pic_flag
            && slice.is_reference
            && !slice.slice_offsets.is_empty()
            && !slice.is_b
            && !slice.long_term_reference_flag
            && native_vulkan_h264_ref_pic_list_modifications_supported(slice)
            && !slice.adaptive_ref_pic_marking_mode_flag
            && (slice.is_intra || (slice.is_p && active_l0_refs > 0))
    });

    NativeVulkanH264AccessUnitSnapshot {
        index,
        bytes: access_unit.stats.bytes,
        byte_hash: native_vulkan_stable_byte_hash(&access_unit.bytes),
        pts_ms: access_unit.pts_ms,
        duration_ms: access_unit.duration_ms,
        has_annex_b_start_codes: access_unit.stats.has_annex_b_start_codes,
        has_parameter_sets: access_unit.stats.parameter_sets_present(),
        h264_sps_count: access_unit.stats.sps_count,
        h264_pps_count: access_unit.stats.pps_count,
        h264_idr_count: access_unit.stats.idr_count,
        h264_slice_count: access_unit.stats.slice_count,
        first_slice,
        first_slice_parse_error,
        idr_decode_ready,
        decode_ready,
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_access_unit_from_sample(
    sample: &gst::Sample,
) -> Result<NativeVulkanH265AccessUnitExtract, NativeVulkanError> {
    let buffer = sample.buffer().ok_or_else(|| {
        NativeVulkanError::Video("H.265 bitstream sample has no buffer".to_owned())
    })?;
    let map = buffer.map_readable().map_err(|_| {
        NativeVulkanError::Video("H.265 bitstream buffer map_readable failed".to_owned())
    })?;
    let bytes = map.as_slice().to_vec();
    if bytes.is_empty() {
        return Err(NativeVulkanError::Video(
            "H.265 bitstream sample is empty".to_owned(),
        ));
    }
    let stats = native_vulkan_h265_nal_stats(&bytes);
    let metadata = native_vulkan_h265_access_unit_metadata_from_sample(sample, buffer);

    Ok(NativeVulkanH265AccessUnitExtract {
        bytes,
        pts_ms: metadata.pts_ms,
        duration_ms: metadata.duration_ms,
        caps: metadata.caps,
        stream_format: metadata.stream_format,
        alignment: metadata.alignment,
        width: metadata.width,
        height: metadata.height,
        framerate: metadata.framerate,
        stats,
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_access_unit_metadata_from_sample(
    sample: &gst::Sample,
    buffer: &gst::BufferRef,
) -> NativeVulkanH265AccessUnitSampleMetadata {
    let mut stream_format = None;
    let mut alignment = None;
    let mut width = None;
    let mut height = None;
    let mut framerate = None;
    let caps = sample.caps().map(|caps| {
        if let Some(structure) = caps.structure(0) {
            stream_format = structure.get::<String>("stream-format").ok();
            alignment = structure.get::<String>("alignment").ok();
            width = structure
                .get::<i32>("width")
                .ok()
                .and_then(|width| u32::try_from(width).ok());
            height = structure
                .get::<i32>("height")
                .ok()
                .and_then(|height| u32::try_from(height).ok());
            framerate = structure
                .get::<gst::Fraction>("framerate")
                .ok()
                .map(|value| value.to_string());
        }
        caps.to_string()
    });

    NativeVulkanH265AccessUnitSampleMetadata {
        pts_ms: native_vulkan_clock_time_ms(buffer.pts()),
        duration_ms: native_vulkan_clock_time_ms(buffer.duration()),
        caps,
        stream_format,
        alignment,
        width,
        height,
        framerate,
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_access_unit_snapshot(
    index: u32,
    access_unit: &NativeVulkanH265AccessUnitExtract,
    parameter_sets: &NativeVulkanH265ParameterSetSnapshot,
) -> NativeVulkanH265AccessUnitSnapshot {
    let first_slice_result =
        native_vulkan_h265_first_slice_probe_snapshot(&access_unit.bytes, parameter_sets);
    let (first_slice, first_slice_parse_error) = match first_slice_result {
        Ok(snapshot) => (Some(snapshot), None),
        Err(err) => (None, Some(err)),
    };
    NativeVulkanH265AccessUnitSnapshot {
        index,
        bytes: access_unit.stats.bytes,
        byte_hash: native_vulkan_stable_byte_hash(&access_unit.bytes),
        pts_ms: access_unit.pts_ms,
        duration_ms: access_unit.duration_ms,
        has_annex_b_start_codes: access_unit.stats.has_annex_b_start_codes,
        has_parameter_sets: access_unit.stats.parameter_sets_present(),
        h265_vps_count: access_unit.stats.vps_count,
        h265_sps_count: access_unit.stats.sps_count,
        h265_pps_count: access_unit.stats.pps_count,
        h265_idr_count: access_unit.stats.idr_count,
        h265_slice_count: access_unit.stats.slice_count,
        first_slice,
        first_slice_parse_error,
    }
}

#[cfg(any(feature = "native-vulkan-gst-video", test))]
fn native_vulkan_h265_sps_short_term_ref_pic_sets_supported(
    ref_pic_sets: &[NativeVulkanH265ShortTermRefPicSetSnapshot],
) -> bool {
    ref_pic_sets.iter().all(|ref_pic_set| {
        !ref_pic_set.inter_ref_pic_set_prediction_flag
            && ref_pic_set.num_negative_pics <= 16
            && ref_pic_set.num_positive_pics <= 16
            && ref_pic_set
                .negative_delta_pocs
                .iter()
                .chain(ref_pic_set.positive_delta_pocs.iter())
                .all(|delta_poc| delta_poc.unsigned_abs() <= u16::MAX as u32)
    })
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_streaming_packet_queue_capacity(requested_frame_count: u32) -> usize {
    std::env::var("GILDER_VULKAN_H264_PACKET_QUEUE_CAPACITY")
        .ok()
        .and_then(|value| value.parse::<usize>().ok())
        .filter(|value| *value > 0)
        .unwrap_or_else(|| requested_frame_count.clamp(8, 32) as usize)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_streaming_packet_queue_capacity(requested_frame_count: u32) -> usize {
    std::env::var("GILDER_VULKAN_H265_PACKET_QUEUE_CAPACITY")
        .ok()
        .and_then(|value| value.parse::<usize>().ok())
        .filter(|value| *value > 0)
        .unwrap_or_else(|| requested_frame_count.clamp(8, 32) as usize)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_sps_max_frame_num(sps: &NativeVulkanH264SpsSnapshot) -> u32 {
    1u32.checked_shl(sps.log2_max_frame_num_minus4.saturating_add(4))
        .unwrap_or(u32::MAX)
        .max(1)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_sps_max_pic_order_cnt_lsb(sps: &NativeVulkanH265SpsSnapshot) -> u32 {
    1u32.checked_shl(sps.log2_max_pic_order_cnt_lsb_minus4.saturating_add(4))
        .unwrap_or(u32::MAX)
        .max(1)
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum NativeVulkanH264ReferenceListEntry {
    ShortTerm(u16),
    LongTerm(u16),
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum NativeVulkanH264DpbSlotKey {
    ShortTerm(u16),
    LongTerm(u16),
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Copy)]
struct NativeVulkanH264DpbReferenceState {
    source_access_unit_index: Option<u32>,
    dpb_slot: u32,
    pic_order_cnt_val: i32,
    frame_num: u16,
    non_existing: bool,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Default)]
struct NativeVulkanH264InferredNonExistingPlan {
    frame_nums: Vec<u16>,
    references: Vec<NativeVulkanH264InferredNonExistingReferenceSnapshot>,
    dropped_short_term_frame_nums: Vec<u16>,
    dropped_long_term_frame_indices: Vec<u16>,
    dropped_reference_slots: Vec<u32>,
}

#[cfg(feature = "native-vulkan-gst-video")]
#[derive(Debug, Clone, Default)]
struct NativeVulkanH264AdaptiveMarkingPlan {
    drop_short_term_frame_nums: Vec<u16>,
    drop_long_term_frame_indices: Vec<u16>,
    convert_short_term_to_long_term: Vec<(u16, u16)>,
    current_long_term_frame_idx: Option<u16>,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_short_term_pic_num(
    frame_num: u16,
    current_frame_num: u16,
    max_frame_num: u32,
) -> i32 {
    let max_frame_num = i32::try_from(max_frame_num.max(1)).unwrap_or(i32::MAX);
    let frame_num = i32::from(frame_num);
    let current_frame_num = i32::from(current_frame_num);
    if frame_num > current_frame_num {
        frame_num.saturating_sub(max_frame_num)
    } else {
        frame_num
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_find_short_term_reference_by_pic_num(
    short_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    current_frame_num: u16,
    max_frame_num: u32,
    pic_num: i32,
) -> Option<(u16, &NativeVulkanH264DpbReferenceState)> {
    short_term_references
        .iter()
        .find(|(frame_num, _)| {
            native_vulkan_h264_short_term_pic_num(**frame_num, current_frame_num, max_frame_num)
                == pic_num
        })
        .map(|(frame_num, reference)| (*frame_num, reference))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_ref_pic_list_modifications_supported(
    slice: &NativeVulkanH264AccessUnitSliceSnapshot,
) -> bool {
    native_vulkan_h264_ref_pic_list_modification_items_supported(
        &slice.ref_pic_list_modifications_l0,
    ) && native_vulkan_h264_ref_pic_list_modification_items_supported(
        &slice.ref_pic_list_modifications_l1,
    )
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_ref_pic_list_modification_items_supported(
    modifications: &[NativeVulkanH264RefPicListModificationSnapshot],
) -> bool {
    modifications
        .iter()
        .all(|modification| matches!(modification.modification_of_pic_nums_idc, 0 | 1 | 2))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_apply_ref_pic_list_modifications(
    entries: &mut Vec<NativeVulkanH264ReferenceListEntry>,
    modifications: &[NativeVulkanH264RefPicListModificationSnapshot],
    current_frame_num: u16,
    short_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    long_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    planned_output_slot: u32,
    max_frame_num: u32,
    list_label: &'static str,
) -> Result<(), String> {
    if modifications.is_empty() {
        return Ok(());
    }

    let max_frame_num = i64::from(max_frame_num.max(1));
    let current_frame_num_i64 = i64::from(current_frame_num);
    let mut pic_num_lx_pred = current_frame_num_i64;
    let mut insertion_index = 0usize;
    for modification in modifications {
        let entry = match modification.modification_of_pic_nums_idc {
            0 | 1 => {
                let diff = modification
                    .abs_diff_pic_num_minus1
                    .ok_or_else(|| {
                        "H.264 short-term ref list modification is missing abs_diff_pic_num_minus1"
                            .to_owned()
                    })?
                    .saturating_add(1);
                let diff = i64::from(diff);
                let pic_num_lx_no_wrap = if modification.modification_of_pic_nums_idc == 0 {
                    let candidate = pic_num_lx_pred - diff;
                    if candidate < 0 {
                        candidate + max_frame_num
                    } else {
                        candidate
                    }
                } else {
                    let value = pic_num_lx_pred + diff;
                    if value >= max_frame_num {
                        value - max_frame_num
                    } else {
                        value
                    }
                };
                pic_num_lx_pred = pic_num_lx_no_wrap;
                let pic_num_lx = if pic_num_lx_no_wrap > current_frame_num_i64 {
                    pic_num_lx_no_wrap.saturating_sub(max_frame_num)
                } else {
                    pic_num_lx_no_wrap
                };
                let pic_num_lx_i32 = i32::try_from(pic_num_lx).map_err(|_| {
                    format!("H.264 modified reference PicNum {pic_num_lx} exceeds i32 range")
                })?;
                let Some((frame_num, reference)) =
                    native_vulkan_h264_find_short_term_reference_by_pic_num(
                        short_term_references,
                        current_frame_num,
                        u32::try_from(max_frame_num).unwrap_or(u32::MAX),
                        pic_num_lx_i32,
                    )
                else {
                    return Err(format!(
                        "H.264 {list_label} ref list modification requested unavailable short-term PicNum {pic_num_lx}"
                    ));
                };
                if reference.dpb_slot == planned_output_slot {
                    return Err(format!(
                        "H.264 {list_label} ref list modification requested frame_num {frame_num} in the output DPB slot"
                    ));
                }
                NativeVulkanH264ReferenceListEntry::ShortTerm(frame_num)
            }
            2 => {
                let long_term_pic_num = modification
                    .long_term_pic_num
                    .ok_or_else(|| {
                        "H.264 long-term ref list modification is missing long_term_pic_num"
                            .to_owned()
                    })
                    .and_then(|value| {
                        u16::try_from(value).map_err(|_| {
                            format!("H.264 long_term_pic_num {value} exceeds supported u16 range")
                        })
                    })?;
                let Some(reference) = long_term_references.get(&long_term_pic_num) else {
                    return Err(format!(
                        "H.264 {list_label} ref list modification requested unavailable long-term pic num {long_term_pic_num}"
                    ));
                };
                if reference.dpb_slot == planned_output_slot {
                    return Err(format!(
                        "H.264 {list_label} ref list modification requested long-term pic num {long_term_pic_num} in the output DPB slot"
                    ));
                }
                NativeVulkanH264ReferenceListEntry::LongTerm(long_term_pic_num)
            }
            other => {
                return Err(format!(
                    "H.264 {list_label} ref_pic_list_modification idc {other} is not supported"
                ));
            }
        };
        entries.retain(|existing| *existing != entry);
        entries.insert(insertion_index.min(entries.len()), entry);
        insertion_index = insertion_index.saturating_add(1);
    }

    Ok(())
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_reference_frame_nums_for_slice(
    slice: &NativeVulkanH264AccessUnitSliceSnapshot,
    short_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    long_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    planned_output_slot: u32,
    max_frame_num: u32,
) -> Result<Vec<NativeVulkanH264ReferenceListEntry>, String> {
    let mut short_term_entries = short_term_references
        .iter()
        .filter(|(_, reference)| reference.dpb_slot != planned_output_slot)
        .map(|(frame_num, _)| {
            (
                *frame_num,
                native_vulkan_h264_short_term_pic_num(*frame_num, slice.frame_num, max_frame_num),
            )
        })
        .collect::<Vec<_>>();
    short_term_entries
        .sort_by(|left, right| right.1.cmp(&left.1).then_with(|| right.0.cmp(&left.0)));
    let mut entries = short_term_entries
        .into_iter()
        .map(|(frame_num, _)| NativeVulkanH264ReferenceListEntry::ShortTerm(frame_num))
        .collect::<Vec<_>>();
    entries.extend(
        long_term_references
            .iter()
            .filter(|(_, reference)| reference.dpb_slot != planned_output_slot)
            .map(|(long_term_frame_idx, _)| {
                NativeVulkanH264ReferenceListEntry::LongTerm(*long_term_frame_idx)
            }),
    );

    native_vulkan_h264_apply_ref_pic_list_modifications(
        &mut entries,
        &slice.ref_pic_list_modifications_l0,
        slice.frame_num,
        short_term_references,
        long_term_references,
        planned_output_slot,
        max_frame_num,
        "L0",
    )?;
    Ok(entries)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_b_reference_frame_nums_for_slice(
    slice: &NativeVulkanH264AccessUnitSliceSnapshot,
    short_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    long_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    planned_output_slot: u32,
    max_frame_num: u32,
) -> Result<Vec<NativeVulkanH264ReferenceListEntry>, String> {
    let current_poc = slice.pic_order_cnt[0];
    let l0_count = slice
        .num_ref_idx_l0_active_minus1
        .map(|value| value.saturating_add(1))
        .unwrap_or(0) as usize;
    let l1_count = slice
        .num_ref_idx_l1_active_minus1
        .map(|value| value.saturating_add(1))
        .unwrap_or(0) as usize;
    let mut before = short_term_references
        .iter()
        .filter_map(|(frame_num, reference)| {
            (reference.pic_order_cnt_val < current_poc)
                .then_some((*frame_num, reference.pic_order_cnt_val))
        })
        .collect::<Vec<_>>();
    before.sort_by(|left, right| right.1.cmp(&left.1).then_with(|| right.0.cmp(&left.0)));
    let mut after = short_term_references
        .iter()
        .filter_map(|(frame_num, reference)| {
            (reference.pic_order_cnt_val > current_poc)
                .then_some((*frame_num, reference.pic_order_cnt_val))
        })
        .collect::<Vec<_>>();
    after.sort_by(|left, right| left.1.cmp(&right.1).then_with(|| left.0.cmp(&right.0)));
    let long_term_entries = long_term_references
        .iter()
        .filter(|(_, reference)| reference.dpb_slot != planned_output_slot)
        .map(|(long_term_frame_idx, _)| {
            NativeVulkanH264ReferenceListEntry::LongTerm(*long_term_frame_idx)
        })
        .collect::<Vec<_>>();

    let mut l0 = before
        .iter()
        .chain(after.iter())
        .map(|(frame_num, _)| NativeVulkanH264ReferenceListEntry::ShortTerm(*frame_num))
        .chain(long_term_entries.iter().copied())
        .collect::<Vec<_>>();
    let mut l1 = after
        .iter()
        .chain(before.iter())
        .map(|(frame_num, _)| NativeVulkanH264ReferenceListEntry::ShortTerm(*frame_num))
        .chain(long_term_entries.iter().copied())
        .collect::<Vec<_>>();
    if l0.len() > 1 && l1.len() > 1 && l0 == l1 {
        l1.swap(0, 1);
    }
    native_vulkan_h264_apply_ref_pic_list_modifications(
        &mut l0,
        &slice.ref_pic_list_modifications_l0,
        slice.frame_num,
        short_term_references,
        long_term_references,
        planned_output_slot,
        max_frame_num,
        "L0",
    )?;
    native_vulkan_h264_apply_ref_pic_list_modifications(
        &mut l1,
        &slice.ref_pic_list_modifications_l1,
        slice.frame_num,
        short_term_references,
        long_term_references,
        planned_output_slot,
        max_frame_num,
        "L1",
    )?;
    l0.truncate(l0_count);
    l1.truncate(l1_count);
    l0.extend(l1);
    let mut unique = Vec::with_capacity(l0.len());
    for entry in l0 {
        if !unique.contains(&entry) {
            unique.push(entry);
        }
    }
    Ok(unique)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_adaptive_marking_plan_for_slice(
    slice: &NativeVulkanH264AccessUnitSliceSnapshot,
    short_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    long_term_references: &BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    max_frame_num: u32,
) -> Result<NativeVulkanH264AdaptiveMarkingPlan, String> {
    let mut plan = NativeVulkanH264AdaptiveMarkingPlan::default();
    if !slice.adaptive_ref_pic_marking_mode_flag {
        if slice.idr && slice.long_term_reference_flag {
            plan.current_long_term_frame_idx = Some(0);
        }
        return Ok(plan);
    }

    let max_frame_num = max_frame_num.max(1);
    for operation in &slice.memory_management_control_operations {
        match operation.memory_management_control_operation {
            1 => {
                let frame_num = native_vulkan_h264_mmco_short_term_frame_num(
                    slice.frame_num,
                    operation.difference_of_pic_nums_minus1,
                    max_frame_num,
                    "MMCO 1",
                )?;
                if !short_term_references.contains_key(&frame_num) {
                    return Err(format!(
                        "H.264 MMCO 1 requested unavailable short-term frame_num {frame_num}"
                    ));
                }
                if !plan.drop_short_term_frame_nums.contains(&frame_num) {
                    plan.drop_short_term_frame_nums.push(frame_num);
                }
            }
            2 => {
                let long_term_pic_num = native_vulkan_h264_optional_u16(
                    operation.long_term_pic_num,
                    "long_term_pic_num",
                )?;
                if !long_term_references.contains_key(&long_term_pic_num) {
                    return Err(format!(
                        "H.264 MMCO 2 requested unavailable long-term pic num {long_term_pic_num}"
                    ));
                }
                if !plan
                    .drop_long_term_frame_indices
                    .contains(&long_term_pic_num)
                {
                    plan.drop_long_term_frame_indices.push(long_term_pic_num);
                }
            }
            3 => {
                let frame_num = native_vulkan_h264_mmco_short_term_frame_num(
                    slice.frame_num,
                    operation.difference_of_pic_nums_minus1,
                    max_frame_num,
                    "MMCO 3",
                )?;
                if !short_term_references.contains_key(&frame_num) {
                    return Err(format!(
                        "H.264 MMCO 3 requested unavailable short-term frame_num {frame_num}"
                    ));
                }
                let long_term_frame_idx = native_vulkan_h264_optional_u16(
                    operation.long_term_frame_idx,
                    "long_term_frame_idx",
                )?;
                plan.convert_short_term_to_long_term
                    .push((frame_num, long_term_frame_idx));
            }
            4 => {
                let max_plus1 = operation.max_long_term_frame_idx_plus1.ok_or_else(|| {
                    "H.264 MMCO 4 is missing max_long_term_frame_idx_plus1".to_owned()
                })?;
                if max_plus1 == 0 {
                    for long_term_frame_idx in long_term_references.keys().copied() {
                        if !plan
                            .drop_long_term_frame_indices
                            .contains(&long_term_frame_idx)
                        {
                            plan.drop_long_term_frame_indices.push(long_term_frame_idx);
                        }
                    }
                } else {
                    let max_idx = u16::try_from(max_plus1.saturating_sub(1)).map_err(|_| {
                        format!(
                            "H.264 MMCO 4 max_long_term_frame_idx_plus1 {max_plus1} exceeds supported u16 range"
                        )
                    })?;
                    for long_term_frame_idx in long_term_references.keys().copied() {
                        if long_term_frame_idx > max_idx
                            && !plan
                                .drop_long_term_frame_indices
                                .contains(&long_term_frame_idx)
                        {
                            plan.drop_long_term_frame_indices.push(long_term_frame_idx);
                        }
                    }
                }
            }
            5 => {
                for frame_num in short_term_references.keys().copied() {
                    if !plan.drop_short_term_frame_nums.contains(&frame_num) {
                        plan.drop_short_term_frame_nums.push(frame_num);
                    }
                }
                for long_term_frame_idx in long_term_references.keys().copied() {
                    if !plan
                        .drop_long_term_frame_indices
                        .contains(&long_term_frame_idx)
                    {
                        plan.drop_long_term_frame_indices.push(long_term_frame_idx);
                    }
                }
            }
            6 => {
                plan.current_long_term_frame_idx = Some(native_vulkan_h264_optional_u16(
                    operation.long_term_frame_idx,
                    "long_term_frame_idx",
                )?);
            }
            other => {
                return Err(format!(
                    "H.264 MMCO {other} is not supported by the first continuous direct gate"
                ));
            }
        }
    }

    Ok(plan)
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_mmco_short_term_frame_num(
    current_frame_num: u16,
    difference_of_pic_nums_minus1: Option<u32>,
    max_frame_num: u32,
    label: &'static str,
) -> Result<u16, String> {
    let difference = difference_of_pic_nums_minus1
        .ok_or_else(|| format!("H.264 {label} is missing difference_of_pic_nums_minus1"))?
        .saturating_add(1);
    let current = u32::from(current_frame_num);
    let pic_num = if current < difference {
        current
            .saturating_add(max_frame_num)
            .saturating_sub(difference)
    } else {
        current.saturating_sub(difference)
    };
    u16::try_from(pic_num)
        .map_err(|_| format!("H.264 {label} target frame_num {pic_num} exceeds u16 range"))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_optional_u16(value: Option<u32>, label: &'static str) -> Result<u16, String> {
    let value = value.ok_or_else(|| format!("H.264 value {label} is missing"))?;
    u16::try_from(value).map_err(|_| format!("H.264 {label} {value} exceeds supported u16 range"))
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanH264DecodeReferencePlanner {
    dpb_slots: u32,
    max_short_term_references: u32,
    max_frame_num: u32,
    gaps_in_frame_num_allowed: bool,
    previous_reference_frame_num: Option<u16>,
    short_term_references: BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    long_term_references: BTreeMap<u16, NativeVulkanH264DpbReferenceState>,
    slot_to_reference_key: Vec<Option<NativeVulkanH264DpbSlotKey>>,
    short_term_reference_order: Vec<u16>,
    next_output_slot: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanH264DecodeReferencePlanner {
    fn new(
        dpb_slots: u32,
        max_short_term_references: u32,
        max_frame_num: u32,
        gaps_in_frame_num_allowed: bool,
    ) -> Self {
        let dpb_slots = dpb_slots.max(1);
        Self {
            dpb_slots,
            max_short_term_references: max_short_term_references.max(1),
            max_frame_num: max_frame_num.max(1),
            gaps_in_frame_num_allowed,
            previous_reference_frame_num: None,
            short_term_references: BTreeMap::new(),
            long_term_references: BTreeMap::new(),
            slot_to_reference_key: vec![None; dpb_slots as usize],
            short_term_reference_order: Vec::new(),
            next_output_slot: 0,
        }
    }

    fn choose_output_slot(&mut self) -> u32 {
        for offset in 0..self.dpb_slots {
            let slot = (self.next_output_slot + offset) % self.dpb_slots;
            if self
                .slot_to_reference_key
                .get(slot as usize)
                .is_none_or(Option::is_none)
            {
                self.next_output_slot = (slot + 1) % self.dpb_slots;
                return slot;
            }
        }
        let slot = self.next_output_slot % self.dpb_slots;
        self.next_output_slot = (slot + 1) % self.dpb_slots;
        slot
    }

    fn infer_non_existing_short_term_references(
        &mut self,
        current_frame_num: u16,
    ) -> Result<NativeVulkanH264InferredNonExistingPlan, String> {
        let Some(previous_frame_num) = self.previous_reference_frame_num else {
            return Ok(NativeVulkanH264InferredNonExistingPlan::default());
        };
        let max_frame_num = self.max_frame_num.max(1);
        let current_frame_num_u32 = u32::from(current_frame_num);
        if current_frame_num_u32 >= max_frame_num {
            return Err(format!(
                "H.264 current frame_num {current_frame_num} is outside max_frame_num {max_frame_num}"
            ));
        }
        let previous_frame_num_u32 = u32::from(previous_frame_num) % max_frame_num;
        let mut frame_num = (previous_frame_num_u32 + 1) % max_frame_num;
        if frame_num == current_frame_num_u32 {
            return Ok(NativeVulkanH264InferredNonExistingPlan::default());
        }
        if !self.gaps_in_frame_num_allowed {
            return Err(format!(
                "H.264 frame_num gap from {previous_frame_num} to {current_frame_num} but SPS gaps_in_frame_num_value_allowed_flag is false"
            ));
        }

        let mut plan = NativeVulkanH264InferredNonExistingPlan::default();
        let mut guard = 0u32;
        while frame_num != current_frame_num_u32 && guard < max_frame_num {
            let inferred_frame_num = u16::try_from(frame_num).map_err(|_| {
                format!(
                    "H.264 inferred non-existing frame_num {frame_num} exceeds supported u16 range"
                )
            })?;
            plan.frame_nums.push(inferred_frame_num);
            let slot = self.choose_output_slot();
            self.clear_slot_for_inference(slot, &mut plan);
            let reference_state = NativeVulkanH264DpbReferenceState {
                source_access_unit_index: None,
                dpb_slot: slot,
                pic_order_cnt_val: i32::from(inferred_frame_num),
                frame_num: inferred_frame_num,
                non_existing: true,
            };
            self.short_term_references
                .insert(inferred_frame_num, reference_state);
            if let Some(slot_ref) = self.slot_to_reference_key.get_mut(slot as usize) {
                *slot_ref = Some(NativeVulkanH264DpbSlotKey::ShortTerm(inferred_frame_num));
            }
            self.short_term_reference_order
                .retain(|existing| *existing != inferred_frame_num);
            self.short_term_reference_order.push(inferred_frame_num);
            while self.short_term_reference_order.len() > self.max_short_term_references as usize {
                let old_frame_num = self.short_term_reference_order.remove(0);
                if let Some(old_slot) = self.remove_short_term_reference(old_frame_num) {
                    if !plan.dropped_short_term_frame_nums.contains(&old_frame_num) {
                        plan.dropped_short_term_frame_nums.push(old_frame_num);
                    }
                    if !plan.dropped_reference_slots.contains(&old_slot) {
                        plan.dropped_reference_slots.push(old_slot);
                    }
                }
            }
            frame_num = (frame_num + 1) % max_frame_num;
            guard = guard.saturating_add(1);
        }
        if frame_num != current_frame_num_u32 {
            return Err(format!(
                "H.264 frame_num gap inference from {previous_frame_num} to {current_frame_num} did not converge within max_frame_num {}",
                max_frame_num
            ));
        }
        plan.references = plan
            .frame_nums
            .iter()
            .filter_map(|frame_num| {
                self.short_term_references
                    .get(frame_num)
                    .and_then(|reference| {
                        reference.non_existing.then_some(
                            NativeVulkanH264InferredNonExistingReferenceSnapshot {
                                frame_num: reference.frame_num,
                                pic_order_cnt_val: reference.pic_order_cnt_val,
                                dpb_slot: reference.dpb_slot,
                            },
                        )
                    })
            })
            .collect();
        Ok(plan)
    }

    fn record_inference_dropped_key(
        &mut self,
        key: NativeVulkanH264DpbSlotKey,
        slot: u32,
        plan: &mut NativeVulkanH264InferredNonExistingPlan,
    ) {
        match key {
            NativeVulkanH264DpbSlotKey::ShortTerm(frame_num) => {
                self.short_term_reference_order
                    .retain(|existing| *existing != frame_num);
                self.short_term_references.remove(&frame_num);
                if !plan.dropped_short_term_frame_nums.contains(&frame_num) {
                    plan.dropped_short_term_frame_nums.push(frame_num);
                }
            }
            NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx) => {
                self.long_term_references.remove(&long_term_frame_idx);
                if !plan
                    .dropped_long_term_frame_indices
                    .contains(&long_term_frame_idx)
                {
                    plan.dropped_long_term_frame_indices
                        .push(long_term_frame_idx);
                }
            }
        }
        if !plan.dropped_reference_slots.contains(&slot) {
            plan.dropped_reference_slots.push(slot);
        }
    }

    fn clear_slot_for_inference(
        &mut self,
        slot: u32,
        plan: &mut NativeVulkanH264InferredNonExistingPlan,
    ) {
        let key = self
            .slot_to_reference_key
            .get(slot as usize)
            .copied()
            .flatten();
        if let Some(key) = key {
            self.record_inference_dropped_key(key, slot, plan);
        }
        if let Some(slot_ref) = self.slot_to_reference_key.get_mut(slot as usize) {
            *slot_ref = None;
        }
    }

    fn remove_short_term_reference(&mut self, frame_num: u16) -> Option<u32> {
        self.short_term_reference_order
            .retain(|existing| *existing != frame_num);
        let reference = self.short_term_references.remove(&frame_num)?;
        let slot = reference.dpb_slot;
        if self
            .slot_to_reference_key
            .get(slot as usize)
            .copied()
            .flatten()
            == Some(NativeVulkanH264DpbSlotKey::ShortTerm(frame_num))
            && let Some(slot_ref) = self.slot_to_reference_key.get_mut(slot as usize)
        {
            *slot_ref = None;
        }
        Some(slot)
    }

    fn remove_long_term_reference(&mut self, long_term_frame_idx: u16) -> Option<u32> {
        let reference = self.long_term_references.remove(&long_term_frame_idx)?;
        let slot = reference.dpb_slot;
        if self
            .slot_to_reference_key
            .get(slot as usize)
            .copied()
            .flatten()
            == Some(NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx))
            && let Some(slot_ref) = self.slot_to_reference_key.get_mut(slot as usize)
        {
            *slot_ref = None;
        }
        Some(slot)
    }

    fn clear_slot(&mut self, slot: u32) {
        let key = self
            .slot_to_reference_key
            .get(slot as usize)
            .copied()
            .flatten();
        match key {
            Some(NativeVulkanH264DpbSlotKey::ShortTerm(frame_num)) => {
                self.short_term_reference_order
                    .retain(|existing| *existing != frame_num);
                self.short_term_references.remove(&frame_num);
            }
            Some(NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx)) => {
                self.long_term_references.remove(&long_term_frame_idx);
            }
            None => {}
        }
        if let Some(slot_ref) = self.slot_to_reference_key.get_mut(slot as usize) {
            *slot_ref = None;
        }
    }

    fn convert_short_term_to_long_term(
        &mut self,
        frame_num: u16,
        long_term_frame_idx: u16,
    ) -> Option<(u32, Option<u32>)> {
        let replaced_slot = self.remove_long_term_reference(long_term_frame_idx);
        self.short_term_reference_order
            .retain(|existing| *existing != frame_num);
        let reference = self.short_term_references.remove(&frame_num)?;
        let slot = reference.dpb_slot;
        self.long_term_references
            .insert(long_term_frame_idx, reference);
        if let Some(slot_ref) = self.slot_to_reference_key.get_mut(slot as usize) {
            *slot_ref = Some(NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx));
        }
        Some((slot, replaced_slot))
    }

    fn plan_next(
        &mut self,
        access_unit: &NativeVulkanH264AccessUnitSnapshot,
    ) -> NativeVulkanH264DecodeReferencePlanEntrySnapshot {
        let first_slice = access_unit.first_slice.as_ref();
        let idr = first_slice.is_some_and(|slice| slice.idr);
        if idr {
            self.short_term_references.clear();
            self.long_term_references.clear();
            self.slot_to_reference_key.fill(None);
            self.short_term_reference_order.clear();
            self.next_output_slot = 0;
            self.previous_reference_frame_num = None;
        }

        let current_frame_num = first_slice.map(|slice| slice.frame_num);
        let current_pic_order_cnt_val = first_slice.map(|slice| slice.pic_order_cnt[0]);
        let current_long_term_frame_idx = first_slice
            .filter(|slice| slice.idr && slice.long_term_reference_flag)
            .map(|_| 0u16);

        let mut unsupported_reason = access_unit.first_slice_parse_error.clone();
        let requested_l0_reference_count = first_slice
            .and_then(|slice| {
                if slice.is_p || slice.is_b {
                    slice
                        .num_ref_idx_l0_active_minus1
                        .map(|value| value.saturating_add(1))
                } else {
                    Some(0)
                }
            })
            .unwrap_or(0);
        let requested_l1_reference_count = first_slice
            .and_then(|slice| {
                slice
                    .is_b
                    .then(|| slice.num_ref_idx_l1_active_minus1.map(|value| value + 1))
                    .flatten()
            })
            .unwrap_or(0);
        let mut requested_reference_count = if first_slice.is_some_and(|slice| slice.is_p) {
            requested_l0_reference_count
        } else {
            0
        };
        if unsupported_reason.is_none() {
            if let Some(slice) = first_slice {
                unsupported_reason = if slice.field_pic_flag {
                    Some("H.264 field pictures are not supported by the first continuous direct gate".to_owned())
                } else if !native_vulkan_h264_ref_pic_list_modifications_supported(slice) {
                    Some("H.264 unsupported reference list modification is not supported by the continuous direct gate".to_owned())
                } else if slice.is_p && requested_reference_count == 0 {
                    Some("H.264 P-slice requested zero active references".to_owned())
                } else if slice.is_b
                    && (requested_l0_reference_count == 0 || requested_l1_reference_count == 0)
                {
                    Some("H.264 B-slice requested zero active L0/L1 references".to_owned())
                } else if !slice.is_intra && !slice.is_p && !slice.is_b {
                    Some(format!(
                        "H.264 slice_type={} is not supported by the first continuous direct gate",
                        slice.slice_type
                    ))
                } else {
                    None
                };
            } else {
                unsupported_reason = Some(format!(
                    "H.264 AU {} has no parsed first slice",
                    access_unit.index
                ));
            }
        }

        let mut inferred_non_existing_plan = NativeVulkanH264InferredNonExistingPlan::default();
        if unsupported_reason.is_none()
            && let (Some(slice), Some(current_frame_num)) = (first_slice, current_frame_num)
            && !slice.idr
            && slice.is_reference
        {
            match self.infer_non_existing_short_term_references(current_frame_num) {
                Ok(plan) => inferred_non_existing_plan = plan,
                Err(err) => unsupported_reason = Some(err),
            }
        }

        let planned_output_slot = if current_frame_num.is_some() {
            self.choose_output_slot()
        } else {
            self.next_output_slot % self.dpb_slots
        };
        let evicted_key = self
            .slot_to_reference_key
            .get(planned_output_slot as usize)
            .copied()
            .flatten();
        let evicted_frame_num = match evicted_key {
            Some(NativeVulkanH264DpbSlotKey::ShortTerm(frame_num)) => Some(frame_num),
            _ => None,
        };
        let evicted_long_term_frame_idx = match evicted_key {
            Some(NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx)) => {
                Some(long_term_frame_idx)
            }
            _ => None,
        };

        let mut reference_entries = Vec::<NativeVulkanH264ReferenceListEntry>::new();
        if unsupported_reason.is_none()
            && let Some(slice) = first_slice
        {
            if slice.is_b {
                match native_vulkan_h264_b_reference_frame_nums_for_slice(
                    slice,
                    &self.short_term_references,
                    &self.long_term_references,
                    planned_output_slot,
                    self.max_frame_num,
                ) {
                    Ok(entries) => {
                        requested_reference_count = entries.len() as u32;
                        reference_entries = entries;
                    }
                    Err(err) => unsupported_reason = Some(err),
                }
            } else if requested_reference_count > 0 {
                match native_vulkan_h264_reference_frame_nums_for_slice(
                    slice,
                    &self.short_term_references,
                    &self.long_term_references,
                    planned_output_slot,
                    self.max_frame_num,
                ) {
                    Ok(entries) => reference_entries = entries,
                    Err(err) => unsupported_reason = Some(err),
                }
            }
        }
        if unsupported_reason.is_none()
            && requested_reference_count > self.max_short_term_references
        {
            unsupported_reason = Some(format!(
                "H.264 slice requests {requested_reference_count} active short-term references but stream/driver plan keeps {}",
                self.max_short_term_references
            ));
        }
        let mut adaptive_marking_plan = NativeVulkanH264AdaptiveMarkingPlan::default();
        if unsupported_reason.is_none()
            && let Some(slice) = first_slice
            && slice.is_reference
        {
            match native_vulkan_h264_adaptive_marking_plan_for_slice(
                slice,
                &self.short_term_references,
                &self.long_term_references,
                self.max_frame_num,
            ) {
                Ok(plan) => adaptive_marking_plan = plan,
                Err(err) => unsupported_reason = Some(err),
            }
        }

        let references = if unsupported_reason.is_none() && requested_reference_count > 0 {
            reference_entries
                .into_iter()
                .filter_map(|entry| {
                    let (used_for_long_term_reference, long_term_frame_idx, reference) = match entry
                    {
                        NativeVulkanH264ReferenceListEntry::ShortTerm(frame_num) => {
                            (false, None, self.short_term_references.get(&frame_num))
                        }
                        NativeVulkanH264ReferenceListEntry::LongTerm(long_term_frame_idx) => (
                            true,
                            Some(long_term_frame_idx),
                            self.long_term_references.get(&long_term_frame_idx),
                        ),
                    };
                    reference.and_then(|reference| {
                        (reference.dpb_slot != planned_output_slot).then(|| {
                            NativeVulkanH264DecodeReferenceSnapshot {
                                frame_num: reference.frame_num,
                                used_for_long_term_reference,
                                long_term_frame_idx,
                                non_existing: reference.non_existing,
                                pic_order_cnt_val: reference.pic_order_cnt_val,
                                available: true,
                                source_access_unit_index: reference.source_access_unit_index,
                                dpb_slot: Some(reference.dpb_slot),
                            }
                        })
                    })
                })
                .take(requested_reference_count as usize)
                .collect::<Vec<_>>()
        } else {
            Vec::new()
        };
        let available_reference_count = references
            .iter()
            .filter(|reference| reference.available)
            .count() as u32;
        let missing_reference_count =
            requested_reference_count.saturating_sub(available_reference_count);
        let ready_for_decode_submit = current_frame_num.is_some()
            && current_pic_order_cnt_val.is_some()
            && unsupported_reason.is_none()
            && missing_reference_count == 0;

        let current_reference_long_term_frame_idx = adaptive_marking_plan
            .current_long_term_frame_idx
            .or(current_long_term_frame_idx);
        let mut dropped_reference_frame_nums = Vec::<u16>::new();
        let mut dropped_long_term_frame_indices = Vec::<u16>::new();
        let mut long_term_reference_conversions =
            Vec::<NativeVulkanH264LongTermReferenceConversionSnapshot>::new();
        let mut dropped_reference_slots = Vec::<u32>::new();
        if ready_for_decode_submit {
            if let Some(evicted_key) = evicted_key {
                match evicted_key {
                    NativeVulkanH264DpbSlotKey::ShortTerm(frame_num) => {
                        self.remove_short_term_reference(frame_num);
                    }
                    NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx) => {
                        self.remove_long_term_reference(long_term_frame_idx);
                    }
                }
            }
            self.clear_slot(planned_output_slot);
            for frame_num in adaptive_marking_plan.drop_short_term_frame_nums {
                if let Some(slot) = self.remove_short_term_reference(frame_num) {
                    dropped_reference_frame_nums.push(frame_num);
                    dropped_reference_slots.push(slot);
                }
            }
            for long_term_frame_idx in adaptive_marking_plan.drop_long_term_frame_indices {
                if let Some(slot) = self.remove_long_term_reference(long_term_frame_idx) {
                    dropped_long_term_frame_indices.push(long_term_frame_idx);
                    dropped_reference_slots.push(slot);
                }
            }
            for (frame_num, long_term_frame_idx) in
                adaptive_marking_plan.convert_short_term_to_long_term
            {
                if let Some((slot, replaced_slot)) =
                    self.convert_short_term_to_long_term(frame_num, long_term_frame_idx)
                {
                    long_term_reference_conversions.push(
                        NativeVulkanH264LongTermReferenceConversionSnapshot {
                            frame_num,
                            long_term_frame_idx,
                            dpb_slot: slot,
                        },
                    );
                    if let Some(replaced_slot) = replaced_slot {
                        if !dropped_long_term_frame_indices.contains(&long_term_frame_idx) {
                            dropped_long_term_frame_indices.push(long_term_frame_idx);
                        }
                        if !dropped_reference_slots.contains(&replaced_slot) {
                            dropped_reference_slots.push(replaced_slot);
                        }
                    }
                }
            }
            if let (Some(slice), Some(current_frame_num), Some(current_pic_order_cnt_val)) =
                (first_slice, current_frame_num, current_pic_order_cnt_val)
                && slice.is_reference
            {
                let reference_state = NativeVulkanH264DpbReferenceState {
                    source_access_unit_index: Some(access_unit.index),
                    dpb_slot: planned_output_slot,
                    pic_order_cnt_val: current_pic_order_cnt_val,
                    frame_num: current_frame_num,
                    non_existing: false,
                };
                if let Some(long_term_frame_idx) = current_reference_long_term_frame_idx {
                    if let Some(replaced_slot) =
                        self.remove_long_term_reference(long_term_frame_idx)
                    {
                        if replaced_slot != planned_output_slot {
                            dropped_reference_slots.push(replaced_slot);
                        }
                        if !dropped_long_term_frame_indices.contains(&long_term_frame_idx) {
                            dropped_long_term_frame_indices.push(long_term_frame_idx);
                        }
                    }
                    self.long_term_references
                        .insert(long_term_frame_idx, reference_state);
                    if let Some(slot) = self
                        .slot_to_reference_key
                        .get_mut(planned_output_slot as usize)
                    {
                        *slot = Some(NativeVulkanH264DpbSlotKey::LongTerm(long_term_frame_idx));
                    }
                } else {
                    if let Some(slot) = self
                        .slot_to_reference_key
                        .get_mut(planned_output_slot as usize)
                    {
                        *slot = Some(NativeVulkanH264DpbSlotKey::ShortTerm(current_frame_num));
                    }
                    self.short_term_references
                        .insert(current_frame_num, reference_state);
                    self.short_term_reference_order
                        .retain(|frame_num| *frame_num != current_frame_num);
                    self.short_term_reference_order.push(current_frame_num);
                    while self.short_term_reference_order.len()
                        > self.max_short_term_references as usize
                    {
                        let old_frame_num = self.short_term_reference_order.remove(0);
                        if let Some(old_slot) = self.remove_short_term_reference(old_frame_num) {
                            dropped_reference_frame_nums.push(old_frame_num);
                            dropped_reference_slots.push(old_slot);
                        }
                    }
                }
                self.previous_reference_frame_num = Some(current_frame_num);
            }
        }

        NativeVulkanH264DecodeReferencePlanEntrySnapshot {
            access_unit_index: access_unit.index,
            pts_ms: access_unit.pts_ms,
            nal_type_label: first_slice.map(|slice| slice.nal_type_label),
            current_frame_num,
            current_pic_order_cnt_val,
            current_long_term_frame_idx: current_reference_long_term_frame_idx,
            planned_output_slot,
            setup_slot_index: first_slice
                .filter(|slice| slice.is_reference)
                .map(|_| planned_output_slot as i32),
            evicted_frame_num,
            evicted_long_term_frame_idx,
            dropped_reference_frame_nums,
            dropped_long_term_frame_indices,
            inferred_non_existing_frame_nums: inferred_non_existing_plan.frame_nums,
            inferred_non_existing_references: inferred_non_existing_plan.references,
            inferred_dropped_reference_frame_nums: inferred_non_existing_plan
                .dropped_short_term_frame_nums,
            inferred_dropped_long_term_frame_indices: inferred_non_existing_plan
                .dropped_long_term_frame_indices,
            inferred_dropped_reference_slots: inferred_non_existing_plan.dropped_reference_slots,
            long_term_reference_conversions,
            dropped_reference_slots,
            requested_reference_count,
            references,
            available_reference_count,
            missing_reference_count,
            unsupported_reason,
            ready_for_decode_submit,
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(dead_code)]
fn native_vulkan_h264_decode_reference_plan(
    access_units: &[NativeVulkanH264AccessUnitSnapshot],
    dpb_slots: u32,
    max_short_term_references: u32,
    max_frame_num: u32,
) -> Vec<NativeVulkanH264DecodeReferencePlanEntrySnapshot> {
    native_vulkan_h264_decode_reference_plan_with_gaps(
        access_units,
        dpb_slots,
        max_short_term_references,
        max_frame_num,
        true,
    )
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_decode_reference_plan_with_gaps(
    access_units: &[NativeVulkanH264AccessUnitSnapshot],
    dpb_slots: u32,
    max_short_term_references: u32,
    max_frame_num: u32,
    gaps_in_frame_num_allowed: bool,
) -> Vec<NativeVulkanH264DecodeReferencePlanEntrySnapshot> {
    let mut planner = NativeVulkanH264DecodeReferencePlanner::new(
        dpb_slots,
        max_short_term_references,
        max_frame_num,
        gaps_in_frame_num_allowed,
    );
    let mut plan = Vec::with_capacity(access_units.len());

    for access_unit in access_units {
        plan.push(planner.plan_next(access_unit));
    }

    plan
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_access_units_max_active_references(
    access_units: &[NativeVulkanH264AccessUnitSnapshot],
) -> u32 {
    access_units
        .iter()
        .filter_map(|access_unit| access_unit.first_slice.as_ref())
        .map(|slice| {
            let l0 = (slice.is_p || slice.is_b)
                .then(|| slice.num_ref_idx_l0_active_minus1.map(|value| value + 1))
                .flatten()
                .unwrap_or(0);
            let l1 = slice
                .is_b
                .then(|| slice.num_ref_idx_l1_active_minus1.map(|value| value + 1))
                .flatten()
                .unwrap_or(0);
            l0.saturating_add(l1)
        })
        .max()
        .unwrap_or(0)
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanH264StreamingBootstrap {
    stream_sps_dpb_slots: u32,
    stream_dpb_slots: u32,
    stream_max_active_reference_pictures: u32,
    max_frame_num: u32,
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_streaming_bootstrap_scan_limit(capacity: usize) -> usize {
    std::env::var("GILDER_VULKAN_STREAMING_BOOTSTRAP_SCAN_LIMIT")
        .ok()
        .and_then(|value| value.parse::<usize>().ok())
        .filter(|value| *value > 0)
        .unwrap_or_else(|| capacity.max(1).saturating_mul(128).max(4096))
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_align_streaming_bootstrap(
    queue: &mut NativeVulkanH264StreamingPacketQueue,
    parameter_sets: &NativeVulkanH264ParameterSetSnapshot,
) -> Result<NativeVulkanH264StreamingBootstrap, NativeVulkanError> {
    let scan_limit = native_vulkan_streaming_bootstrap_scan_limit(queue.capacity);
    let mut skipped_access_unit_indices = Vec::<u32>::new();
    loop {
        let bootstrap_access_units = queue.bootstrap_access_units();
        if bootstrap_access_units.is_empty() {
            return Err(NativeVulkanError::Video(format!(
                "H.264 streaming bootstrap could not find a decodable AU window after skipping {} leading AU(s)",
                skipped_access_unit_indices.len()
            )));
        }
        let stream_sps_dpb_slots = native_vulkan_h264_sps_dpb_slot_count(&parameter_sets.sps);
        let max_frame_num = native_vulkan_h264_sps_max_frame_num(&parameter_sets.sps);
        let stream_max_active_reference_pictures = parameter_sets
            .sps
            .max_num_ref_frames
            .max(native_vulkan_h264_access_units_max_active_references(
                &bootstrap_access_units,
            ))
            .max(1);
        let (stream_dpb_slots, bootstrap_plan) =
            native_vulkan_h264_min_decodable_dpb_plan_with_gaps(
                &bootstrap_access_units,
                stream_sps_dpb_slots,
                stream_max_active_reference_pictures,
                max_frame_num,
                parameter_sets.sps.gaps_in_frame_num_value_allowed_flag,
            );
        let Some(first_unready_offset) = bootstrap_plan
            .iter()
            .position(|entry| !entry.ready_for_decode_submit)
        else {
            queue.set_loop_skip_access_units(queue.bootstrap_discarded_access_units.min(u32::MAX));
            return Ok(NativeVulkanH264StreamingBootstrap {
                stream_sps_dpb_slots,
                stream_dpb_slots,
                stream_max_active_reference_pictures,
                max_frame_num,
            });
        };
        let first_unready = &bootstrap_plan[first_unready_offset];
        let random_access_offset = bootstrap_access_units.iter().position(|access_unit| {
            access_unit
                .first_slice
                .as_ref()
                .is_some_and(|slice| slice.idr)
        });
        let discard_count = random_access_offset
            .filter(|offset| *offset > 0)
            .unwrap_or(usize::from(first_unready_offset == 0));
        if discard_count == 0 {
            return Err(NativeVulkanError::Video(format!(
                "H.264 streaming bootstrap AU {} is not decodable with optimized DPB slot count {stream_dpb_slots} after skipping {} leading AU(s): {}",
                first_unready.access_unit_index,
                queue.bootstrap_discarded_access_units,
                first_unready
                    .unsupported_reason
                    .as_deref()
                    .unwrap_or("missing references")
            )));
        }
        if usize::try_from(queue.bootstrap_discarded_access_units)
            .unwrap_or(usize::MAX)
            .saturating_add(discard_count)
            > scan_limit
        {
            return Err(NativeVulkanError::Video(format!(
                "H.264 streaming bootstrap exceeded scan limit {scan_limit} while looking for a decodable AU window; last leading AU {} was not decodable: {}",
                first_unready.access_unit_index,
                first_unready
                    .unsupported_reason
                    .as_deref()
                    .unwrap_or("missing references")
            )));
        }
        for _ in 0..discard_count {
            let Some(dropped) = queue.discard_front_for_bootstrap()? else {
                return Err(NativeVulkanError::Video(format!(
                    "H.264 streaming bootstrap reached EOS after skipping {} leading AU(s) without finding a decodable window",
                    queue.bootstrap_discarded_access_units
                )));
            };
            skipped_access_unit_indices.push(dropped.snapshot.index);
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
#[allow(dead_code)]
fn native_vulkan_h264_min_decodable_dpb_plan(
    access_units: &[NativeVulkanH264AccessUnitSnapshot],
    max_dpb_slots: u32,
    max_short_term_references: u32,
    max_frame_num: u32,
) -> (u32, Vec<NativeVulkanH264DecodeReferencePlanEntrySnapshot>) {
    native_vulkan_h264_min_decodable_dpb_plan_with_gaps(
        access_units,
        max_dpb_slots,
        max_short_term_references,
        max_frame_num,
        true,
    )
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h264_min_decodable_dpb_plan_with_gaps(
    access_units: &[NativeVulkanH264AccessUnitSnapshot],
    max_dpb_slots: u32,
    max_short_term_references: u32,
    max_frame_num: u32,
    gaps_in_frame_num_allowed: bool,
) -> (u32, Vec<NativeVulkanH264DecodeReferencePlanEntrySnapshot>) {
    let max_dpb_slots = max_dpb_slots.max(1);
    let mut last_plan = Vec::new();
    for dpb_slots in 1..=max_dpb_slots {
        let plan = native_vulkan_h264_decode_reference_plan_with_gaps(
            access_units,
            dpb_slots,
            max_short_term_references,
            max_frame_num,
            gaps_in_frame_num_allowed,
        );
        if plan.iter().all(|entry| entry.ready_for_decode_submit) {
            return (dpb_slots, plan);
        }
        last_plan = plan;
    }
    (max_dpb_slots, last_plan)
}

#[cfg(feature = "native-vulkan-gst-video")]
struct NativeVulkanH265DecodeReferencePlanner {
    dpb_slots: u32,
    max_pic_order_cnt_lsb: u32,
    poc_to_decoded_slot: BTreeMap<i32, (u32, u32)>,
    slot_to_poc: Vec<Option<i32>>,
    next_output_slot: u32,
    prev_poc_lsb: Option<i32>,
    prev_poc_msb: i32,
}

#[cfg(feature = "native-vulkan-gst-video")]
impl NativeVulkanH265DecodeReferencePlanner {
    fn new(dpb_slots: u32, max_pic_order_cnt_lsb: u32) -> Self {
        let dpb_slots = dpb_slots.max(1);
        Self {
            dpb_slots,
            max_pic_order_cnt_lsb: max_pic_order_cnt_lsb.max(1),
            poc_to_decoded_slot: BTreeMap::new(),
            slot_to_poc: vec![None; dpb_slots as usize],
            next_output_slot: 0,
            prev_poc_lsb: None,
            prev_poc_msb: 0,
        }
    }

    fn reset_for_idr(&mut self) {
        self.poc_to_decoded_slot.clear();
        self.slot_to_poc.fill(None);
        self.next_output_slot = 0;
        self.prev_poc_lsb = Some(0);
        self.prev_poc_msb = 0;
    }

    fn derive_current_poc(
        &mut self,
        slice: &NativeVulkanH265AccessUnitSliceSnapshot,
    ) -> Option<i32> {
        if slice.idr {
            self.prev_poc_lsb = Some(0);
            self.prev_poc_msb = 0;
            return Some(0);
        }
        let poc_lsb = slice.pic_order_cnt_lsb? as i32;
        let max_lsb = i32::try_from(self.max_pic_order_cnt_lsb).unwrap_or(i32::MAX);
        let prev_lsb = self.prev_poc_lsb.unwrap_or(0);
        let prev_msb = self.prev_poc_msb;
        let half_max_lsb = max_lsb / 2;
        let poc_msb = if poc_lsb < prev_lsb && prev_lsb.saturating_sub(poc_lsb) >= half_max_lsb {
            prev_msb.saturating_add(max_lsb)
        } else if poc_lsb > prev_lsb && poc_lsb.saturating_sub(prev_lsb) > half_max_lsb {
            prev_msb.saturating_sub(max_lsb)
        } else {
            prev_msb
        };
        self.prev_poc_lsb = Some(poc_lsb);
        self.prev_poc_msb = poc_msb;
        Some(poc_msb.saturating_add(poc_lsb))
    }

    fn plan_next(
        &mut self,
        access_unit: &NativeVulkanH265AccessUnitSnapshot,
    ) -> NativeVulkanH265DecodeReferencePlanEntrySnapshot {
        let first_slice = access_unit.first_slice.as_ref();
        let idr = first_slice.is_some_and(|slice| slice.idr);
        if idr {
            self.reset_for_idr();
        }
        let current_poc = first_slice.and_then(|slice| self.derive_current_poc(slice));
        let planned_output_slot = self.next_output_slot % self.dpb_slots;
        if current_poc.is_some() {
            self.next_output_slot = self.next_output_slot.saturating_add(1);
        }
        let evicted_poc = self
            .slot_to_poc
            .get(planned_output_slot as usize)
            .copied()
            .flatten();
        let reference_delta_pocs = first_slice
            .and_then(|slice| slice.short_term_ref_pic_set.as_ref())
            .map(|rps| {
                rps.used_negative_delta_pocs
                    .iter()
                    .chain(rps.used_positive_delta_pocs.iter())
                    .copied()
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let references = current_poc
            .map(|current_poc| {
                reference_delta_pocs
                    .iter()
                    .copied()
                    .map(|delta_poc| {
                        let poc = current_poc.saturating_add(delta_poc);
                        let source = self.poc_to_decoded_slot.get(&poc).copied();
                        let available = source.is_some_and(|(_, slot)| slot != planned_output_slot);
                        NativeVulkanH265DecodeReferenceSnapshot {
                            delta_poc,
                            poc,
                            available,
                            source_access_unit_index: source.map(|(index, _)| index),
                            dpb_slot: source.map(|(_, slot)| slot),
                        }
                    })
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let missing_reference_pocs = references
            .iter()
            .filter(|reference| !reference.available)
            .map(|reference| reference.poc)
            .collect::<Vec<_>>();
        let available_reference_count = references
            .iter()
            .filter(|reference| reference.available)
            .count() as u32;
        let missing_reference_count = missing_reference_pocs.len() as u32;
        let ready_for_decode_submit = current_poc.is_some()
            && access_unit.first_slice_parse_error.is_none()
            && missing_reference_count == 0;

        if ready_for_decode_submit && let Some(current_poc) = current_poc {
            if let Some(evicted_poc) = evicted_poc {
                self.poc_to_decoded_slot.remove(&evicted_poc);
            }
            if let Some(slot) = self.slot_to_poc.get_mut(planned_output_slot as usize) {
                *slot = Some(current_poc);
            }
            self.poc_to_decoded_slot
                .insert(current_poc, (access_unit.index, planned_output_slot));
        }

        NativeVulkanH265DecodeReferencePlanEntrySnapshot {
            access_unit_index: access_unit.index,
            pts_ms: access_unit.pts_ms,
            nal_type_label: first_slice.map(|slice| slice.nal_type_label),
            current_poc,
            planned_output_slot,
            setup_slot_index: current_poc.map(|_| planned_output_slot as i32),
            evicted_poc,
            references,
            available_reference_count,
            missing_reference_count,
            missing_reference_pocs,
            ready_for_decode_submit,
        }
    }
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_decode_reference_plan(
    access_units: &[NativeVulkanH265AccessUnitSnapshot],
    dpb_slots: u32,
    max_pic_order_cnt_lsb: u32,
) -> Vec<NativeVulkanH265DecodeReferencePlanEntrySnapshot> {
    let mut planner = NativeVulkanH265DecodeReferencePlanner::new(dpb_slots, max_pic_order_cnt_lsb);
    let mut plan = Vec::with_capacity(access_units.len());

    for access_unit in access_units {
        plan.push(planner.plan_next(access_unit));
    }

    plan
}

#[cfg(feature = "native-vulkan-gst-video")]
fn native_vulkan_h265_min_decodable_dpb_plan(
    access_units: &[NativeVulkanH265AccessUnitSnapshot],
    max_dpb_slots: u32,
    max_pic_order_cnt_lsb: u32,
) -> (u32, Vec<NativeVulkanH265DecodeReferencePlanEntrySnapshot>) {
    let max_dpb_slots = max_dpb_slots.max(1);
    let mut last_plan = Vec::new();
    for dpb_slots in 1..=max_dpb_slots {
        let plan = native_vulkan_h265_decode_reference_plan(
            access_units,
            dpb_slots,
            max_pic_order_cnt_lsb,
        );
        if plan.iter().all(|entry| entry.ready_for_decode_submit) {
            return (dpb_slots, plan);
        }
        last_plan = plan;
    }
    (max_dpb_slots, last_plan)
}

